# ── Compatibilidade @st.fragment (Streamlit >= 1.37) ──────────────────────
def _fragment(func=None, *, run_every=None):
    """Decorator que usa st.fragment se disponível, senão é no-op."""
    def _decorator(f):
        try:
            import streamlit as _st
            if hasattr(_st, "fragment"):
                kwargs = {"run_every": run_every} if run_every else {}
                return _st.fragment(f, **kwargs)
        except Exception:
            pass
        return f
    return _decorator(func) if func is not None else _decorator

# ═══════════════════════════════════════════════════════════════════
#  AUTO-SYNC Gestão de Frotas — Sincronização automática de hora em hora
#  Roda em background threads (daemon) — uma thread por cliente.
#  Persiste entre reruns do Streamlit enquanto o servidor estiver ativo.
# ═══════════════════════════════════════════════════════════════════
import threading as _threading

_AUTO_SYNC_INTERVAL = 3600  # segundos entre cada ciclo (1 hora)

# @st.cache_resource garante que os dicts sobrevivem a reruns do Streamlit.
# Sem isso, _AUTO_SYNC_THREADS = {} no módulo é re-executado a cada rerun,
# destruindo referências de threads ativas.
@st.cache_resource
def _get_auto_sync_state():
    """Retorna dicts de estado do auto-sync — criados UMA vez por processo."""
    return {
        "threads":     {},        # cnpj_frota → threading.Thread
        "status":      {},        # cnpj_frota → dict de status
        "lock":        _threading.Lock(),
        "initialized": False,
    }

_AUTO_SYNC_STATE       = _get_auto_sync_state()
_AUTO_SYNC_THREADS     = _AUTO_SYNC_STATE["threads"]
_AUTO_SYNC_STATUS      = _AUTO_SYNC_STATE["status"]
_AUTO_SYNC_LOCK        = _AUTO_SYNC_STATE["lock"]
_AUTO_SYNC_INITIALIZED = False   # flag local; _STATE persiste


def _auto_sync_create_db():
    """Cria cliente Supabase sem st.session_state (thread-safe)."""
    try:
        from supabase import create_client as _cc
        # 1) Variáveis de ambiente
        _url = os.environ.get("SUPABASE_URL", "")
        _key = os.environ.get("SUPABASE_KEY", "")
        # 2) Arquivo secrets.toml do Streamlit (local)
        if not (_url and _key):
            for _sp in [
                os.path.join(_DIR, ".streamlit", "secrets.toml"),
                os.path.expanduser("~/.streamlit/secrets.toml"),
            ]:
                if os.path.exists(_sp):
                    try:
                        import tomllib as _tl
                    except ImportError:
                        try:
                            import tomli as _tl
                        except ImportError:
                            _tl = None
                    if _tl:
                        with open(_sp, "rb") as _f:
                            _sec = _tl.load(_f)
                        _url = _sec.get("supabase", {}).get("url", "")
                        _key = _sec.get("supabase", {}).get("key", "")
                        if _url and _key:
                            break
        if _url and _key:
            return _cc(_url, _key)
    except Exception:
        pass
    return None


def _auto_sync_worker(cnpj_frota: str, token_inicial: str):
    """
    Worker de sincronização automática.
    Executa a cada _AUTO_SYNC_INTERVAL segundos em background.
    Busca registros das últimas 3 horas (+ 1h de overlap para segurança).
    """
    import datetime as _dt
    import time as _tm
    import re as _re_th

    _retry_delay = 60  # espera 1 min após falha antes de tentar de novo
    while True:
        try:
            _db_th = _auto_sync_create_db()
            if not _db_th:
                _AUTO_SYNC_STATUS[cnpj_frota] = {
                    "status": "erro",
                    "msg": "Supabase indisponível — verifique secrets/env vars.",
                    "last_attempt": _dt.datetime.now(tz=_dt.timezone(_dt.timedelta(hours=-3))).isoformat(),
                }
                _tm.sleep(300)   # retry em 5 min se sem DB
                continue

            # ── Descobre o token mais recente e último sync ───────────
            _cur_token = token_inicial
            try:
                _r = (_db_th.table("profrotas_api_keys")
                      .select("token,ultimo_sync")
                      .eq("cnpj_frota", cnpj_frota)
                      .execute())
                _row = (_r.data or [{}])[0] if _r.data else {}
                _cur_token = _row.get("token") or token_inicial
                _last_sync = _row.get("ultimo_sync")
            except Exception:
                _last_sync = None

            # ── Calcula data_inicio: re-busca overlap de 2h ───────────
            if _last_sync:
                try:
                    _ts = _dt.datetime.fromisoformat(_last_sync.replace("Z", "+00:00"))
                    _ts_naive = _ts.replace(tzinfo=None)
                    _data_inicio = (
                        _ts_naive - _dt.timedelta(hours=2)
                    ).strftime("%Y-%m-%dT%H:%M:%SZ")
                except Exception:
                    _data_inicio = (
                        _dt.datetime.utcnow() - _dt.timedelta(hours=4)
                    ).strftime("%Y-%m-%dT%H:%M:%SZ")
            else:
                # Primeiro sync automático: pega as últimas 4 horas
                _data_inicio = (
                    _dt.datetime.utcnow() - _dt.timedelta(hours=4)
                ).strftime("%Y-%m-%dT%H:%M:%SZ")

            _inicio_ts = _dt.datetime.utcnow()
            _AUTO_SYNC_STATUS[cnpj_frota] = {
                "status":  "syncing",
                "started": _inicio_ts.isoformat(),
                "msg":     "Sincronizando...",
            }

            # ── Executa sync (usa _db_override para evitar session_state) ──
            _pags, _salvos, _novo_tok, _erro, _total = _profrotas_sync(
                cnpj_frota, _cur_token, _data_inicio,
                _db_override=_db_th,
            )

            # Atualiza token se renovado
            if _novo_tok:
                token_inicial = _novo_tok

            _fim_ts = _dt.datetime.utcnow()
            _duracao = int((_fim_ts - _inicio_ts).total_seconds())
            _next_ts = _fim_ts + _dt.timedelta(seconds=_AUTO_SYNC_INTERVAL)

            _AUTO_SYNC_STATUS[cnpj_frota] = {
                "status":       "ok" if not _erro else "erro_parcial",
                "last_sync":    _fim_ts.isoformat(),
                "next_sync":    _next_ts.isoformat(),
                "records_last": _salvos,
                "total_api":    _total,
                "paginas":      _pags,
                "erro":         _erro or "",
                "duracao_s":    _duracao,
            }

        except Exception as _ex:
            _AUTO_SYNC_STATUS[cnpj_frota] = {
                "status":       "erro",
                "msg":          str(_ex)[:300],
                "last_attempt": _dt.datetime.now(tz=_dt.timezone(_dt.timedelta(hours=-3))).isoformat(),
            }

        _tm.sleep(_AUTO_SYNC_INTERVAL)


def _auto_sync_ensure_running(cnpj_frota: str, token: str) -> bool:
    """Inicia ou verifica thread de sync automático para um cliente.
    Retorna True se a thread foi iniciada agora, False se já estava rodando."""
    with _AUTO_SYNC_LOCK:
        _t = _AUTO_SYNC_THREADS.get(cnpj_frota)
        if _t and _t.is_alive():
            return False
        _t = _threading.Thread(
            target=_auto_sync_worker,
            args=(cnpj_frota, token),
            daemon=True,
            name=f"auto_sync_{cnpj_frota}",
        )
        _AUTO_SYNC_THREADS[cnpj_frota] = _t
        _t.start()
        _AUTO_SYNC_STATUS[cnpj_frota] = {
            "status":    "iniciado",
            "msg":       "Thread iniciada — primeiro sync em andamento.",
            "started":   __import__("datetime").datetime.utcnow().isoformat(),
            "next_sync": (
                __import__("datetime").datetime.utcnow() +
                __import__("datetime").timedelta(seconds=_AUTO_SYNC_INTERVAL)
            ).isoformat(),
        }
        return True


def _auto_sync_ensure_all():
    """
    Inicia ou re-verifica threads para todas as chaves Gestão de Frotas ativas.
    _auto_sync_ensure_running() é idempotente — não recria threads vivas.
    """
    try:
        _chaves = _profrotas_listar_chaves()
        for _c in _chaves:
            if _c.get("ativo") and _c.get("token") and _c.get("cnpj_frota"):
                _auto_sync_ensure_running(_c["cnpj_frota"], _c["token"])
    except Exception as _e_as:
        _AUTO_SYNC_STATUS["_startup_error"] = {
            "status": "erro", "msg": str(_e_as)[:200],
        }


@st.cache_resource
def _auto_sync_watchdog_state():
    """Estado global do watchdog — persiste entre reruns no mesmo processo."""
    import time as _t
    return {"last_check": 0.0}


def _auto_sync_heartbeat():
    """
    Chamada em todo rerun. Garante threads vivas sem hammering do banco:
    - executa _auto_sync_ensure_all() no máximo 1x por minuto
    - detecta e reinicia threads mortas imediatamente após redeploy/restart
    """
    import time as _t
    _wd = _auto_sync_watchdog_state()
    if _t.time() - _wd["last_check"] > 60:
        _wd["last_check"] = _t.time()
        _auto_sync_ensure_all()


# ═══════════════════════════════════════════════════════════════════
#  FORMATAÇÃO NUMÉRICA — Padrão Brasileiro (pt-BR)
#  Separador decimal: vírgula  |  Separador de milhar: ponto
#  Exemplos:  1234.56 → "1.234,56"  |  1234 → "1.234"
# ═══════════════════════════════════════════════════════════════════

def _br_num(v, d: int = 2) -> str:
    """Número decimal no padrão BR: 1.234,56 (sem prefixo de moeda)."""
    try:
        return f"{float(v):,.{d}f}".replace(",", "X").replace(".", ",").replace("X", ".")
    except (TypeError, ValueError):
        return "—"


def _br_moeda(v, d: int = 2) -> str:
    """Valor monetário no padrão BR: R$ 1.234,56."""
    try:
        return "R$ " + f"{float(v):,.{d}f}".replace(",", "X").replace(".", ",").replace("X", ".")
    except (TypeError, ValueError):
        return "R$ —"


def _br_int(v) -> str:
    """Inteiro com separador de milhar BR: 1.234."""
    try:
        return f"{int(round(float(v))):,}".replace(",", ".")
    except (TypeError, ValueError):
        return "—"

# ═══════════════════════════════════════════════════════════════════
#  SUPABASE — Banco de Dados para Persistência
# ═══════════════════════════════════════════════════════════════════

def _db_client():
    """Retorna o cliente Supabase. Cria uma vez por sessão via session_state.
    Suporta Railway (env vars) e Streamlit Cloud (secrets.toml) automaticamente.
    """
    if "_supabase_client" not in st.session_state:
        _url, _key = "", ""
        # 1. Env vars — Railway, Render, qualquer PaaS
        _url = os.environ.get("SUPABASE_URL", "")
        _key = os.environ.get("SUPABASE_KEY", "")
        # 2. st.secrets — Streamlit Cloud / local secrets.toml (pode lançar exceção)
        if not (_url and _key):
            try:
                _url = st.secrets.get("supabase", {}).get("url", "") or _url
                _key = st.secrets.get("supabase", {}).get("key", "") or _key
            except Exception:
                pass
        # 3. Criar cliente
        try:
            from supabase import create_client
            if _url and _key:
                st.session_state["_supabase_client"] = create_client(_url, _key)
            else:
                st.session_state["_supabase_client"] = None
        except Exception:
            st.session_state["_supabase_client"] = None
    return st.session_state["_supabase_client"]





def _db_criar_empresa_e_vincular(nome_empresa: str, cnpj_empresa: str,
                                   email_usuario: str, nome_usuario: str) -> dict | None:
    """
    Auto-cadastro: cria a empresa e vincula o usuário como 'gestor' (role principal),
    tudo em uma operação. Usado no onboarding de novos usuários sem empresa.
    Garante unicidade: não cria empresa duplicada por CNPJ ou por email já vinculado.
    """
    db = _db_client()
    if not db:
        return None
    try:
        import re as _re_emp
        _cnpj_norm = _re_emp.sub(r"[\s.\-/]", "", cnpj_empresa.strip()).upper() or None

        # 1. Verifica se o usuário já tem empresa vinculada
        _vinc_exist = db.table("usuarios_empresas").select("empresa_id, empresas(id,nome,cnpj,plano,status)").eq("user_email", email_usuario.lower()).eq("ativo", True).execute()
        if _vinc_exist.data:
            _emp_exist = (_vinc_exist.data[0].get("empresas") or {})
            if _emp_exist.get("id"):
                return _emp_exist  # já tem empresa — retorna sem criar

        # 2. Verifica se já existe empresa com mesmo CNPJ
        _empresa = None
        if _cnpj_norm:
            _cnpj_check = db.table("empresas").select("*").eq("cnpj", _cnpj_norm).execute()
            if not _cnpj_check.data:
                # Tenta também com formatação original
                _cnpj_check2 = db.table("empresas").select("*").eq("cnpj", cnpj_empresa.strip()).execute()
                if _cnpj_check2.data:
                    _empresa = _cnpj_check2.data[0]
            else:
                _empresa = _cnpj_check.data[0]

        # 3. Cria empresa apenas se não existe
        if not _empresa:
            _emp_res = db.table("empresas").insert({
                "nome":   nome_empresa.strip(),
                "cnpj":   _cnpj_norm or cnpj_empresa.strip() or None,
                "ativo":  True,
                "plano":  "gratuito",
                "status": "ativo",
            }).execute()
            if not _emp_res.data:
                return None
            _empresa = _emp_res.data[0]

        db.table("usuarios_empresas").insert({
            "user_email": email_usuario.lower(),
            "empresa_id": _empresa["id"],
            "role":       "gestor",
            "ativo":      True,
        }).execute()

        # Atualiza/cria também em usuarios_app para manter perfil consistente
        db.table("usuarios_app").upsert({
            "email":          email_usuario.lower(),
            "nome":           nome_usuario,
            "perfil":         "gestor_frota",
            "cnpj_vinculado": cnpj_empresa.strip() or None,
            "empresa_nome":   nome_empresa.strip(),
            "ativo":          True,
            "criado_em":      __import__("datetime").datetime.now(__import__("datetime").timezone.utc).isoformat(),
            "origem":         "auto_onboarding",
        }, on_conflict="email").execute()

        return _empresa
    except Exception as _e_auto:
        st.session_state["_erro_auto_cadastro"] = str(_e_auto)
        return None

def _solic_registrar(email: str, nome: str = "") -> None:
    """Registra uma solicitação de acesso pendente (idempotente por email)."""
    try:
        _db = _db_client()
        if not _db:
            return
        _existe = (_db.table("solicitacoes_acesso")
                   .select("id").eq("email", email.lower())
                   .eq("status", "pendente").limit(1).execute().data)
        if _existe:
            return
        _db.table("solicitacoes_acesso").insert({
            "email": email.lower(),
            "nome":  nome or "",
            "status": "pendente",
        }).execute()
    except Exception:
        pass


@st.cache_data(show_spinner=False, ttl=30)
def _solic_listar_pendentes() -> list:
    """Lista solicitações de acesso pendentes."""
    try:
        _db = _db_client()
        if not _db:
            return []
        return (_db.table("solicitacoes_acesso")
                .select("*").eq("status", "pendente")
                .order("criado_em", desc=True).execute().data or [])
    except Exception:
        return []


def _solic_resolver(solic_id: str, resolvido_por: str) -> bool:
    """Marca uma solicitação como resolvida."""
    try:
        import datetime as _dt_solic
        _db = _db_client()
        _db.table("solicitacoes_acesso").update({
            "status": "resolvido",
            "resolvido_em": _dt_solic.datetime.now(_dt_solic.timezone.utc).isoformat(),
            "resolvido_por": resolvido_por,
        }).eq("id", solic_id).execute()
        _solic_listar_pendentes.clear()
        return True
    except Exception as _e_solic:
        st.session_state["_erro_solic_resolver"] = str(_e_solic)
        return False

