def _profrotas_para_df_analise(cnpj_frota: str | None = None,
                                dias: int = 180) -> "pd.DataFrame":
    """Converte dados do Gestão de Frotas (profrotas_abastecimentos) para o
    formato normalizado usado pela Análise de Cliente e Relatórios.

    Colunas de saída: _placa, _data, _hora, _produto, _litros, _preco_litro,
    _valor_total, _motorista, _cnpj_posto, _nome_posto, _cidade_posto, _uf_posto,
    _hod_atual, _cnpj_frota, _fonte
    """
    _df_raw = _profrotas_carregar_abast(cnpj_frota, dias)
    if _df_raw.empty:
        return pd.DataFrame()

    import numpy as _np2

    def _safe_f(v):
        try:
            f = float(v)
            return None if (_np2.isnan(f) or _np2.isinf(f)) else f
        except Exception:
            return None

    rows = []
    for _, r in _df_raw.iterrows():
        _dt = pd.to_datetime(r.get("data_abastecimento"), errors="coerce")
        rows.append({
            "_id_transacao":  r.get("identificador"),
            "_data":          _dt.date() if _dt is not pd.NaT else None,
            "_hora":          _dt.strftime("%H:%M") if _dt is not pd.NaT else "",
            "_cnpj_frota":    re.sub(r"\D","",str(r.get("cnpj_frota","") or "")).zfill(14),
            "_razao_frota":   str(r.get("frota_razao_social", "") or ""),
            "_placa":         str(r.get("veiculo_placa", "") or "").upper().strip(),
            "_tipo_veiculo":  "",
            "_motorista":     str(r.get("motorista_nome", "") or ""),
            "_produto":       str(r.get("item_nome", "") or ""),
            "_litros":        _safe_f(r.get("item_quantidade")),
            "_preco_litro":   _safe_f(r.get("item_valor_unitario")),
            "_valor_comb":    _safe_f(r.get("item_valor_total")),
            "_valor_total":   _safe_f(r.get("item_valor_total")),
            "_hod_atual":     _safe_f(r.get("hodometro")),
            "_hod_anterior":  None,
            "_km_perc":       None,
            "_media_km_l":    None,
            "_cnpj_posto":    re.sub(r"\D","",str(r.get("pv_cnpj","") or "")).zfill(14),
            "_nome_posto":    str(r.get("pv_razao_social", "") or ""),
            "_cidade_posto":  str(r.get("pv_municipio", "") or ""),
            "_uf_posto":      str(r.get("pv_uf", "") or ""),
            "_lat_posto":     _safe_f(r.get("pv_latitude")),
            "_lon_posto":     _safe_f(r.get("pv_longitude")),
            "_status":        str(r.get("status_autorizacao", "") or ""),
            "_centro_custo":  "",
            "_nome_arquivo":  "Gestão de Frotas API",
            "_fonte":         "gestaoFrotas",
        })

    df = pd.DataFrame(rows)

    # Calcular km_percorrido e media_km_l por placa (ordenado por data+hodômetro)
    if not df.empty and "_hod_atual" in df.columns:
        df = df.sort_values(["_placa", "_data", "_hod_atual"], na_position="last")
        df["_hod_anterior"] = df.groupby("_placa")["_hod_atual"].shift(1)
        df["_km_perc"] = (df["_hod_atual"] - df["_hod_anterior"]).clip(lower=0)
        mask = (df["_km_perc"] > 0) & (df["_litros"] > 0)
        df.loc[mask, "_media_km_l"] = (df.loc[mask, "_km_perc"] / df.loc[mask, "_litros"]).round(2)
        df = df.sort_values(["_data", "_placa"], ascending=[False, True])

    return df



# ═══════════════════════════════════════════════════════════════════
#  PROFROTAS API — Integração de Abastecimentos
# ═══════════════════════════════════════════════════════════════════

_PROFROTAS_API = "https://api-portal.profrotas.com.br/api"
_PROFROTAS_PESQ = f"{_PROFROTAS_API}/frotista/abastecimento/pesquisa"
_PROFROTAS_PAGE_SIZE = 100   # registros por página


def _profrotas_request(token: str, payload: dict,
                        _retry: int = 3) -> tuple[dict | None, str | None]:
    """POST autenticado na API Gestão de Frotas com retry automático em 429/5xx.
    Retorna (data_dict, novo_token_ou_None) ou levanta exceção com mensagem.
    """
    import urllib.request, urllib.error, json as _json, ssl as _ssl, time as _time
    ctx = _ssl.create_default_context()
    body = _json.dumps(payload).encode()

    for _tentativa in range(1, _retry + 1):
        req = urllib.request.Request(_PROFROTAS_PESQ, data=body, method="POST")
        req.add_header("Authorization", f"Bearer {token}")
        req.add_header("Content-Type", "application/json")
        req.add_header("Accept", "application/json")
        try:
            with urllib.request.urlopen(req, context=ctx, timeout=30) as resp:
                novo_token = resp.headers.get("Renovacao-Automatica-JWT")
                data = _json.loads(resp.read().decode())
                return data, novo_token
        except urllib.error.HTTPError as e:
            if e.code == 429 and _tentativa < _retry:
                # Rate limit — espera progressiva: 5s, 15s, 30s
                _wait = [5, 15, 30][_tentativa - 1]
                _time.sleep(_wait)
                continue
            raise RuntimeError(f"HTTP {e.code}: {e.reason}")
        except Exception as e:
            if _tentativa < _retry:
                _time.sleep(3)
                continue
            raise RuntimeError(str(e))
    raise RuntimeError("Máximo de tentativas atingido.")


def _profrotas_validar_token(token: str) -> tuple[bool, str]:
    """Valida o token fazendo uma requisição mínima (1 registro).
    Retorna (ok: bool, mensagem: str).
    """
    import datetime as _dt
    hoje = _dt.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    try:
        data, _ = _profrotas_request(token, {
            "pagina": 1, "dataInicial": hoje, "dataFinal": hoje
        })
        if isinstance(data, dict) and "totalItems" in data:
            return True, f"Token válido — frota autenticada com sucesso."
        return False, f"Resposta inesperada: {str(data)[:120]}"
    except RuntimeError as e:
        return False, str(e)


def _profrotas_salvar_chave(cnpj_frota: str, nome_empresa: str,
                             token: str, criado_por: str = "") -> tuple[bool, str]:
    """Salva ou atualiza a chave API de um cliente no Supabase."""
    import datetime as _dt
    _db = _db_client()
    if not _db:
        return False, "Supabase não disponível."
    cnpj_norm = re.sub(r"\D", "", str(cnpj_frota).strip())
    try:
        payload = {
            "cnpj_frota":       cnpj_norm,
            "nome_empresa":     nome_empresa.strip(),
            "token":            token.strip(),
            "ativo":            True,
            "data_cadastro":    _dt.datetime.now(tz=_dt.timezone(_dt.timedelta(hours=-3))).isoformat(),
            "data_inicio_sync": _dt.datetime.now(tz=_dt.timezone(_dt.timedelta(hours=-3))).isoformat(),
            "criado_por":       criado_por,
            "registros_sync":   0,
        }
        _db.table("profrotas_api_keys").upsert(
            payload, on_conflict="cnpj_frota"
        ).execute()
        return True, "Chave salva com sucesso."
    except Exception as e:
        return False, str(e)


def _profrotas_listar_chaves() -> list:
    """
    Retorna lista de chaves cadastradas.
    Multi-tenant: admin/analista veem todas; gestor_frota/posto só veem a própria.
    """
    _db = _db_client()
    if not _db:
        return []
    try:
        _perfil_ch = st.session_state.get("_auth_perfil", "")
        _q = _db.table("profrotas_api_keys").select("*").order("nome_empresa")
        if _perfil_ch not in ("admin", "analista"):
            # Filtra pelo CNPJ da empresa vinculada ao usuário
            _emp_ch  = st.session_state.get("_empresa_ativa") or {}
            _cnpj_ch = (_emp_ch.get("cnpj") or
                        st.session_state.get("_auth_cnpj_vinculado") or "").strip()
            if _cnpj_ch:
                import re as _re_ch
                _cnpj_ch = _re_ch.sub(r"\D", "", _cnpj_ch)
                _q = _q.eq("cnpj_frota", _cnpj_ch)
            else:
                return []  # sem CNPJ → não exibe nada por segurança
        r = _q.execute()
        return r.data or []
    except Exception:
        return []



def _cnpj_usuario_atual() -> str | None:
    """
    Retorna o CNPJ normalizado (só dígitos) do usuário logado,
    ou None se for admin/analista (visão total).
    """
    import re as _re_cnpj
    _p = st.session_state.get("_auth_perfil", "")
    if _p in ("admin", "analista", ""):
        return None
    _emp = st.session_state.get("_empresa_ativa") or {}
    _cnpj = (_emp.get("cnpj") or
             st.session_state.get("_auth_cnpj_vinculado") or "").strip()
    return _re_cnpj.sub(r"\D", "", _cnpj) or None

# ─── Auto-sync: watchdog global — reinicia threads mortas em todo rerun ───────
try:
    _auto_sync_heartbeat()
    _AUTO_SYNC_INITIALIZED = True   # type: ignore[assignment]
except Exception as _e_as_init:
    _AUTO_SYNC_STATUS["_startup_error"] = {
        "status": "erro", "msg": str(_e_as_init)[:200],
    }



_PROFROTAS_BATCH_SIZE = 25   # linhas por upsert — evita limite de payload Supabase


def _profrotas_garantir_tabela(db) -> tuple[bool, str]:
    """
    Garante que a tabela profrotas_abastecimentos existe no Supabase.
    Tenta criar via SQL RPC; se não disponível, testa com SELECT.
    Retorna (ok, mensagem_erro).
    """
    _ddl = """
    CREATE TABLE IF NOT EXISTS profrotas_abastecimentos (
        id                      bigserial,
        sync_key                text        NOT NULL,
        cnpj_frota              text        NOT NULL,
        identificador           text,
        item_id                 text        NOT NULL DEFAULT '',
        abastecimento_estornado boolean,
        data_abastecimento      timestamptz,
        data_atualizacao        timestamptz,
        data_transacao          timestamptz,
        status_autorizacao      text,
        motivo_recusa           text,
        motivo_cancelamento     text,
        hodometro               numeric,
        horimetro               numeric,
        frota_cnpj              text,
        frota_razao_social      text,
        motorista_id            text,
        motorista_nome          text,
        veiculo_id              text,
        veiculo_placa           text,
        pv_cnpj                 text,
        pv_razao_social         text,
        pv_posto_interno        boolean,
        pv_municipio            text,
        pv_uf                   text,
        pv_latitude             numeric,
        pv_longitude            numeric,
        item_nome               text,
        item_tipo               integer,
        item_quantidade         numeric,
        item_valor_unitario     numeric,
        item_valor_total        numeric,
        payload_raw             jsonb,
        criado_em               timestamptz DEFAULT now(),
        PRIMARY KEY (sync_key)
    );
    CREATE INDEX IF NOT EXISTS idx_pfa_cnpj_frota   ON profrotas_abastecimentos(cnpj_frota);
    CREATE INDEX IF NOT EXISTS idx_pfa_data         ON profrotas_abastecimentos(data_abastecimento DESC);
    CREATE INDEX IF NOT EXISTS idx_pfa_placa        ON profrotas_abastecimentos(veiculo_placa);
    """
    try:
        db.rpc("exec_sql", {"sql": _ddl}).execute()
    except Exception:
        pass

    # Garante unique constraint em sync_key (necessário para upsert ON CONFLICT)
    _ddl_uc = """
    DO $$ BEGIN
        IF NOT EXISTS (
            SELECT 1 FROM pg_constraint
            WHERE conname = 'profrotas_abastecimentos_sync_key_key'
        ) THEN
            ALTER TABLE profrotas_abastecimentos
                ADD CONSTRAINT profrotas_abastecimentos_sync_key_key UNIQUE (sync_key);
        END IF;
    END $$;
    """
    try:
        db.rpc("exec_sql", {"sql": _ddl_uc}).execute()
    except Exception:
        pass  # sem RPC ou constraint já existe — sem problema, Estratégia 3 cobre
        return True, ""
    except Exception:
        pass
    # Fallback: verifica se a tabela existe (coluna cnpj_frota sempre presente)
    try:
        db.table("profrotas_abastecimentos").select("cnpj_frota").limit(1).execute()
    except Exception as _e:
        _msg = str(_e)
        if "42P01" in _msg or "relation" in _msg.lower():
            return False, (
                "A tabela `profrotas_abastecimentos` não existe no Supabase. "
                "Execute o arquivo `profrotas_api.sql` no SQL Editor do Supabase para criá-la."
            )
        # Outro erro (ex: RLS) — tabela existe, continua
    # Verifica se a coluna sync_key existe; se não, tenta adicioná-la via RPC
    try:
        db.table("profrotas_abastecimentos").select("sync_key").limit(1).execute()
    except Exception:
        # sync_key ausente — tabela antiga; tenta adicionar a coluna
        _alter = """
        ALTER TABLE profrotas_abastecimentos
            ADD COLUMN IF NOT EXISTS sync_key text;
        UPDATE profrotas_abastecimentos
           SET sync_key = md5(cnpj_frota || '|' || COALESCE(identificador,'sem_id') || '|' || COALESCE(item_id,''))
         WHERE sync_key IS NULL;
        ALTER TABLE profrotas_abastecimentos
            ALTER COLUMN sync_key SET NOT NULL;
        DO $$ BEGIN
            IF NOT EXISTS (
                SELECT 1 FROM pg_constraint
                 WHERE conname = 'profrotas_abastecimentos_pkey'
            ) THEN
                ALTER TABLE profrotas_abastecimentos ADD PRIMARY KEY (sync_key);
            END IF;
        END $$;
        """
        try:
            db.rpc("exec_sql", {"sql": _alter}).execute()
        except Exception:
            pass   # sem RPC — o upsert usará INSERT com fallback
    return True, ""


def _profrotas_sync(cnpj_frota: str, token: str,
                    data_inicio: str, progress_cb=None,
                    _db_override=None,
                    _usuario_email: str | None = None) -> tuple[int, int, str | None, str, int]:
    """Busca todos os abastecimentos desde data_inicio e salva no Supabase.

    _db_override: cliente Supabase externo (usado pelo auto-sync em threads
    background para evitar dependência de st.session_state).
    Retorna (paginas, salvos, novo_token_ou_None, erro_msg, total_api).
    """
    import datetime as _dt, json as _json, hashlib as _hl
    _db = _db_override or _db_client()
    if not _db:
        return 0, 0, None, "Supabase não disponível. Verifique as configurações em st.secrets.", 0

    # ── Garante que a tabela existe antes de tentar salvar ──────────
    _tab_ok, _tab_err = _profrotas_garantir_tabela(_db)
    if not _tab_ok:
        return 0, 0, None, _tab_err, 0

    novo_token  = None
    pagina      = 1
    total_salvos        = 0
    total_items         = None
    total_registros_api = 0   # registros da API (≠ rows expandidas por item)
    erros_batch         = []
    hoje = _dt.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")

    def _make_sync_key(cnpj: str, ident, item: str) -> str:
        """Chave determinística para upsert — nunca é NULL."""
        _raw = f"{cnpj}|{ident or 'sem_id'}|{item or ''}"
        return _hl.md5(_raw.encode()).hexdigest()

    def _safe_ts(val):
        """Converte string de data para ISO sem fuso horário extra."""
        if not val:
            return None
        try:
            return str(val).replace("Z", "+00:00")
        except Exception:
            return None

    def _safe_num(val):
        """Converte para float seguro ou None."""
        try:
            return float(val) if val is not None else None
        except (TypeError, ValueError):
            return None

    def _upsert_batch(rows: list) -> str | None:
        """Faz upsert de um lote com 3 estratégias em cascata."""
        import json as _j

        # ── Sanitização inline — sem dependência de _sanitize_row ────────────
        # Colunas integer no Supabase não aceitam Python bool nem string "false".
        # Todas as colunas integer/bigint da tabela real no Supabase
        _INT_COLS = {
            "item_tipo", "abastecimento_estornado",
            "hodometro", "horimetro",
            "status_autorizacao",
            "identificador", "motorista_id", "veiculo_id",
        }

        def _fix(k, v):
            # Regra 1: bool Python → 0/1 (aceito por boolean e integer no PG)
            if isinstance(v, bool):
                return int(v)
            # Regra 2: float inteiro (ex: 193900.0) → int
            # Colunas hodometro/horimetro podem ser integer na tabela real.
            if isinstance(v, float):
                try:
                    if v == int(v):
                        return int(v)
                except (ValueError, OverflowError):
                    pass
                return v
            # Regra 3: colunas explicitamente integer (item_tipo)
            if k in _INT_COLS:
                if v is None:
                    return None
                if isinstance(v, str) and v.strip().lower() in ("false", "true", ""):
                    return None
                try:
                    return int(float(v))
                except (TypeError, ValueError):
                    return None
            return v

        _rows_safe = []
        for _r in rows:
            _row = {k: _fix(k, v) for k, v in _r.items()}
            if isinstance(_row.get("payload_raw"), dict):
                _row["payload_raw"] = _j.dumps(_row["payload_raw"], ensure_ascii=False, default=str)
            _rows_safe.append(_row)

        # Estratégia 1: upsert por sync_key
        _e1_msg = ""
        try:
            _db.table("profrotas_abastecimentos").upsert(
                _rows_safe, on_conflict="sync_key"
            ).execute()
            return None
        except Exception as _e1:
            _e1_msg = str(_e1)[:120]

        # Estratégia 2: upsert por identificador+cnpj_frota+item_id (tabela antiga com unique constraint)
        _rows_sem_sk = [{k: v for k, v in r.items() if k != "sync_key"} for r in _rows_safe]
        try:
            _db.table("profrotas_abastecimentos").upsert(
                _rows_sem_sk, on_conflict="cnpj_frota,identificador,item_id"
            ).execute()
            return None
        except Exception as _e2:
            pass

        # Estratégia 3: INSERT individual — duplicate key = já existe = OK
        _salvos3 = 0
        _already3 = 0
        _last_err = ""
        for _single in _rows_safe:
            _row_sk = {k: v for k, v in _single.items() if k != "id"}
            try:
                _db.table("profrotas_abastecimentos").insert(
                    _row_sk, returning="minimal"
                ).execute()
                _salvos3 += 1
            except Exception as _e3:
                _e3s = str(_e3).lower()
                if "duplicate" in _e3s or "unique" in _e3s or "23505" in _e3s:
                    _already3 += 1  # registro já existe — não é erro real
                else:
                    _last_err = str(_e3)[:120]
        if _salvos3 + _already3 > 0:
            return None   # todos processados (inseridos ou já existentes)
        return f"Todas as estratégias falharam. Último erro: {_last_err}"

    def _sanitize_row(row: dict) -> dict:
        """Converte booleans Python para None em colunas integer do Supabase.
        Evita erro: invalid input syntax for type integer: "false".
        """
        _INT_COLS = {"item_tipo"}
        out = {}
        for k, v in row.items():
            if k in _INT_COLS and isinstance(v, bool):
                out[k] = None
            elif k in _INT_COLS and isinstance(v, str) and v.strip().lower() in ("false","true",""):
                out[k] = None
            else:
                out[k] = v
        return out

    while True:
        payload = {"pagina": pagina, "dataInicial": data_inicio, "dataFinal": hoje}
        try:
            data, _novo = _profrotas_request(token, payload)
        except RuntimeError as e:
            _err_msg = f"Erro API pág {pagina}: {e}"
            if total_salvos > 0:
                _err_msg += f" ({total_salvos} registros anteriores já salvos)"
            return pagina - 1, total_salvos, novo_token, _err_msg, total_items or 0

        # Salva resposta da 1ª página para debug (só em contexto Streamlit)
        if pagina == 1 and isinstance(data, dict) and _db_override is None:
            try:
                import streamlit as _st_dbg
                _st_dbg.session_state["_profrotas_last_response"] = {
                    k: (v if k != "registros" else f"[{len(v)} registros]")
                    for k, v in data.items()
                }
            except Exception:
                pass   # ignora em threads background

        if _novo:
            novo_token = _novo

        if not isinstance(data, dict):
            return pagina, total_salvos, novo_token, \
                   f"Resposta inválida da API: {str(data)[:200]}", total_items or 0

        # Chaves alternativas que a API Gestão de Frotas pode retornar
        registros = (data.get("registros") or data.get("items") or
                     data.get("data") or data.get("content") or [])
        if total_items is None:
            total_items = int(
                data.get("totalItems") or data.get("total") or
                data.get("totalRegistros") or data.get("count") or 0
            )
        tam_pag = int(data.get("tamanhoPagina", _PROFROTAS_PAGE_SIZE)) or _PROFROTAS_PAGE_SIZE

        if progress_cb:
            progress_cb(pagina, total_items, tam_pag)

        total_registros_api += len(registros)
        rows_pagina = []
        for reg in registros:
            _id    = str(reg.get("identificador") or "")
            _data  = _safe_ts(reg.get("data") or reg.get("dataTransacao"))
            _frt   = reg.get("frota") or {}
            _mot   = reg.get("motorista") or {}
            _vei   = reg.get("veiculo") or {}
            _pv    = reg.get("pontoVenda") or {}
            _end   = _pv.get("endereco") or {}
            _itens = reg.get("items") or []

            _base = {
                "cnpj_frota":              cnpj_frota,
                "identificador":           _id or None,
                "abastecimento_estornado": bool(reg.get("abastecimentoEstornado")),
                "data_abastecimento":      _data,
                "data_atualizacao":        _safe_ts(reg.get("dataAtualizacao")),
                "data_transacao":          _safe_ts(reg.get("dataTransacao")),
                "status_autorizacao":      reg.get("statusAutorizacao"),
                "motivo_recusa":           reg.get("motivoRecusa"),
                "motivo_cancelamento":     reg.get("motivoCancelamento"),
                "hodometro":               _safe_num(reg.get("hodometro")),
                "horimetro":               _safe_num(reg.get("horimetro")),
                "frota_cnpj":              re.sub(r"\D", "", str(_frt.get("cnpj") or "")).zfill(14),
                "frota_razao_social":      _frt.get("razaoSocial"),
                "motorista_id":            str(_mot.get("identificador") or "") or None,
                "motorista_nome":          _mot.get("nome"),
                "veiculo_id":              str(_vei.get("identificador") or "") or None,
                "veiculo_placa":           _vei.get("placa"),
                "pv_cnpj":                 re.sub(r"\D", "", str(_pv.get("cnpj") or "")).zfill(14),
                "pv_razao_social":         _pv.get("razaoSocial"),
                "pv_posto_interno":        bool(_pv.get("postoInterno")),
                "pv_municipio":            _end.get("municipio"),
                "pv_uf":                   _end.get("uf"),
                "pv_latitude":             _safe_num(_end.get("latitude")),
                "pv_longitude":            _safe_num(_end.get("longitude")),
                "payload_raw":             reg,
            }

            if _itens:
                for item in _itens:
                    _tipo_raw = item.get("tipo")
                    if isinstance(_tipo_raw, dict):
                        _tipo_raw_val = _tipo_raw.get("codigo")
                        _item_nome_extra = _tipo_raw.get("valor")
                    else:
                        _tipo_raw_val = _tipo_raw
                        _item_nome_extra = None
                    # Converte para int seguro — rejeita booleans e strings inválidas
                    try:
                        # Cobre: None, bool Python, string "false"/"true" (API retorna campo vazio)
                        if (_tipo_raw_val is None or isinstance(_tipo_raw_val, bool)
                                or (isinstance(_tipo_raw_val, str)
                                    and _tipo_raw_val.strip().lower() in ("false","true",""))):
                            _tipo_int = None
                        else:
                            try:
                                _tipo_int = int(_tipo_raw_val)
                            except (TypeError, ValueError):
                                _tipo_int = None
                    except (TypeError, ValueError):
                        _tipo_int = None
                    _iid = str(item.get("identificador") or "")
                    row  = dict(_base)
                    row["item_id"]             = _iid
                    row["item_nome"]           = item.get("nome") or _item_nome_extra
                    row["item_tipo"]           = _tipo_int
                    row["item_quantidade"]     = _safe_num(item.get("quantidade"))
                    row["item_valor_unitario"] = _safe_num(item.get("valorUnitario"))
                    row["item_valor_total"]    = _safe_num(item.get("valorTotal"))
                    row["sync_key"]            = _make_sync_key(cnpj_frota, _id, _iid)
                    rows_pagina.append(row)
            else:
                _base["item_id"]  = ""
                _base["sync_key"] = _make_sync_key(cnpj_frota, _id, "")
                rows_pagina.append(_base)

        # Salva em micro-lotes de _PROFROTAS_BATCH_SIZE
        for _i in range(0, len(rows_pagina), _PROFROTAS_BATCH_SIZE):
            _lote = rows_pagina[_i: _i + _PROFROTAS_BATCH_SIZE]
            _err  = _upsert_batch(_lote)
            if _err:
                erros_batch.append(f"Pág {pagina} lote {_i//25+1}: {_err[:120]}")
            else:
                total_salvos += len(_lote)
                # ── Persiste também em frota_abastecimentos (tabela unificada) ──
                if _usuario_email:
                    try:
                        _rows_unif = []
                        for _r in _lote:
                            _rows_unif.append({
                                "usuario_email":      _usuario_email,
                                "id_transacao":       _r.get("sync_key"),
                                "data_abastecimento": _r.get("data_abastecimento"),
                                "placa":              str(_r.get("veiculo_placa") or "").upper().strip(),
                                "motorista":          str(_r.get("motorista_nome") or ""),
                                "produto":            str(_r.get("item_nome") or ""),
                                "litros":             _r.get("item_quantidade"),
                                "preco_litro":        _r.get("item_valor_unitario"),
                                "valor_total":        _r.get("item_valor_total"),
                                "hodometro":          _r.get("hodometro"),
                                "cnpj_posto":         str(_r.get("pv_cnpj") or ""),
                                "nome_posto":         str(_r.get("pv_razao_social") or ""),
                                "cidade_posto":       str(_r.get("pv_municipio") or ""),
                                "uf_posto":           str(_r.get("pv_uf") or ""),
                                "lat_posto":          _r.get("pv_latitude"),
                                "lon_posto":          _r.get("pv_longitude"),
                                "cnpj_frota":         _r.get("cnpj_frota"),
                                "nome_arquivo":       "GestaoFrotas API",
                                "fonte":              "gestaoFrotas",
                            })
                        _db.table("frota_abastecimentos").upsert(
                            _rows_unif,
                            on_conflict="usuario_email,id_transacao",
                            ignore_duplicates=True,
                        ).execute()
                    except Exception:
                        pass

        # ── Condição de parada robusta — usa totalItems como controle primário ──
        # Não para em páginas parciais (falsos negativos causavam sync incompleto).
        import math as _math_pg
        _total_pg = (_math_pg.ceil(total_items / tam_pag)
                     if total_items and tam_pag else None)
        if not registros:
            break   # página vazia = fim real
        if _total_pg and pagina >= _total_pg:
            break   # última página esperada atingida
        if total_items and total_registros_api >= total_items:
            break   # todos os registros da API já buscados
        if not total_items and len(registros) < tam_pag:
            break   # fallback: sem totalItems, página curta = fim
        pagina += 1
        import time as _time_pag
        _time_pag.sleep(0.3)  # reduzido: 0.5s → 0.3s

    # Atualiza metadados da chave
    try:
        import datetime as _dt2
        _db.table("profrotas_api_keys").update({
            "ultimo_sync":    _dt2.datetime.utcnow().isoformat(),
            "registros_sync": total_salvos,
            **({"token": novo_token} if novo_token else {}),
        }).eq("cnpj_frota", cnpj_frota).execute()
    except Exception:
        pass

    _err_final = "; ".join(erros_batch) if erros_batch else ""
    return pagina, total_salvos, novo_token, _err_final, total_items or 0


def _profrotas_carregar_abast(cnpj_frota: str | None = None,
                               dias: int = 90) -> "pd.DataFrame":
    """Carrega abastecimentos do Supabase com paginação (sem limite de 1000).
    Salva o último erro em session_state['_profrotas_read_error'] para diagnóstico.
    """
    import datetime as _dt
    _db = _db_client()
    if not _db:
        return pd.DataFrame()
    try:
        todos = []
        _page_size = 1000
        _offset = 0
        while True:
            q = (_db.table("profrotas_abastecimentos")
                 .select("*")
                 .order("data_abastecimento", desc=True)
                 .limit(_page_size)
                 .offset(_offset))
            # Aplica filtro de data apenas se dias > 0
            if dias and dias > 0:
                desde = (_dt.datetime.utcnow() - _dt.timedelta(days=dias)).isoformat()
                q = q.gte("data_abastecimento", desde)
            if cnpj_frota:
                q = q.eq("cnpj_frota", cnpj_frota)
            r = q.execute()
            batch = r.data or []
            todos.extend(batch)
            if len(batch) < _page_size:
                break
            _offset += _page_size
        import streamlit as _st2
        _st2.session_state.pop("_profrotas_read_error", None)
        return pd.DataFrame(todos)
    except Exception as _re:
        import streamlit as _st2
        _st2.session_state["_profrotas_read_error"] = str(_re)
        return pd.DataFrame()


