# ── Persistência ────────────────────────────────────────────────────

def _intel_seed_from_db(hist: dict) -> int:
    """
    Popula o histórico local a partir do Supabase quando o JSON está vazio.
    Lê até 5.000 registros mais recentes e os converte para o formato interno.
    Retorna quantidade de entradas adicionadas.
    """
    try:
        rows = _db_paginar(
            "historico_precos",
            "cnpj,razao_social,municipio,uf,combustivel,preco,data_ref",
            order_by="data_ref", order_desc=True,
        )
    except Exception:
        return 0

    adicionados = 0
    for r in rows:
        _cnpj = re.sub(r"\D", "", str(r.get("cnpj") or ""))
        if len(_cnpj) != 14:
            continue
        _comb  = str(r.get("combustivel") or "").upper().strip()
        _preco = float(r.get("preco") or 0)
        _data  = str(r.get("data_ref") or "")[:10]
        if not _comb or _preco <= 0 or not _data:
            continue
        _lista = hist.setdefault(_cnpj, [])
        _ja = any(e.get("data") == _data and e.get("combustivel") == _comb
                  for e in _lista)
        if not _ja:
            _lista.append({
                "data":        _data,
                "preco":       round(_preco, 3),
                "combustivel": _comb,
                "nome":        str(r.get("razao_social") or ""),
                "municipio":   str(r.get("municipio") or ""),
                "uf":          str(r.get("uf") or ""),
            })
            adicionados += 1
    return adicionados


def _intel_load() -> dict:
    """
    Carrega dados de inteligência.
    Ordem de prioridade:
      1. Cache da sessão (mais rápido — evita releituras)
      2. _intel_data.json local
      3. Supabase historico_precos (fallback quando o JSON está vazio/inexistente)
    """
    if st.session_state.get("_intel_loaded"):
        return st.session_state.get("_intel_data", {})
    try:
        if _os_mod.path.exists(_INTEL_PATH):
            with open(_INTEL_PATH, "r", encoding="utf-8") as _f:
                _data = _json_mod.load(_f)
        else:
            _data = {}
    except Exception:
        _data = {}
    _data.setdefault("historico", {})   # {cnpj14: [{data, preco, combustivel, nome, municipio, uf}]}
    _data.setdefault("limiar",    {})   # {combustivel: float}
    _data.setdefault("last_report", None)

    # Se o histórico local está vazio, tenta recuperar do Supabase
    # (acontece quando o servidor reinicia e perde o _intel_data.json)
    if not _data["historico"]:
        _n_seed = _intel_seed_from_db(_data["historico"])
        if _n_seed > 0:
            # Persiste imediatamente no JSON local para próximas leituras
            try:
                with open(_INTEL_PATH, "w", encoding="utf-8") as _f:
                    _json_mod.dump(_data, _f, ensure_ascii=False, separators=(",", ":"))
            except Exception:
                pass

    st.session_state["_intel_data"]   = _data
    st.session_state["_intel_loaded"] = True
    return _data


def _intel_save(data: dict) -> bool:
    """Persiste dados de inteligência no JSON."""
    try:
        with open(_INTEL_PATH, "w", encoding="utf-8") as _f:
            _json_mod.dump(data, _f, ensure_ascii=False, separators=(",", ":"))
        st.session_state["_intel_data"]   = data
        st.session_state["_intel_loaded"] = True
        return True
    except Exception:
        return False


# ── Registro de observações de preço ───────────────────────────────

def _hist_record_lote(
    df: "pd.DataFrame",
    combustivel: str,
    data_str: str = None,
) -> int:
    """
    Registra preços de um DataFrame de postos no histórico.
    df precisa de: cnpj (ou _cnpj_norm), razaoSocial/nome, coluna de preço.
    Retorna quantidade de novos registros adicionados.
    """
    if df is None or df.empty:
        return 0
    if data_str is None:
        data_str = datetime.now().strftime("%Y-%m-%d")

    # detecta coluna de preço
    _preco_col = None
    for _c in df.columns:
        _cl = _c.lower()
        if "preco" in _cl or "preço" in _cl or _cl.startswith("_preco"):
            _preco_col = _c
            break
    if _preco_col is None:
        return 0

    # detecta coluna de CNPJ
    _cnpj_col = ("_cnpj_norm" if "_cnpj_norm" in df.columns
                 else ("cnpj" if "cnpj" in df.columns else None))
    if _cnpj_col is None:
        return 0

    _nome_col = next((c for c in ["razaoSocial","nome","nomeFantasia"] if c in df.columns), None)
    _mun_col  = "municipio" if "municipio" in df.columns else None
    _uf_col   = "uf"        if "uf"        in df.columns else None

    intel = _intel_load()
    hist  = intel["historico"]
    novos = 0

    for _, row in df.iterrows():
        _cnpj = re.sub(r"\D", "", str(row.get(_cnpj_col, "") or ""))
        if len(_cnpj) != 14:
            continue
        _preco = pd.to_numeric(row.get(_preco_col), errors="coerce")
        if pd.isna(_preco) or _preco <= 0:
            continue

        _entry: dict = {"data": data_str, "preco": round(float(_preco), 3),
                        "combustivel": combustivel}
        if _nome_col: _entry["nome"]      = str(row.get(_nome_col, ""))[:50]
        if _mun_col:  _entry["municipio"] = str(row.get(_mun_col,  ""))
        if _uf_col:   _entry["uf"]        = str(row.get(_uf_col,   ""))

        _lista = hist.setdefault(_cnpj, [])
        _ja_tem = any(
            e.get("data") == data_str and e.get("combustivel") == combustivel
            for e in _lista
        )
        if not _ja_tem:
            _lista.append(_entry)
            if len(_lista) > 52:
                _lista[:] = sorted(_lista, key=lambda e: e.get("data", ""))[-52:]
            novos += 1

    if novos > 0:
        _intel_save(intel)
    return novos


def _hist_record_pp_df(pp_df: "pd.DataFrame") -> int:
    """
    Registra preços do _pp_df normalizado no histórico local (JSON) E no Supabase.

    _pp_df tem colunas: cnpj_norm, combustivel_pk, combustivel_label,
                        preco, data_atualizacao.
    Retorna quantidade de registros efetivamente novos no JSON local.

    Design:
    - Supabase recebe TODOS os registros válidos (o banco lida com deduplicação).
    - JSON local só acumula registros realmente novos (evita crescimento ilimitado).
    - Erros do Supabase são gravados em st.session_state["_hist_db_erro"]
      para o UI exibir sem travar o fluxo.
    """
    if pp_df is None or pp_df.empty:
        return 0

    # Limpa erro anterior imediatamente — evita que erros de runs anteriores
    # fiquem visíveis quando o Supabase não é chamado (pp_df vazio, sem conexão…)
    st.session_state.pop("_hist_db_erro", None)

    _hoje = datetime.now().strftime("%Y-%m-%d")

    # ── Lookup de localização: CNPJ → {razao_social, municipio, uf, lat, lon} ──
    _pf_lookup: dict = {}
    try:
        _pf_ss = st.session_state.get("pf_coords_df")
        if _pf_ss is not None and not _pf_ss.empty and "cnpj" in _pf_ss.columns:
            # Vetorizado: sem iterrows()
            _pf_cnpjs = _pf_ss["cnpj"].astype(str).str.replace(r"\D", "", regex=True)
            _mask_14  = _pf_cnpjs.str.len() == 14
            _pf_sub   = _pf_ss[_mask_14].copy()
            _pf_cnpjs = _pf_cnpjs[_mask_14]
            def _sf(col): return _pf_sub[col].fillna("").astype(str) if col in _pf_sub.columns else ""
            def _sfn(col):
                if col not in _pf_sub.columns: return [None]*len(_pf_sub)
                return pd.to_numeric(_pf_sub[col], errors="coerce").where(
                    pd.to_numeric(_pf_sub[col], errors="coerce").notna()).tolist()
            _rs_col = "razaoSocial" if "razaoSocial" in _pf_sub.columns else "razao_social"
            _pf_lookup = dict(zip(_pf_cnpjs, [
                {"razao_social": rs, "municipio": mu, "uf": uf, "lat": la, "lon": lo}
                for rs, mu, uf, la, lo in zip(
                    _sf(_rs_col), _sf("municipio"), _sf("uf"), _sfn("lat"), _sfn("lon"))
            ]))
    except Exception:
        pass

    intel = _intel_load()
    hist  = intel["historico"]
    novos = 0

    # ── Listas separadas: uma para Supabase (todos), outra para JSON (novos) ──
    # IMPORTANTE: a lista do Supabase inclui TODOS os registros válidos — não
    # apenas os "novos" para o JSON local — porque o histórico local pode estar
    # vazio após reinício do servidor mesmo que o Supabase já tenha os dados.
    # O banco cuida da deduplicação via UNIQUE CONSTRAINT.
    _supabase_registros: list = []

    for _, row in pp_df.iterrows():
        _cnpj = str(row.get("cnpj_norm", "") or "").strip()
        if len(_cnpj) != 14:
            continue
        _preco = pd.to_numeric(row.get("preco"), errors="coerce")
        if pd.isna(_preco) or _preco <= 0:
            continue
        _comb = str(
            row.get("combustivel_pk") or row.get("combustivel_label") or ""
        ).upper().strip()
        if not _comb:
            continue

        _data_raw = str(row.get("data_atualizacao", "") or "").strip()
        try:
            _data = pd.to_datetime(_data_raw, dayfirst=True).strftime("%Y-%m-%d")
        except Exception:
            _data = _hoje

        _loc = _pf_lookup.get(_cnpj, {})

        # ── Supabase: acumula todos (DB deduplica) ──
        _supabase_registros.append({
            "cnpj":         _cnpj,
            "razao_social": _loc.get("razao_social", ""),
            "municipio":    _loc.get("municipio", ""),
            "uf":           _loc.get("uf", ""),
            "combustivel":  _comb,
            "preco":        round(float(_preco), 3),
            "data_ref":     _data,
            "lat":          _loc.get("lat"),
            "lon":          _loc.get("lon"),
            "fonte":        "PP",
        })

        # ── JSON local: só adiciona se realmente novo ──
        _lista = hist.setdefault(_cnpj, [])
        _ja_tem = any(
            e.get("data") == _data and e.get("combustivel") == _comb
            for e in _lista
        )
        if not _ja_tem:
            _lista.append({
                "data":        _data,
                "preco":       round(float(_preco), 3),
                "combustivel": _comb,
                "nome":        _loc.get("razao_social", ""),
                "municipio":   _loc.get("municipio", ""),
                "uf":          _loc.get("uf", ""),
            })
            if len(_lista) > 52:
                _lista[:] = sorted(_lista, key=lambda e: e.get("data", ""))[-52:]
            novos += 1

    # ── 1. Persiste novos no JSON local ──
    if novos > 0:
        _intel_save(intel)
        st.session_state.pop("_intel_loaded", None)

    # ── 2. Envia TODOS para o Supabase (ignora duplicatas via constraint) ──
    # Deduplicar o lote ANTES de enviar: o Postgres rejeita batches em que
    # duas linhas do mesmo INSERT conflitam entre si (código 21000).
    if _supabase_registros:
        _dedup: dict = {}
        for _rec in _supabase_registros:
            _k = (_rec["cnpj"], _rec["combustivel"], _rec["data_ref"])
            _dedup[_k] = _rec          # última ocorrência vence
        _supabase_registros = list(_dedup.values())

    if _supabase_registros:
        _db = _db_client()
        if _db:
            # Insere em lotes de 200 usando DO NOTHING (ignore_duplicates=True).
            # DO NOTHING evita o erro 21000 "ON CONFLICT DO UPDATE cannot affect
            # row a second time" que ocorre com DO UPDATE quando duas linhas do
            # batch conflitam com a mesma linha existente.
            # Novos registros são inseridos; duplicatas são silenciosamente ignoradas.
            try:
                _CHUNK = 200
                for _i in range(0, len(_supabase_registros), _CHUNK):
                    _db.table("historico_precos").upsert(
                        _supabase_registros[_i: _i + _CHUNK],
                        on_conflict="cnpj,combustivel,data_ref",
                        ignore_duplicates=True,
                    ).execute()
                # limpa qualquer erro residual de execução anterior
                st.session_state.pop("_hist_db_erro", None)
            except Exception as _ei:
                # Fallback: envia um a um para isolar a linha problemática
                _ok = 0
                for _rec in _supabase_registros:
                    try:
                        _db.table("historico_precos").upsert(
                            [_rec],
                            on_conflict="cnpj,combustivel,data_ref",
                            ignore_duplicates=True,
                        ).execute()
                        _ok += 1
                    except Exception:
                        pass
                if _ok == 0:
                    st.session_state["_hist_db_erro"] = str(_ei)

    return novos


# ── Persistência de cargas PP no Supabase ──────────────────────────────────

def _garantir_tabelas_pp() -> bool:
    """
    Cria as tabelas cargas_precos_pp e variacoes_precos_pp se não existirem.
    Chamada automaticamente antes do primeiro upload de Preço Posto.
    """
    _db = _db_client()
    if _db is None:
        return False
    _ddl = """
    CREATE TABLE IF NOT EXISTS cargas_precos_pp (
        id              bigserial PRIMARY KEY,
        created_at      timestamptz DEFAULT now(),
        nome_arquivo    text,
        total_postos    integer DEFAULT 0,
        total_combustiveis integer DEFAULT 0,
        dados           jsonb
    );
    CREATE TABLE IF NOT EXISTS variacoes_precos_pp (
        id              bigserial PRIMARY KEY,
        created_at      timestamptz DEFAULT now(),
        carga_id        bigint,
        carga_anterior_id bigint,
        total_altas     integer DEFAULT 0,
        total_quedas    integer DEFAULT 0,
        total_novos     integer DEFAULT 0,
        total_removidos integer DEFAULT 0,
        dados           jsonb
    );
    """
    try:
        _db.rpc("exec_sql", {"sql": _ddl}).execute()
        return True
    except Exception:
        pass
    # Fallback: tenta verificar se as tabelas existem com SELECT
    try:
        _db.table("cargas_precos_pp").select("id").limit(1).execute()
        return True
    except Exception:
        return False


def _salvar_carga_pp_supabase(pp_df: "pd.DataFrame", nome_arquivo: str = "") -> "int | None":
    """
    Salva o snapshot completo de uma carga de Preços PP no Supabase.
    Retorna o id da linha inserida, ou None em caso de erro/sem conexão.
    """
    _db = _db_client()
    if _db is None or pp_df is None or pp_df.empty:
        return None
    try:
        _dados = pp_df.where(pp_df.notna(), None).to_dict(orient="records")
        _resp = _db.table("cargas_precos_pp").insert({
            "nome_arquivo":       nome_arquivo or "upload_manual",
            "total_postos":       int(pp_df["cnpj_norm"].nunique())       if "cnpj_norm"       in pp_df.columns else 0,
            "total_combustiveis": int(pp_df["combustivel_pk"].nunique())   if "combustivel_pk"  in pp_df.columns else 0,
            "dados":              _dados,
        }).execute()
        return _resp.data[0]["id"] if _resp.data else None
    except Exception as _e:
        st.session_state["_hist_db_erro"] = str(_e)
        return None


def _carregar_cargas_pp_supabase(n: int = 2) -> "list[dict]":
    """
    Carrega as n cargas PP mais recentes do Supabase.
    Cada item do retorno tem: id, created_at, nome_arquivo,
    total_postos, total_combustiveis, dados (lista de dicts).
    """
    _db = _db_client()
    if _db is None:
        return []
    try:
        _resp = (
            _db.table("cargas_precos_pp")
            .select("id,created_at,nome_arquivo,total_postos,total_combustiveis,dados")
            .order("created_at", desc=True)
            .limit(n)
            .execute()
        )
        return _resp.data or []
    except Exception:
        return []


def _salvar_variacao_pp_supabase(
    var_df: "pd.DataFrame",
    carga_id: int,
    carga_ant_id: "int | None",
) -> bool:
    """
    Salva o DataFrame de variação entre duas cargas PP no Supabase.
    Preenche também os contadores de altas/quedas/novos/removidos.
    """
    _db = _db_client()
    if _db is None or var_df is None or var_df.empty:
        return False
    try:
        _dados = var_df.where(var_df.notna(), None).to_dict(orient="records")
        _db.table("variacoes_precos_pp").insert({
            "carga_id":           carga_id,
            "carga_anterior_id":  carga_ant_id,
            "total_altas":        int((var_df.get("Status", pd.Series()) == "🔺 Alta").sum()),
            "total_quedas":       int((var_df.get("Status", pd.Series()) == "🔻 Queda").sum()),
            "total_novos":        int((var_df.get("Status", pd.Series()) == "🆕 Novo").sum()),
            "total_removidos":    int((var_df.get("Status", pd.Series()) == "🗑️ Removido").sum()),
            "dados":              _dados,
        }).execute()
        return True
    except Exception as _e:
        st.session_state["_hist_db_erro"] = str(_e)
        return False


def _carregar_ultima_variacao_pp_supabase() -> "pd.DataFrame | None":
    """Carrega o DataFrame do resultado da comparação mais recente do Supabase."""
    _db = _db_client()
    if _db is None:
        return None
    try:
        _resp = (
            _db.table("variacoes_precos_pp")
            .select("dados,created_at")
            .order("created_at", desc=True)
            .limit(1)
            .execute()
        )
        if _resp.data and _resp.data[0].get("dados"):
            return pd.DataFrame(_resp.data[0]["dados"])
        return None
    except Exception:
        return None


def _restaurar_estado_pp_do_supabase() -> None:
    """
    Chamada uma vez por sessão (flag _pp_restaurado_supabase).
    Restaura _pp_df e _pp_variacao do Supabase para que reboots
    não percam o histórico de cargas e comparações.
    Usa setdefault: não sobrescreve dados que já estejam na sessão.
    """
    if st.session_state.get("_pp_restaurado_supabase"):
        return
    st.session_state["_pp_restaurado_supabase"] = True

    # ── Restaura última carga ──────────────────────────────────
    try:
        _cargas = _carregar_cargas_pp_supabase(n=1)
        if _cargas and _cargas[0].get("dados"):
            _pp_restaurado = pd.DataFrame(_cargas[0]["dados"])
            if not _pp_restaurado.empty:
                st.session_state.setdefault("_pp_df",           _pp_restaurado)
                st.session_state.setdefault("_pp_carga_id",     _cargas[0]["id"])
                st.session_state.setdefault("_pp_carregado_em", _cargas[0].get("created_at", ""))
                st.session_state.setdefault("_pp_fonte",        "supabase")
    except Exception:
        pass

    # ── Restaura última variação ───────────────────────────────
    try:
        _var_restaurada = _carregar_ultima_variacao_pp_supabase()
        if _var_restaurada is not None and not _var_restaurada.empty:
            st.session_state.setdefault("_pp_variacao", _var_restaurada)
    except Exception:
        pass


# ── Telemetria: persistência no Supabase ─────────────────────────────────────

def _tele_salvar_frota_supabase(frota: list) -> bool:
    """
    Sincroniza a frota no Supabase usando DELETE + INSERT (evita ON CONFLICT).
    O índice partial WHERE ativo=true não é reconhecido pelo PostgREST como
    constraint de conflito, então upsert falhava com código 21000.
    """
    _db = _db_client()
    if _db is None or not frota:
        return False
    try:
        # Deduplica: mantém o último registro por placa
        _visto: dict = {}
        for v in frota:
            _placa = v.get("placa", "").strip()
            if _placa:
                _visto[_placa] = v
        if not _visto:
            return True
        # Apaga registros existentes para essas placas e reinsere
        _db.table("tele_frota").delete().in_("placa", list(_visto.keys())).execute()
        _registros = [
            {
                "placa":           _placa,
                "combustivel":     v.get("combustivel", ""),
                "tanque_l":        v.get("tanque_l"),
                "consumo_esp_kml": v.get("consumo_esp_kml"),
                "empresa":         v.get("empresa", ""),
                "modelo":          v.get("modelo", ""),
                "ativo":           True,
            }
            for _placa, v in _visto.items()
        ]
        _db.table("tele_frota").insert(_registros).execute()
        return True
    except Exception as _e:
        st.session_state["_hist_db_erro"] = str(_e)
        return False


def _tele_carregar_frota_supabase() -> list:
    """Carrega veículos ativos da tabela tele_frota com isolamento multi-tenant."""
    try:
        _perfil_tele = st.session_state.get("_auth_perfil", "")
        _filters = [("ativo", True)]
        # Admin/analista veem todos; outros veem só da própria empresa
        if _perfil_tele not in ("admin", "analista"):
            _emp_tele = st.session_state.get("_empresa_ativa") or {}
            _emp_id_tele = _emp_tele.get("id")
            _emp_nome_tele = _emp_tele.get("nome") or (
                st.session_state.get("_auth_usuario_db") or {}
            ).get("empresa_nome", "")
            if _emp_id_tele:
                _filters.append(("empresa_id", _emp_id_tele))
            elif _emp_nome_tele:
                _filters.append(("empresa", _emp_nome_tele))
            else:
                return []  # sem empresa identificada → não exibe nada
        return _db_paginar(
            "tele_frota",
            "placa,combustivel,tanque_l,consumo_esp_kml,empresa,modelo",
            filters=_filters,
        )
    except Exception:
        return []


def _tele_salvar_abastecimentos_supabase(abast: list) -> bool:
    """
    Insere novos abastecimentos no Supabase.
    Só insere registros que ainda não existem (placa + data_abast + litros como proxy de unicidade).
    """
    _db = _db_client()
    if _db is None or not abast:
        return False
    try:
        # Carrega TODOS os registros existentes para evitar duplicatas (paginação)
        _ex_rows = _db_paginar("tele_abastecimentos", "placa,data_abast,litros")
        _existentes = set()
        for _row in _ex_rows:
            _existentes.add((_row.get("placa", ""), str(_row.get("data_abast", "")), str(_row.get("litros", ""))))

        _novos = []
        for _a in abast:
            _chave = (
                str(_a.get("placa", "")),
                str(_a.get("data", ""))[:10],
                str(_a.get("litros", "")),
            )
            if _chave not in _existentes:
                _novos.append({
                    "placa":          str(_a.get("placa", "")),
                    "data_abast":     str(_a.get("data", ""))[:10] if _a.get("data") else None,
                    "litros":         _a.get("litros"),
                    "valor_total":    _a.get("valor_total"),
                    "preco_litro":    round(_a["valor_total"] / _a["litros"], 3)
                                      if _a.get("valor_total") and _a.get("litros") else None,
                    "hodometro":      _a.get("hodometro"),
                    "nome_posto":     _a.get("nome_posto", ""),
                    "cnpj_posto":     _a.get("cnpj_posto", ""),
                    "fonte":          _a.get("fonte", "manual"),
                })

        if _novos:
            _db.table("tele_abastecimentos").insert(_novos).execute()
        return True
    except Exception as _e:
        st.session_state["_hist_db_erro"] = str(_e)
        return False


def _tele_carregar_abastecimentos_supabase() -> list:
    """Carrega abastecimentos do Supabase com isolamento multi-tenant."""
    try:
        _perfil_ta = st.session_state.get("_auth_perfil", "")
        _filters_ta = []
        if _perfil_ta not in ("admin", "analista"):
            _emp_ta = st.session_state.get("_empresa_ativa") or {}
            _emp_id_ta = _emp_ta.get("id")
            if _emp_id_ta:
                _filters_ta = [("empresa_id", _emp_id_ta)]
            else:
                # Sem empresa identificada — filtra pelas placas da frota do usuário
                _placas_ta = {v.get("placa") for v in st.session_state.get("_tele_frota", []) if v.get("placa")}
                if not _placas_ta:
                    return []  # sem frota cadastrada → não exibe nada
                # Usa in_ para filtrar por placas conhecidas
                _db_ta = _db_client()
                if not _db_ta:
                    return []
                _raw_ta = (_db_ta.table("tele_abastecimentos")
                    .select("placa,data_abast,litros,valor_total,preco_litro,hodometro,nome_posto,cnpj_posto,fonte")
                    .in_("placa", list(_placas_ta))
                    .order("data_abast").execute().data or [])
                return [{
                    "placa": r.get("placa",""), "data": r.get("data_abast",""),
                    "litros": r.get("litros"), "valor_total": r.get("valor_total"),
                    "hodometro": r.get("hodometro"), "nome_posto": r.get("nome_posto",""),
                    "cnpj_posto": r.get("cnpj_posto",""), "fonte": r.get("fonte","supabase"),
                } for r in _raw_ta]
        _raw = _db_paginar(
            "tele_abastecimentos",
            "placa,data_abast,litros,valor_total,preco_litro,hodometro,nome_posto,cnpj_posto,fonte",
            filters=_filters_ta,
            order_by="data_abast", order_desc=False,
        )
        return [
            {
                "placa":       _r.get("placa", ""),
                "data":        _r.get("data_abast", ""),
                "litros":      _r.get("litros"),
                "valor_total": _r.get("valor_total"),
                "hodometro":   _r.get("hodometro"),
                "nome_posto":  _r.get("nome_posto", ""),
                "cnpj_posto":  _r.get("cnpj_posto", ""),
                "fonte":       _r.get("fonte", "supabase"),
            }
            for _r in _raw
        ]
    except Exception:
        return []


def _tele_restaurar_do_supabase() -> None:
    """
    Chamada uma vez por sessão (flag _tele_restaurado).
    Restaura _tele_frota e _tele_abast do Supabase para que reboots
    não percam os dados de telemetria cadastrados.
    """
    if st.session_state.get("_tele_restaurado"):
        return
    st.session_state["_tele_restaurado"] = True

    try:
        _frota_sb = _tele_carregar_frota_supabase()
        if _frota_sb:
            st.session_state.setdefault("_tele_frota", _frota_sb)
    except Exception:
        pass

    try:
        _abast_sb = _tele_carregar_abastecimentos_supabase()
        if _abast_sb:
            st.session_state.setdefault("_tele_abast", _abast_sb)
    except Exception:
        pass


# ═══════════════════════════════════════════════════════════════════
#  FIPE — ENRIQUECIMENTO DE FROTA VIA TABELA FIPE (parallelum API)
#  Fluxo: usuario seleciona Tipo → Marca → Modelo → Ano
#         API parallelum.com.br retorna dados + valor de mercado
#  Cache em Supabase (frota_veiculos_fipe) — TTL 30 dias.
# ═══════════════════════════════════════════════════════════════════

_FIPE_CACHE_TTL_DIAS = 30

# API oficial FIPE — site veiculos.fipe.org.br (POST)
_FIPE_OFICIAL_BASE = "https://veiculos.fipe.org.br/api/veiculos"
_FIPE_TIPO_COD     = {"carros": 1, "motos": 2, "caminhoes": 3}

# Cabeçalhos que imitam um navegador acessando o site FIPE
_FIPE_HEADERS = {
    "Content-Type":   "application/json;charset=UTF-8",
    "Accept":         "application/json, text/javascript, */*; q=0.01",
    "User-Agent":     (
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
        "AppleWebKit/537.36 (KHTML, like Gecko) "
        "Chrome/124.0.0.0 Safari/537.36"
    ),
    "Origin":         "https://veiculos.fipe.org.br",
    "Referer":        "https://veiculos.fipe.org.br/",
    "X-Requested-With": "XMLHttpRequest",
}

# BrasilAPI FIPE (marcas) — alternativa gratuita e confiável
_BRASILAPI_FIPE = "https://brasilapi.com.br/api/fipe"


def _fipe_normalizar_placa(placa: str) -> str:
    """Remove separadores e converte para maiúscula."""
    return re.sub(r"[^A-Z0-9]", "", str(placa or "").upper())


def _fipe_parse_valor(valor_str: str) -> float | None:
    """Converte 'R$ 45.678,00' → 45678.00."""
    try:
        _s = re.sub(r"[^\d,]", "", str(valor_str or ""))
        return float(_s.replace(",", ".")) if _s else None
    except Exception:
        return None


def _fipe_api_get(endpoint: str) -> list | dict:
    """
    Mantida por compatibilidade. Chama diretamente a API oficial FIPE.
    Retorna [] em caso de falha.
    """
    return []   # parallelum descontinuado — usar _fipe_marcas/_fipe_modelos/_fipe_anos/_fipe_valor


def _fipe_ref_code() -> int:
    """
    Retorna o código da tabela de referência mais recente da FIPE.
    Usa cache em session_state por 1 hora.
    """
    import requests as _req
    import time as _time
    _key = "_fipe_ref_code_cache"
    _cached = st.session_state.get(_key)
    if _cached and (_time.time() - _cached.get("ts", 0)) < 3600:
        return _cached["cod"]
    try:
        _r = _req.post(
            f"{_FIPE_OFICIAL_BASE}/ConsultarTabelaDeReferencia",
            json={},
            timeout=15,
            headers=_FIPE_HEADERS,
        )
        if _r.status_code == 200:
            _lista = _r.json()
            if _lista:
                _cod = int(_lista[0]["Codigo"])
                st.session_state[_key] = {"cod": _cod, "ts": _time.time()}
                return _cod
    except Exception:
        pass
    return 0   # 0 = tabela atual (aceitável como fallback)


def _fipe_post(endpoint: str, body: dict) -> list | dict:
    """
    POST genérico para a API oficial FIPE.
    Registra erros em session_state['_fipe_api_ultimo_erro'].
    """
    import requests as _req
    try:
        _r = _req.post(
            f"{_FIPE_OFICIAL_BASE}/{endpoint}",
            json=body,
            timeout=20,
            headers=_FIPE_HEADERS,
        )
        if _r.status_code == 200:
            st.session_state.pop("_fipe_api_ultimo_erro", None)
            return _r.json()
        _msg = f"FIPE oficial HTTP {_r.status_code}: {_r.text[:120]}"
        st.session_state["_fipe_api_ultimo_erro"] = _msg
    except Exception as _e:
        st.session_state["_fipe_api_ultimo_erro"] = f"FIPE oficial: {type(_e).__name__} — {_e}"
    return []


def _fipe_marcas(tipo: str) -> list:
    """
    Busca marcas FIPE.
    Tenta: 1) API oficial FIPE (POST)  2) BrasilAPI FIPE (GET).
    Retorna [{nome, codigo}].
    """
    import requests as _req
    _cod_tipo = _FIPE_TIPO_COD.get(tipo, 1)
    _ref      = _fipe_ref_code()

    # 1 — API oficial
    _erros = []
    _raw = _fipe_post(
        "ConsultarMarcas",
        {"codigoTabelaReferencia": _ref, "codigoTipoVeiculo": _cod_tipo},
    )
    if isinstance(_raw, list) and _raw:
        return [{"nome": d["Label"], "codigo": str(d["Value"])} for d in _raw]
    _erros.append(st.session_state.get("_fipe_api_ultimo_erro", "FIPE oficial sem dados"))

    # 2 — BrasilAPI FIPE
    try:
        _r2 = _req.get(
            f"{_BRASILAPI_FIPE}/marcas/v1/{tipo}",
            timeout=15,
            headers={"User-Agent": "FNI-Frota/2.0", "Accept": "application/json"},
        )
        if _r2.status_code == 200:
            _dados2 = _r2.json()
            if _dados2:
                st.session_state.pop("_fipe_api_ultimo_erro", None)
                # BrasilAPI retorna {nome, valor} — "valor" é o código
                return [{"nome": d.get("nome", d.get("Label","")),
                         "codigo": str(d.get("valor", d.get("Value","")))}
                        for d in _dados2]
        _erros.append(f"BrasilAPI HTTP {_r2.status_code}")
    except Exception as _e2:
        _erros.append(f"BrasilAPI: {type(_e2).__name__}")

    st.session_state["_fipe_api_ultimo_erro"] = " | ".join(_erros)
    return []


def _fipe_modelos(tipo: str, marca_cod: str) -> list:
    """
    Busca modelos FIPE para uma marca.
    Retorna [{nome, codigo}].
    """
    _cod_tipo = _FIPE_TIPO_COD.get(tipo, 1)
    _ref      = _fipe_ref_code()
    _raw = _fipe_post(
        "ConsultarModelos",
        {
            "codigoTipoVeiculo":    _cod_tipo,
            "codigoTabelaReferencia": _ref,
            "codigoMarca":          int(marca_cod),
        },
    )
    if isinstance(_raw, dict):
        _lista = _raw.get("Modelos", _raw.get("modelos", []))
    elif isinstance(_raw, list):
        _lista = _raw
    else:
        _lista = []
    return [{"nome": d["Label"], "codigo": str(d["Value"])} for d in _lista if "Label" in d]


def _fipe_anos(tipo: str, marca_cod: str, modelo_cod: str) -> list:
    """
    Busca anos/combustíveis FIPE para um modelo.
    Retorna [{nome, codigo}].
    """
    _cod_tipo = _FIPE_TIPO_COD.get(tipo, 1)
    _ref      = _fipe_ref_code()
    _raw = _fipe_post(
        "ConsultarAnoModelo",
        {
            "codigoTipoVeiculo":    _cod_tipo,
            "codigoTabelaReferencia": _ref,
            "codigoMarca":          int(marca_cod),
            "codigoModelo":         int(modelo_cod),
        },
    )
    if isinstance(_raw, list):
        return [{"nome": d["Label"], "codigo": str(d["Value"])} for d in _raw if "Label" in d]
    return []


def _fipe_valor(tipo: str, marca_cod: str, modelo_cod: str, ano_cod: str) -> dict:
    """
    Busca valor/detalhe FIPE para marca+modelo+ano específicos.
    ano_cod formato "AAAA-C" (ex: "2021-1" = 2021 Gasolina).
    Retorna dict com chaves: Marca, Modelo, AnoModelo, Combustivel,
    CodigoFipe, Valor, MesReferencia.
    """
    _cod_tipo = _FIPE_TIPO_COD.get(tipo, 1)
    _ref      = _fipe_ref_code()
    _partes   = str(ano_cod).split("-")
    _ano_num  = int(_partes[0]) if _partes and _partes[0].isdigit() else 0
    _comb_cod = int(_partes[1]) if len(_partes) > 1 and _partes[1].isdigit() else 1

    _raw = _fipe_post(
        "ConsultarValorComTodosParametros",
        {
            "codigoTipoVeiculo":    _cod_tipo,
            "codigoTabelaReferencia": _ref,
            "codigoMarca":          int(marca_cod),
            "codigoModelo":         int(modelo_cod),
            "ano":                  ano_cod,
            "codigoTipoCombustivel": _comb_cod,
            "anoModelo":            _ano_num,
            "modeloCodigoExterno":  "",
            "tipoConsulta":         "tradicional",
        },
    )
    if isinstance(_raw, dict) and _raw.get("Valor"):
        return _raw
    return {}


def _fipe_carregar_cache() -> dict:
    """Carrega cache Supabase. Retorna {placa_norm: {...}}."""
    _db = _db_client()
    if not _db:
        return {}
    try:
        _rows = _db_paginar("frota_veiculos_fipe", "*")
        return {r["placa"]: r for r in _rows}
    except Exception:
        return {}


def _fipe_salvar_registro(placa: str, dados: dict) -> tuple[bool, str]:
    """Upsert em frota_veiculos_fipe. Retorna (ok, erro)."""
    from datetime import timezone as _tz
    _db = _db_client()
    if not _db:
        return False, "Sem conexão com Supabase"
    try:
        _row = {
            "placa":            _fipe_normalizar_placa(placa),
            "marca":            dados.get("marca", ""),
            "modelo":           dados.get("modelo", ""),
            "ano_modelo":       dados.get("ano_modelo", ""),
            "cor":              dados.get("cor", ""),
            "tipo_veiculo":     dados.get("tipo_veiculo", ""),
            "municipio":        dados.get("municipio", ""),
            "uf_veiculo":       dados.get("uf_veiculo", ""),
            "codigo_fipe":      dados.get("codigo_fipe", ""),
            "valor_fipe":       dados.get("valor_fipe"),
            "combustivel_fipe": dados.get("combustivel_fipe", ""),
            "mes_referencia":   dados.get("mes_referencia", ""),
            "empresa_id":       _db_empresa_id(),
            "buscado_em":       datetime.now(_tz.utc).strftime("%Y-%m-%dT%H:%M:%SZ"),
        }
        _db.table("frota_veiculos_fipe").upsert(_row, on_conflict="placa").execute()
        return True, ""
    except Exception as _e:
        return False, str(_e)


# ── Lookup automático por placa ──────────────────────────────────────────────

_BRASILAPI_BASE = "https://brasilapi.com.br/api"


def _brasilapi_placa(placa: str) -> dict:
    """
    Consulta BrasilAPI /veiculos/v1/{placa} (dados DENATRAN/SINESP).
    Retorna dict com: marca, modelo, ano, cor, municipio, uf, combustivel.
    Em caso de falha retorna {}.
    """
    import requests as _req
    _p = _fipe_normalizar_placa(placa)
    if not _p:
        return {}
    try:
        _r = _req.get(
            f"{_BRASILAPI_BASE}/veiculos/v1/{_p}",
            timeout=12,
            headers={"User-Agent": "FNI-Frota/2.0", "Accept": "application/json"},
        )
        if _r.status_code == 200:
            _d = _r.json()
            return {
                "marca":      _d.get("marca", ""),
                "modelo":     _d.get("modelo", ""),
                "ano_modelo": str(_d.get("anoModelo", "")),
                "cor":        _d.get("cor", ""),
                "municipio":  _d.get("municipio", ""),
                "uf_veiculo": _d.get("uf", ""),
                "combustivel_fipe": _d.get("combustivel", ""),
                "_fonte": "brasilapi",
            }
        return {}
    except Exception:
        return {}


def _fipe_buscar_valor_auto(
    marca_str: str, modelo_str: str, ano_str: str, tipo: str = "carros"
) -> dict:
    """
    Dado marca/modelo/ano em texto (vindos da BrasilAPI ou outro), tenta
    localizar o registro na Tabela FIPE via parallelum e retorna o valor.
    Usa difflib para fuzzy-match de nomes.
    Retorna dict com codigo_fipe, valor_fipe, combustivel_fipe, mes_referencia
    ou {} se não encontrar.
    """
    from difflib import get_close_matches as _gcm
    if not marca_str or not modelo_str:
        return {}

    # 1 – Marcas
    _marcas_raw = _fipe_marcas(tipo)
    if not _marcas_raw:
        return {}
    _marcas_nome_cod = {m["nome"].upper(): m["codigo"] for m in _marcas_raw}

    # fuzzy match da marca
    _marca_upper = marca_str.upper()
    # tenta match exato primeiro (substring)
    _marca_cod = None
    for _nm, _cod in _marcas_nome_cod.items():
        if _marca_upper in _nm or _nm in _marca_upper:
            _marca_cod = _cod
            break
    if not _marca_cod:
        _matches = _gcm(_marca_upper, list(_marcas_nome_cod.keys()), n=1, cutoff=0.4)
        if _matches:
            _marca_cod = _marcas_nome_cod[_matches[0]]
    if not _marca_cod:
        return {}

    # 2 – Modelos
    _modelos_raw = _fipe_modelos(tipo, _marca_cod)
    if not _modelos_raw:
        return {}
    _modelos_nome_cod = {m["nome"].upper(): m["codigo"] for m in _modelos_raw}

    # fuzzy match do modelo
    _modelo_upper = modelo_str.upper()
    _modelo_cod = None
    # tenta substring
    for _nm, _cod in _modelos_nome_cod.items():
        if _modelo_upper in _nm or _nm in _modelo_upper:
            _modelo_cod = _cod
            break
    if not _modelo_cod:
        # divide o modelo em tokens e tenta achar o melhor
        _tokens = [t for t in _modelo_upper.split() if len(t) >= 3]
        _best_score = 0
        _best_cod = None
        for _nm, _cod in _modelos_nome_cod.items():
            _score = sum(1 for t in _tokens if t in _nm)
            if _score > _best_score:
                _best_score = _score
                _best_cod = _cod
        if _best_score > 0:
            _modelo_cod = _best_cod
    if not _modelo_cod:
        _matches = _gcm(_modelo_upper, list(_modelos_nome_cod.keys()), n=1, cutoff=0.3)
        if _matches:
            _modelo_cod = _modelos_nome_cod[_matches[0]]
    if not _modelo_cod:
        return {}

    # 3 – Anos disponíveis
    _anos_raw = _fipe_anos(tipo, _marca_cod, _modelo_cod)
    if not _anos_raw:
        return {}

    # escolhe o ano mais próximo do informado
    _ano_target = 0
    try:
        _ano_target = int(str(ano_str or "").split("-")[0].strip())
    except Exception:
        pass

    _ano_cod_escolhido = None
    if _ano_target:
        _melhor_diff = 9999
        for _a in _anos_raw:
            try:
                _a_num = int(str(_a["nome"]).split()[0])
                if abs(_a_num - _ano_target) < _melhor_diff:
                    _melhor_diff = abs(_a_num - _ano_target)
                    _ano_cod_escolhido = _a["codigo"]
            except Exception:
                pass
    if not _ano_cod_escolhido and _anos_raw:
        _ano_cod_escolhido = _anos_raw[0]["codigo"]

    # 4 – Valor FIPE para o ano escolhido
    _det = _fipe_valor(tipo, _marca_cod, _modelo_cod, _ano_cod_escolhido)
    if not isinstance(_det, dict) or not _det:
        return {}

    return {
        "codigo_fipe":      _det.get("CodigoFipe", ""),
        "valor_fipe":       _fipe_parse_valor(_det.get("Valor", "")),
        "combustivel_fipe": _det.get("Combustivel", ""),
        "mes_referencia":   _det.get("MesReferencia", ""),
        "_marca_fipe":      _det.get("Marca", ""),
        "_modelo_fipe":     _det.get("Modelo", ""),
        "_ano_fipe":        str(_det.get("AnoModelo", "")),
    }


def _fipe_auto_lookup_placa(placa: str) -> dict:
    """
    Pipeline completo para uma placa:
    1. BrasilAPI → marca/modelo/ano/cor/combustivel (DENATRAN)
    2. parallelum FIPE → valor de mercado (fuzzy match)
    Retorna dict pronto para salvar em frota_veiculos_fipe, ou {} se falhar.
    """
    _base = _brasilapi_placa(placa)
    if not _base.get("marca"):
        return {}

    # Determina tipo de veículo para FIPE (heurística básica)
    _tipo_hint = "carros"
    _comb = (_base.get("combustivel_fipe") or "").upper()
    # motos normalmente têm combustível "GASOLINA" e modelo conhecido
    # caminhões costumam ter "DIESEL"
    if "DIESEL" in _comb:
        _tipo_hint = "caminhoes"

    _fipe_extra = _fipe_buscar_valor_auto(
        _base.get("marca", ""),
        _base.get("modelo", ""),
        _base.get("ano_modelo", ""),
        tipo=_tipo_hint,
    )

    # Merge: base (DENATRAN) + FIPE value
    _resultado = {**_base}
    _resultado.pop("_fonte", None)
    if _fipe_extra:
        _resultado["codigo_fipe"]      = _fipe_extra.get("codigo_fipe", "")
        _resultado["valor_fipe"]       = _fipe_extra.get("valor_fipe")
        _resultado["combustivel_fipe"] = _fipe_extra.get("combustivel_fipe") or _base.get("combustivel_fipe", "")
        _resultado["mes_referencia"]   = _fipe_extra.get("mes_referencia", "")
        # Usa marca/modelo da FIPE quando disponíveis (mais padronizados)
        if _fipe_extra.get("_marca_fipe"):
            _resultado["marca"] = _fipe_extra["_marca_fipe"]
        if _fipe_extra.get("_modelo_fipe"):
            _resultado["modelo"] = _fipe_extra["_modelo_fipe"]
        if _fipe_extra.get("_ano_fipe"):
            _resultado["ano_modelo"] = _fipe_extra["_ano_fipe"]
    else:
        _resultado.setdefault("codigo_fipe", "")
        _resultado.setdefault("valor_fipe", None)
        _resultado.setdefault("mes_referencia", "")
    _resultado.setdefault("tipo_veiculo", "Carro")
    return _resultado


def _fipe_df_enriquecido(df_abast: "pd.DataFrame", cache_fipe: dict) -> "pd.DataFrame":
    """Mescla colunas FIPE no DataFrame de abastecimentos."""
    _COLS = ["_fipe_marca", "_fipe_modelo", "_fipe_ano", "_fipe_cor",
             "_fipe_tipo", "_fipe_valor", "_fipe_comb_ref", "_fipe_mes_ref"]
    if df_abast is None or df_abast.empty or not cache_fipe:
        _df = df_abast.copy() if df_abast is not None else pd.DataFrame()
        for _c in _COLS:
            _df[_c] = None
        return _df

    _df = df_abast.copy()
    _col_placa = next((c for c in ["_placa", "placa"] if c in _df.columns), None)
    if not _col_placa:
        for _c in _COLS:
            _df[_c] = None
        return _df

    def _get(placa, campo, fallback=None):
        _p = _fipe_normalizar_placa(str(placa or ""))
        return (cache_fipe.get(_p) or {}).get(campo, fallback)

    _df["_fipe_marca"]    = _df[_col_placa].apply(lambda p: _get(p, "marca"))
    _df["_fipe_modelo"]   = _df[_col_placa].apply(lambda p: _get(p, "modelo"))
    _df["_fipe_ano"]      = _df[_col_placa].apply(lambda p: _get(p, "ano_modelo"))
    _df["_fipe_cor"]      = _df[_col_placa].apply(lambda p: _get(p, "cor"))
    _df["_fipe_tipo"]     = _df[_col_placa].apply(lambda p: _get(p, "tipo_veiculo"))
    _df["_fipe_valor"]    = _df[_col_placa].apply(lambda p: _get(p, "valor_fipe"))
    _df["_fipe_comb_ref"] = _df[_col_placa].apply(lambda p: _get(p, "combustivel_fipe"))
    _df["_fipe_mes_ref"]  = _df[_col_placa].apply(lambda p: _get(p, "mes_referencia"))
    return _df


def _fipe_secao_ui(
    df_abast: "pd.DataFrame",
    cache_fipe: dict,
    key_prefix: str = "fipe",
) -> None:
    """
    Seção FIPE completa:
      Tab 1 — Visão Geral da frota
      Tab 2 — Busca Automática por placa (BrasilAPI DENATRAN + parallelum FIPE)
      Tab 3 — Associação Manual (fallback para placas que a busca automática não encontrar)
    """
    if df_abast is None or df_abast.empty:
        st.info("Carregue dados de abastecimentos para ver as informações FIPE da frota.")
        return

    _col_placa = next((c for c in ["_placa", "placa"] if c in df_abast.columns), None)
    if not _col_placa:
        st.warning("Coluna de placa não encontrada nos dados.")
        return

    _placas       = sorted(df_abast[_col_placa].dropna().unique().tolist())
    _placas_norm  = [_fipe_normalizar_placa(p) for p in _placas]
    _n_placas     = len(_placas)

    # cache vivo — pode ser atualizado durante a sessão
    _cache_live = st.session_state.get(f"{key_prefix}_cache_fipe", cache_fipe)
    _em_cache   = sum(1 for p in _placas_norm if _cache_live.get(p, {}).get("marca"))
    _sem_cache  = _n_placas - _em_cache

    # ── métricas ──────────────────────────────────────────────────
    _m1, _m2, _m3 = st.columns(3)
    _m1.metric("🚗 Veículos na frota", _n_placas)
    _m2.metric("✅ Com dados FIPE",    _em_cache,
               delta=f"{_sem_cache} sem dados" if _sem_cache else None,
               delta_color="inverse")
    _m3.metric("📊 Cobertura",
               f"{int(_em_cache/_n_placas*100)}%" if _n_placas else "—")

    # ── abas ──────────────────────────────────────────────────────
    _t1, _t2, _t3 = st.tabs(["📋 Visão Geral", "🔍 Busca Automática", "🔗 Associação Manual"])

    # ════════════════════════════════════
    #  TAB 1 — Visão geral
    # ════════════════════════════════════
    with _t1:
        _cache_t1 = st.session_state.get(f"{key_prefix}_cache_fipe", cache_fipe)

        _linhas = []
        for _p in _placas:
            _pn = _fipe_normalizar_placa(_p)
            _d  = _cache_t1.get(_pn) or {}
            _ok = bool(_d.get("marca"))
            _linhas.append({
                "Status":         "✅" if _ok else "⏳",
                "Placa":          _p,
                "Marca":          _d.get("marca")             or "—",
                "Modelo":         _d.get("modelo")            or "—",
                "Ano":            _d.get("ano_modelo")        or "—",
                "Cor":            _d.get("cor")               or "—",
                "Tipo":           _d.get("tipo_veiculo")      or "—",
                "Comb. Ref.":     _d.get("combustivel_fipe")  or "—",
                "Valor FIPE":     _d.get("valor_fipe"),
                "Ref. FIPE":      _d.get("mes_referencia")    or "—",
            })
        _df_vis = pd.DataFrame(_linhas)
        _df_vis["Valor FIPE (R$)"] = _df_vis["Valor FIPE"].apply(
            lambda v: _br_moeda(v, 0) if pd.notna(v) and v else "—"
        )
        st.dataframe(
            _df_vis[["Status","Placa","Marca","Modelo","Ano","Cor",
                     "Tipo","Comb. Ref.","Valor FIPE (R$)","Ref. FIPE"]],
            use_container_width=True, hide_index=True,
        )
        if _sem_cache:
            st.caption(
                "⏳ Placas sem dados → use **🔍 Busca Automática** para preencher tudo de uma vez."
            )

        # KPIs de valor
        _vals = _df_vis["Valor FIPE"].dropna()
        _vals = _vals[_vals > 0]
        if not _vals.empty:
            st.markdown("#### 💰 Valor de Mercado da Frota (FIPE)")
            _k1, _k2, _k3, _k4 = st.columns(4)
            _k1.metric("Total estimado",    _br_moeda(_vals.sum(), 0))
            _k2.metric("Média por veículo", _br_moeda(_vals.mean(), 0))
            _k3.metric("Maior valor",       _br_moeda(_vals.max(), 0))
            _k4.metric("Menor valor",       _br_moeda(_vals.min(), 0))

        # Gráficos
        _df_c = _df_vis[_df_vis["Marca"] != "—"].copy()
        if len(_df_c) >= 2:
            st.markdown("#### 📊 Composição da Frota")
            _gc1, _gc2 = st.columns(2)
            with _gc1:
                _por_marca = _df_c["Marca"].value_counts().head(10)
                _fig_m = go.Figure(go.Bar(
                    x=_por_marca.values, y=_por_marca.index,
                    orientation="h", marker_color="#1040a0",
                    text=_por_marca.values, textposition="outside",
                ))
                _fig_m.update_layout(
                    title="Veículos por Marca", height=320,
                    margin=dict(l=10, r=30, t=40, b=10),
                    yaxis=dict(autorange="reversed"),
                    paper_bgcolor="white", plot_bgcolor="#f9fbff",
                )
                st.plotly_chart(_fig_m, use_container_width=True)
            with _gc2:
                _por_tipo = _df_c["Tipo"].value_counts()
                _fig_t = go.Figure(go.Pie(
                    labels=_por_tipo.index, values=_por_tipo.values,
                    hole=0.4,
                    marker_colors=["#1040a0","#2E7D32","#F57F17",
                                   "#C62828","#6A1B9A","#00838F"],
                ))
                _fig_t.update_layout(
                    title="Tipos de Veículo", height=320,
                    margin=dict(l=10, r=10, t=40, b=10),
                    paper_bgcolor="white",
                )
                st.plotly_chart(_fig_t, use_container_width=True)

    # ════════════════════════════════════
    #  TAB 2 — Busca Automática
    # ════════════════════════════════════
    with _t2:
        _cache_t2    = st.session_state.get(f"{key_prefix}_cache_fipe", cache_fipe)
        _pendentes2  = [p for p in _placas
                        if not _cache_t2.get(_fipe_normalizar_placa(p), {}).get("marca")]
        _total_pend  = len(_pendentes2)

        st.markdown(
            "A busca automática consulta o **DENATRAN** (via BrasilAPI) para obter "
            "marca, modelo, ano, cor e combustível de cada placa. Em seguida, busca "
            "o **valor de mercado** na Tabela FIPE via correspondência automática."
        )

        if not _pendentes2:
            st.success(f"✅ Todos os {_n_placas} veículos já têm dados FIPE.")
        else:
            st.info(f"**{_total_pend} placa(s)** ainda sem dados FIPE.", icon="ℹ️")

        _col_btn1, _col_btn2 = st.columns([2, 1])
        with _col_btn1:
            _btn_auto_all = st.button(
                f"🔍 Buscar automaticamente ({_total_pend} pendentes)" if _pendentes2
                else "🔄 Re-buscar todos os veículos",
                key=f"{key_prefix}_btn_auto_all",
                type="primary",
                use_container_width=True,
                disabled=(_total_pend == 0 and not st.session_state.get(f"{key_prefix}_auto_rebusc")),
            )
        with _col_btn2:
            if st.button("🔄 Re-buscar tudo", key=f"{key_prefix}_btn_auto_rebusc",
                         use_container_width=True):
                st.session_state[f"{key_prefix}_auto_rebusc"] = True
                st.rerun()

        # Pool: pendentes normalmente; todas as placas se "re-buscar" ativado
        _pool_auto = _placas if st.session_state.get(f"{key_prefix}_auto_rebusc") else _pendentes2

        if _btn_auto_all and _pool_auto:
            st.session_state.pop(f"{key_prefix}_auto_rebusc", None)
            _progresso   = st.progress(0, text="Iniciando busca…")
            _log_area    = st.empty()
            _log_lines: list = []
            _cache_novo  = dict(_cache_t2)
            _ok_count    = 0
            _err_count   = 0
            _sem_fipe    = []

            for _i, _placa in enumerate(_pool_auto):
                _pct  = int((_i / len(_pool_auto)) * 100)
                _progresso.progress(_pct, text=f"Buscando {_placa} ({_i+1}/{len(_pool_auto)})…")

                _dados = _fipe_auto_lookup_placa(_placa)
                if _dados.get("marca"):
                    _ok_db, _err_db = _fipe_salvar_registro(_placa, _dados)
                    _pn_novo = _fipe_normalizar_placa(_placa)
                    _cache_novo[_pn_novo] = _dados
                    if _ok_db:
                        _ok_count += 1
                        _val_str  = (
                            _br_moeda(_dados["valor_fipe"], 0)
                            if _dados.get("valor_fipe") else "sem valor FIPE"
                        )
                        _log_lines.append(
                            f"✅ **{_placa}** → {_dados['marca']} {_dados['modelo']} "
                            f"{_dados.get('ano_modelo','')} ({_val_str})"
                        )
                    else:
                        _err_count += 1
                        _log_lines.append(f"⚠️ **{_placa}** → dados encontrados mas erro ao salvar: {_err_db}")
                else:
                    _err_count += 1
                    _sem_fipe.append(_placa)
                    _log_lines.append(
                        f"❌ **{_placa}** → não encontrado (placa pode não estar na base DENATRAN)"
                    )

                _log_area.markdown("\n\n".join(_log_lines[-15:]))  # mostra últimas 15 linhas

            _progresso.progress(100, text="Busca concluída!")
            # Persiste cache atualizado na sessão
            st.session_state[f"{key_prefix}_cache_fipe"] = _cache_novo

            # Resumo final
            st.markdown("---")
            _r1, _r2, _r3 = st.columns(3)
            _r1.metric("✅ Encontrados",  _ok_count)
            _r2.metric("❌ Não encontrados", _err_count)
            _r3.metric("📊 Cobertura nova",
                       f"{int(_ok_count/len(_pool_auto)*100)}%" if _pool_auto else "—")

            if _sem_fipe:
                st.warning(
                    f"As seguintes placas não foram encontradas na base DENATRAN: "
                    f"{', '.join(_sem_fipe)}. "
                    "Use a aba **🔗 Associação Manual** para adicioná-las manualmente.",
                    icon="⚠️",
                )
            st.rerun()

        # Tabela de resultados da busca anterior (log na sessão)
        elif not _btn_auto_all and _pool_auto:
            # Mostra as placas pendentes num preview
            _prev_data = []
            for _p in _pool_auto[:20]:  # limite de 20 para não sobrecarregar
                _prev_data.append({"Placa": _p, "Status": "⏳ Pendente"})
            if _prev_data:
                st.dataframe(pd.DataFrame(_prev_data), use_container_width=True,
                             hide_index=True)
                if len(_pool_auto) > 20:
                    st.caption(f"… e mais {len(_pool_auto)-20} placas.")

    # ════════════════════════════════════
    #  TAB 3 — Associação Manual (formulário de texto direto)
    # ════════════════════════════════════════════════════════
    with _t3:
        _cache_t3   = st.session_state.get(f"{key_prefix}_cache_fipe", cache_fipe)
        _pendentes3 = [p for p in _placas
                       if not _cache_t3.get(_fipe_normalizar_placa(p), {}).get("marca")]

        st.markdown(
            "Preencha os dados do veículo manualmente. "
            "Consulte o valor FIPE em "
            "[veiculos.fipe.org.br](https://veiculos.fipe.org.br) se necessário."
        )

        if not _pendentes3:
            st.success(f"✅ Todos os {_n_placas} veículos já têm dados associados.")
            if st.button("🔄 Editar um veículo", key=f"{key_prefix}_man_editar_btn"):
                st.session_state[f"{key_prefix}_man_mostrar_todos"] = True
                st.rerun()
            _pool3 = _placas if st.session_state.get(f"{key_prefix}_man_mostrar_todos") else []
        else:
            st.info(f"**{len(_pendentes3)} placa(s)** sem dados FIPE.", icon="ℹ️")
            _pool3 = _pendentes3

        if not _pool3:
            return

        # ── Seleção da placa ──────────────────────────────────────
        _placa_sel3 = st.selectbox(
            "Placa",
            _pool3,
            key=f"{key_prefix}_man_placa_sel",
        )
        _pn3 = _fipe_normalizar_placa(_placa_sel3)
        _ex3 = _cache_t3.get(_pn3) or {}   # dados já salvos (para pré-preencher)

        # ── Formulário ────────────────────────────────────────────
        with st.form(key=f"{key_prefix}_man_form_{_placa_sel3}"):
            _c1, _c2 = st.columns(2)
            with _c1:
                _f_marca   = st.text_input("Marca *",
                    value=_ex3.get("marca", ""),
                    placeholder="Ex: Toyota",
                    key=f"{key_prefix}_f_marca")
                _f_modelo  = st.text_input("Modelo *",
                    value=_ex3.get("modelo", ""),
                    placeholder="Ex: Corolla XEi 2.0",
                    key=f"{key_prefix}_f_modelo")
                _f_ano     = st.text_input("Ano do modelo *",
                    value=_ex3.get("ano_modelo", ""),
                    placeholder="Ex: 2022",
                    key=f"{key_prefix}_f_ano")
            with _c2:
                _f_cor     = st.text_input("Cor",
                    value=_ex3.get("cor", ""),
                    placeholder="Ex: Prata",
                    key=f"{key_prefix}_f_cor")
                _f_comb    = st.selectbox(t("Combustível"),
                    ["", "Gasolina", "Flex", "Diesel", "Elétrico", "Híbrido", "GNV"],
                    index=(["", "Gasolina", "Flex", "Diesel", "Elétrico", "Híbrido", "GNV"]
                           .index(_ex3.get("combustivel_fipe", ""))
                           if _ex3.get("combustivel_fipe", "") in
                           ["", "Gasolina", "Flex", "Diesel", "Elétrico", "Híbrido", "GNV"]
                           else 0),
                    key=f"{key_prefix}_f_comb")
                _f_tipo    = st.selectbox("Tipo",
                    ["Carro", "Caminhão", "Moto", "Utilitário", "Ônibus"],
                    index=(["Carro", "Caminhão", "Moto", "Utilitário", "Ônibus"]
                           .index(_ex3.get("tipo_veiculo", "Carro"))
                           if _ex3.get("tipo_veiculo", "Carro") in
                           ["Carro", "Caminhão", "Moto", "Utilitário", "Ônibus"]
                           else 0),
                    key=f"{key_prefix}_f_tipo")

            _f_valor = st.number_input(
                "Valor FIPE (R$) — opcional",
                min_value=0.0, step=500.0, format="%.2f",
                value=float(_ex3.get("valor_fipe") or 0),
                key=f"{key_prefix}_f_valor",
                help="Consulte em veiculos.fipe.org.br e informe o valor de mercado.",
            )
            _f_cod_fipe = st.text_input(
                "Código FIPE — opcional",
                value=_ex3.get("codigo_fipe", ""),
                placeholder="Ex: 005340-2",
                key=f"{key_prefix}_f_cod_fipe",
            )

            _submit3 = st.form_submit_button(
                "✅ Salvar", type="primary", use_container_width=True
            )

        if _submit3:
            if not _f_marca.strip() or not _f_modelo.strip() or not _f_ano.strip():
                st.error("Preencha pelo menos Marca, Modelo e Ano.")
            else:
                _dados3 = {
                    "marca":            _f_marca.strip().title(),
                    "modelo":           _f_modelo.strip(),
                    "ano_modelo":       _f_ano.strip(),
                    "cor":              _f_cor.strip().title(),
                    "tipo_veiculo":     _f_tipo,
                    "municipio":        "",
                    "uf_veiculo":       "",
                    "codigo_fipe":      _f_cod_fipe.strip(),
                    "valor_fipe":       _f_valor if _f_valor > 0 else None,
                    "combustivel_fipe": _f_comb,
                    "mes_referencia":   "",
                }
                _ok3, _err3 = _fipe_salvar_registro(_placa_sel3, _dados3)
                if _ok3:
                    _new_cache3 = dict(_cache_t3)
                    _new_cache3[_pn3] = _dados3
                    st.session_state[f"{key_prefix}_cache_fipe"] = _new_cache3
                    _val_msg = (
                        f" — {_br_moeda(_f_valor, 0)}"
                        if _f_valor > 0 else ""
                    )
                    st.success(
                        f"✅ **{_placa_sel3}** salvo: "
                        f"{_dados3['marca']} {_dados3['modelo']} "
                        f"{_dados3['ano_modelo']}{_val_msg}"
                    )
                    st.session_state.pop(f"{key_prefix}_man_mostrar_todos", None)
                    st.rerun()
                else:
                    st.error(f"Erro ao salvar no Supabase: {_err3}")

    st.caption(
        f"Busca automática via **DENATRAN** (BrasilAPI). "
        f"Valor FIPE: consulte [veiculos.fipe.org.br](https://veiculos.fipe.org.br). "
        f"Cache válido por {_FIPE_CACHE_TTL_DIAS} dias."
    )




def _comparar_cargas_precos(
    df_novo: "pd.DataFrame",
    df_ant:  "pd.DataFrame",
    pf_df:   "pd.DataFrame | None" = None,
) -> "pd.DataFrame":
    """
    Compara duas cargas de preço (_pp_df) e retorna DataFrame de variações.

    Colunas retornadas:
        CNPJ · Nome · UF · Combustível · Preço Ant. · Preço Novo
        · Δ R$ · Δ% · Status (Alta / Queda / Sem Alteração / Novo / Removido)
    """
    _KEY = ["cnpj_norm", "combustivel_pk"]

    # Normaliza colunas mínimas
    def _prep(df):
        if df is None or df.empty:
            return pd.DataFrame(columns=_KEY + ["preco", "combustivel_label"])
        d = df.copy()
        for c in _KEY + ["preco"]:
            if c not in d.columns:
                d[c] = None
        d["preco"] = pd.to_numeric(d["preco"], errors="coerce")
        return d

    _n = _prep(df_novo)
    _a = _prep(df_ant)

    # Agrega por posto × combustível (média se houver duplicatas)
    _n_agg = _n.groupby(_KEY).agg(
        preco_novo=("preco", "mean"),
        combustivel_label=("combustivel_label", "first"),
    ).reset_index()
    _a_agg = _a.groupby(_KEY).agg(
        preco_ant=("preco", "mean"),
    ).reset_index()

    # Merge full outer
    _merged = _n_agg.merge(_a_agg, on=_KEY, how="outer")

    # Enriquecer com nome/UF a partir de pf_df
    _nome_map: dict = {}
    _uf_map:   dict = {}
    if pf_df is not None and not pf_df.empty:
        _cn_col = next((c for c in pf_df.columns
                        if c.lower() in ("cnpj", "cnpj_norm")), None)
        _nm_col = next((c for c in pf_df.columns
                        if c.lower() in ("razaosocial", "razão social", "nome")), None)
        _uf_col = next((c for c in pf_df.columns if c.lower() == "uf"), None)
        if _cn_col and _nm_col:
            # Vetorizado: sem iterrows()
            _cnpj_v = pf_df[_cn_col].astype(str).str.replace(r"\D", "", regex=True)
            _mask_v = _cnpj_v.str.len() > 0
            _nome_map = dict(zip(_cnpj_v[_mask_v], pf_df.loc[_mask_v, _nm_col].astype(str)))
            if _uf_col:
                _uf_map = dict(zip(_cnpj_v[_mask_v], pf_df.loc[_mask_v, _uf_col].astype(str)))

    # Vetorizado: sem iterrows()
    _mg = _merged.copy()
    _mg["_cnpj_v"]    = _mg["cnpj_norm"].astype(str)
    _mg["_comb_v"]    = _mg.get("combustivel_label", _mg["combustivel_pk"]).fillna("").astype(str)
    _mg["_pant_v"]    = pd.to_numeric(_mg.get("preco_ant"),  errors="coerce")
    _mg["_pnov_v"]    = pd.to_numeric(_mg.get("preco_novo"), errors="coerce")
    _mg["_pant_ok_v"] = _mg["_pant_v"].notna() & (_mg["_pant_v"] > 0)
    rows = []
    for _, r in _mg.iterrows():
        _cnpj   = r["_cnpj_v"]
        _comb   = r["_comb_v"]
        _pant   = r["_pant_v"]
        _pnov   = r["_pnov_v"]
        _pant_ok = r["_pant_ok_v"]
        _pnov_ok = pd.notna(_pnov) and _pnov > 0

        if _pnov_ok and not _pant_ok:
            _status = "🆕 Novo"
            _delta_r = None
            _delta_p = None
        elif _pant_ok and not _pnov_ok:
            _status = "🗑️ Removido"
            _delta_r = None
            _delta_p = None
        else:
            _d = round(float(_pnov) - float(_pant), 4)
            _dp = round(_d / float(_pant) * 100, 2) if _pant else 0
            if _d > 0.001:
                _status = "🔺 Alta"
            elif _d < -0.001:
                _status = "🔻 Queda"
            else:
                _status = "➡️ Sem alteração"
            _delta_r = _d
            _delta_p = _dp

        # Formatar CNPJ
        _cn14 = _cnpj.zfill(14)
        _cnpj_fmt = (
            f"{_cn14[:2]}.{_cn14[2:5]}.{_cn14[5:8]}/{_cn14[8:12]}-{_cn14[12:14]}"
            if len(_cn14) == 14 else _cnpj
        )

        rows.append({
            "CNPJ":          _cnpj_fmt,
            "Nome":          _nome_map.get(_cnpj, "—"),
            "UF":            _uf_map.get(_cnpj, "—"),
            "Combustível":   _comb,
            "Preço Ant.":    round(float(_pant), 4) if _pant_ok else None,
            "Preço Novo":    round(float(_pnov), 4) if _pnov_ok else None,
            "Δ R$":          round(_delta_r, 4) if _delta_r is not None else None,
            "Δ%":            round(_delta_p, 2) if _delta_p is not None else None,
            "Status":        _status,
        })

    df_out = pd.DataFrame(rows)
    if df_out.empty:
        return df_out

    # Ordenar: Alta primeiro (maior Δ absoluto), depois Queda, Novo, Removido, Sem alteração
    _ord = {"🔺 Alta": 0, "🔻 Queda": 1, "🆕 Novo": 2, "🗑️ Removido": 3, "➡️ Sem alteração": 4}
    df_out["_ord"] = df_out["Status"].map(_ord).fillna(5)
    df_out["_abs"] = df_out["Δ R$"].abs().fillna(0)
    df_out = (df_out
              .sort_values(["_ord", "_abs"], ascending=[True, False])
              .drop(columns=["_ord", "_abs"])
              .reset_index(drop=True))
    return df_out


def _hist_get_posto(cnpj: str, combustivel: str = None) -> list:
    """Retorna histórico de preços de um posto (lista de dicts)."""
    _cnpj_n   = re.sub(r"\D", "", str(cnpj or ""))
    intel     = _intel_load()
    registros = intel.get("historico", {}).get(_cnpj_n, [])
    if combustivel:
        _ck = combustivel.upper()
        registros = [r for r in registros if r.get("combustivel", "").upper() == _ck]
    return sorted(registros, key=lambda r: r.get("data", ""))


def _hist_chart_posto(cnpj: str, nome: str, combustivel: str = None):
    """Retorna figura Plotly com evolução de preço de um posto."""
    import plotly.graph_objects as _pgo
    from collections import defaultdict as _dd
    registros = _hist_get_posto(cnpj, combustivel)
    if not registros:
        return None

    _CORES_COMB = {
        "GASOLINA COMUM":      "#EF5350",
        "GASOLINA ADITIVADA":  "#FF7043",
        "ETANOL HIDRATADO":    "#66BB6A",
        "ETANOL COMUM":        "#81C784",
        "DIESEL S10":          "#42A5F5",
        "DIESEL S500":         "#1E88E5",
        "DIESEL S-500 COMUM":  "#1565C0",
        "DIESEL S-500 ADITIVADO": "#0D47A1",
        "GNV":                 "#AB47BC",
        "GLP":                 "#FFA726",
    }
    por_comb: dict = _dd(list)
    for r in registros:
        por_comb[r.get("combustivel", "Combustível")].append(
            (r["data"], r["preco"])
        )

    fig = _pgo.Figure()
    for comb, pts in sorted(por_comb.items()):
        pts_s  = sorted(pts, key=lambda x: x[0])
        # Converte "YYYY-MM-DD" → "DD/MM/YYYY" para exibir no eixo X como categoria
        datas  = []
        for _d in [p[0] for p in pts_s]:
            try:
                _parts = str(_d).split("-")
                datas.append(f"{_parts[2]}/{_parts[1]}/{_parts[0]}" if len(_parts) == 3 else str(_d))
            except Exception:
                datas.append(str(_d))
        precos = [p[1] for p in pts_s]
        fig.add_trace(_pgo.Scatter(
            x=datas, y=precos,
            mode="lines+markers" if len(precos) > 1 else "markers",
            name=comb,
            line=dict(color=_CORES_COMB.get(comb, "#90CAF9"), width=2.5),
            marker=dict(size=8, line=dict(width=1.5, color="white")),
            hovertemplate=(
                "<b>%{x}</b><br>"
                f"<span style='color:{_CORES_COMB.get(comb,'#90CAF9')}'>{comb}</span><br>"
                "R$ <b>%{y:.3f}</b>/L<extra></extra>"
            ),
        ))

    fig.update_layout(
        # Sem title interno — será renderizado via st.markdown antes do gráfico
        xaxis_title=None,
        yaxis_title="R$/L",
        legend=dict(
            orientation="h",
            yanchor="top", y=-0.18,       # legenda abaixo do gráfico
            xanchor="center", x=0.5,
            font=dict(size=11),
            bgcolor="rgba(255,255,255,0.85)",
            bordercolor="rgba(0,0,0,0.08)",
            borderwidth=1,
        ),
        plot_bgcolor="rgba(0,0,0,0)",
        paper_bgcolor="rgba(0,0,0,0)",
        margin=dict(t=16, b=110, l=55, r=16),   # margem inferior para a legenda
        height=360,
        hovermode="x unified",
        xaxis=dict(
            type="category",                     # trata datas como texto — sem timezone
            gridcolor="rgba(0,0,0,0.07)",
            tickangle=-35,
            tickfont=dict(size=11),
            title=dict(text="Data", font=dict(size=12)),
        ),
        yaxis=dict(
            gridcolor="rgba(0,0,0,0.07)",
            tickprefix="R$ ",
            tickformat=".3f",
            tickfont=dict(size=11),
        ),
    )
    return fig


# ── Score de posto ──────────────────────────────────────────────────

_SCORE_ICONES = {"A": "🟢", "B": "🔵", "C": "🟡", "D": "🔴"}
_SCORE_CORES  = {
    "A": ("#e8f5e9", "#2e7d32", "#a5d6a7"),
    "B": ("#e3f2fd", "#1565c0", "#90caf9"),
    "C": ("#fff8e1", "#f57f17", "#ffe082"),
    "D": ("#ffebee", "#c62828", "#ef9a9a"),
}


def _calcular_score_posto(
    row:                  dict,
    preco_ref_anp:        float = None,
    lat_ref:              float = None,
    lon_ref:              float = None,
    servicos_keys:        list  = None,
    n_servicos_max:       int   = 10,
) -> dict:
    """
    Score composto 0-100 para um posto.
    Pesos: preço vs ANP 50% · serviços 30% · distância 20%.
    Graus: A≥75 · B≥55 · C≥35 · D<35
    """
    # ── Preço (50%) ─────────────────────────────────────────────────
    _s_preco = 50.0
    _det_preco = "Sem referência ANP"
    if preco_ref_anp and preco_ref_anp > 0:
        _p = pd.to_numeric(
            row.get("_preco_posto") or row.get("preco") or row.get("_preco"),
            errors="coerce")
        if pd.notna(_p) and _p > 0:
            _diff = (_p - preco_ref_anp) / preco_ref_anp
            _s_preco = max(0.0, min(100.0, 50.0 - _diff * 500.0))
            _det_preco = f"{_diff:+.1%} vs ANP ({preco_ref_anp:.3f})"

    # ── Serviços (30%) ──────────────────────────────────────────────
    _s_svc = 0.0
    _det_svc = "Sem dados de serviços"
    if servicos_keys and n_servicos_max > 0:
        _n = sum(1 for s in servicos_keys if row.get(s))
        _s_svc = min(100.0, _n / n_servicos_max * 100.0)
        _det_svc = f"{_n}/{n_servicos_max} serviços"

    # ── Distância (20%) ─────────────────────────────────────────────
    _s_dist = 50.0
    _det_dist = "Sem ponto de referência"
    if lat_ref is not None and lon_ref is not None:
        _lat = pd.to_numeric(row.get("_lat") or row.get("lat"), errors="coerce")
        _lon = pd.to_numeric(row.get("_lon") or row.get("lon"), errors="coerce")
        if pd.notna(_lat) and pd.notna(_lon):
            _dlat = _math_mod.radians(_lat - lat_ref)
            _dlon = _math_mod.radians(_lon - lon_ref)
            _a    = (_math_mod.sin(_dlat/2)**2 +
                     _math_mod.cos(_math_mod.radians(lat_ref)) *
                     _math_mod.cos(_math_mod.radians(_lat)) *
                     _math_mod.sin(_dlon/2)**2)
            _d_km = 6371 * 2 * _math_mod.atan2(
                _math_mod.sqrt(_a), _math_mod.sqrt(1 - _a))
            _s_dist   = max(0.0, min(100.0, 100.0 - _d_km))
            _det_dist = f"{_d_km:.1f} km do ponto de busca"

    _score = 0.50 * _s_preco + 0.30 * _s_svc + 0.20 * _s_dist
    _grade = ("A" if _score >= 75 else
              "B" if _score >= 55 else
              "C" if _score >= 35 else "D")
    return {
        "score":           round(_score, 1),
        "grade":           _grade,
        "score_preco":     round(_s_preco, 1),
        "score_servicos":  round(_s_svc,   1),
        "score_distancia": round(_s_dist,  1),
        "detalhe_preco":   _det_preco,
        "detalhe_svc":     _det_svc,
        "detalhe_dist":    _det_dist,
    }


def _score_badge_html(score: float, grade: str, tooltip: str = "",
                      size: str = "normal") -> str:
    """Badge colorido com score e grau (HTML)."""
    bg, txt, brd = _SCORE_CORES.get(grade, ("#f5f5f5", "#424242", "#e0e0e0"))
    _ic   = _SCORE_ICONES.get(grade, "⚪")
    _font = "13px" if size == "normal" else "11px"
    _pad  = "4px 10px" if size == "normal" else "2px 7px"
    _tt   = f" title='{tooltip}'" if tooltip else ""
    return (
        f"<span{_tt} style='display:inline-flex;align-items:center;gap:5px;"
        f"background:{bg};border:1px solid {brd};border-radius:20px;"
        f"padding:{_pad};font-size:{_font};font-weight:700;color:{txt};cursor:default'>"
        f"{_ic} Score {score:.0f}"
        f"<span style='opacity:.65;font-weight:600'>({grade})</span>"
        f"</span>"
    )


def _calcular_score_df(
    df: "pd.DataFrame",
    preco_ref_anp: float = None,
    lat_ref: float = None,
    lon_ref: float = None,
) -> "pd.DataFrame":
    """
    Adiciona coluna '⭐ Score' ao DataFrame de postos.
    Retorna df com a coluna inserida na posição 0.
    """
    if df is None or df.empty:
        return df
    _svc_keys = list(st.session_state.get("_servicos_pf_labels", {}).keys())
    _n_max    = max(len(_svc_keys), 1)
    # Usa to_dict('records') para evitar overhead do iterrows()
    _scores   = []
    for row in df.to_dict("records"):
        _res = _calcular_score_posto(
            row,
            preco_ref_anp=preco_ref_anp,
            lat_ref=lat_ref,
            lon_ref=lon_ref,
            servicos_keys=_svc_keys,
            n_servicos_max=_n_max,
        )
        _scores.append(f"{_res['grade']} {_res['score']:.0f}")
    _df = df.copy()
    _df.insert(0, "⭐ Score", _scores)
    return _df


# ── Otimização de Abastecimento v3 ─────────────────────────────────

def _otimizar_rota_v3(
    ests: list,
    rcap: float,
    raut: float,
    rd: float,
    pesos: dict,
    fill_mode: str = "normal",
    max_paradas: int = 30,
) -> list:
    """
    Motor de otimização de abastecimento com métrica composta.

    Parâmetros
    ----------
    ests       : candidatos ao longo da rota — cada dict deve ter:
                 _km (km na rota), preco, _dev (desvio em km),
                 grade (A/B/C/D, opcional), cnpj, label, ...
    rcap       : capacidade do tanque (L)
    raut       : autonomia (km/L)
    rd         : distância total da rota (km)
    pesos      : dict {"preco": float, "score": float, "desvio": float}
                 (devem somar 1.0)
    fill_mode  : "normal" → enche ao máximo quando vantajoso
                 "minimo" → abastece o mínimo necessário em cada parada
    max_paradas: limite de iterações de segurança

    Retorna
    -------
    Lista de dicts de parada, cada um com todos os campos do candidato
    mais: litros_sugeridos, custo_abast, fuel_chegada, pct_chegada,
          fuel_apos, pct_apos, motivo, metrica_valor
    """
    if not ests or raut <= 0 or rcap <= 0:
        return []

    rmin         = rcap * 0.25          # nível mínimo (25 %)
    alc_efetivo  = (rcap - rmin) * raut # alcance por ciclo (km)
    PCT_BAIXO    = 0.65                 # % tanque — abaixo disso considera parar
    VANT_PRECO   = 0.03                 # vantagem mínima de preço para look-ahead
    LITROS_MIN   = 5                    # descarta paradas com < 5 L

    # ── normalização de preço e score ──────────────────────────────
    _precos = [e["preco"] for e in ests if "preco" in e]
    _pmin   = min(_precos) if _precos else 0.0
    _pmax   = max(_precos) if _precos else 1.0
    _GRADE  = {"A": 1.0, "B": 0.75, "C": 0.5, "D": 0.25}

    def _met(e: dict) -> float:
        """Métrica composta: maior = melhor posto para parar."""
        _p = 1.0 - (e["preco"] - _pmin) / max(_pmax - _pmin, 0.01)
        _g = _GRADE.get(e.get("grade"), 0.25)
        _d = 1.0 - min(e.get("_dev", 0.0) / 5.0, 1.0)
        return pesos["preco"] * _p + pesos["score"] * _g + pesos["desvio"] * _d

    # ── algoritmo greedy look-ahead ─────────────────────────────────
    paradas: list = []
    pos:   float  = 0.0
    fuel:  float  = float(rcap)
    seen: set     = set()
    ult_preco     = None

    for _ in range(max_paradas):
        if pos >= rd:
            break

        can_go = (fuel - rmin) * raut
        must   = pos + can_go

        if must >= rd:
            break  # chega ao destino sem parar

        janela = [e for e in ests
                  if pos < e["_km"] <= must and e["cnpj"] not in seen]

        janela_ext = [e for e in ests
                      if must < e["_km"] <= pos + alc_efetivo * 1.85
                      and e["cnpj"] not in seen]

        if not janela:
            alem = [e for e in ests if e["_km"] > pos and e["cnpj"] not in seen]
            if not alem:
                break
            best  = dict(min(alem, key=lambda x: x["_km"]))
            best["motivo"] = "emergencia"
            fill_tgt_km    = None
        else:
            best_obrig  = max(janela, key=_met)
            fill_tgt_km = None

            if janela_ext:
                best_ext = max(janela_ext, key=_met)
                # look-ahead: se o posto à frente tem métrica bem melhor E preço menor
                if (_met(best_ext) > _met(best_obrig) * 1.05
                        and best_ext.get("preco", 9999) < best_obrig.get("preco", 9999) * (1 - VANT_PRECO)):
                    fill_tgt_km = best_ext["_km"]

            best = dict(best_obrig)
            best["motivo"] = "estrategico" if fill_tgt_km else "otimizado"

        km_ate       = best["_km"] - pos
        fuel_chegada = max(0.0, fuel - km_ate / raut)
        pct_chegada  = fuel_chegada / rcap * 100

        # pula se tanque ainda alto e posto não compensa
        if (best.get("motivo") != "emergencia"
                and pct_chegada >= PCT_BAIXO * 100
                and ult_preco is not None
                and best.get("preco", 9999) >= ult_preco * (1 - VANT_PRECO)
                and not fill_tgt_km):
            pos  = best["_km"]
            fuel = fuel_chegada
            seen.add(best["cnpj"])
            continue

        dist_rest = rd - best["_km"]

        if fill_mode == "minimo":
            # Abastece o mínimo para chegar ao próximo posto obrigatório
            prox_obrig = [e for e in ests
                          if e["_km"] > best["_km"] and e["cnpj"] not in seen]
            if prox_obrig:
                _prox_km = min(prox_obrig, key=lambda x: x["_km"])["_km"]
                _dist_prox = _prox_km - best["_km"]
                litros_nec = (_dist_prox / raut) * 1.10 + rmin - fuel_chegada
            else:
                litros_nec = (dist_rest / raut) * 1.15 + rmin - fuel_chegada
        elif fill_tgt_km:
            dist_tgt   = fill_tgt_km - best["_km"]
            litros_nec = (dist_tgt / raut) * 1.10 + rmin - fuel_chegada
        elif dist_rest <= alc_efetivo:
            litros_nec = (dist_rest / raut) * 1.15 + rmin - fuel_chegada
        else:
            litros_nec = rcap - fuel_chegada

        litros_fill = max(0.0, litros_nec)
        litros_fill = min(litros_fill, rcap - fuel_chegada)
        litros_fill = math.ceil(litros_fill)

        if litros_fill < LITROS_MIN:
            pos  = best["_km"]
            fuel = fuel_chegada
            seen.add(best["cnpj"])
            continue

        fuel_apos = min(fuel_chegada + litros_fill, rcap)
        pct_apos  = fuel_apos / rcap * 100
        custo_ab  = round(litros_fill * best.get("preco", 0.0), 2)

        best.update({
            "fuel_chegada":     round(fuel_chegada, 1),
            "pct_chegada":      round(pct_chegada,  1),
            "litros_sugeridos": int(litros_fill),
            "custo_abast":      custo_ab,
            "fuel_apos":        round(fuel_apos, 1),
            "pct_apos":         round(pct_apos,  1),
            "metrica_valor":    round(_met(best), 3),
        })

        seen.add(best["cnpj"])
        paradas.append(best)
        ult_preco = best.get("preco")
        fuel      = fuel_apos
        pos       = best["_km"]

    return paradas


# ── Relatório semanal de alertas ────────────────────────────────────

def _gerar_relatorio_alertas_xlsx(
    df_pp:  "pd.DataFrame",
    limiar: dict,
    semana: str = None,
) -> tuple:
    """
    Gera relatório Excel de postos em alerta de preço.

    df_pp:  DataFrame de preços dos postos GF.
    limiar: {combustivel_norm: preco_max_float}.
    semana: label de referência (ex: "2024-W05").

    Retorna (bytes_xlsx, filename, error_msg).
    """
    if df_pp is None or df_pp.empty:
        return None, None, "Nenhuma planilha de preços carregada."
    if not limiar:
        return None, None, "Defina ao menos um limiar de preço."

    try:
        import io as _io
        import openpyxl as _opxl
        from openpyxl.styles import (PatternFill, Font, Alignment,
                                     Border, Side, numbers)
        from openpyxl.utils import get_column_letter

        # ── Enriquece df_pp com dados cadastrais do pf_coords_df ──────
        _pf = st.session_state.get("pf_coords_df", pd.DataFrame())
        if not _pf.empty and "cnpj_norm" in _pf.columns:
            _info_cols = [c for c in ["cnpj_norm","razaoSocial","municipio","uf","distribuidora"]
                          if c in _pf.columns]
            _pf_info = _pf[_info_cols].drop_duplicates("cnpj_norm")
            # df_pp usa cnpj_norm; garante coluna antes do merge
            _key = "cnpj_norm" if "cnpj_norm" in df_pp.columns else None
            if _key:
                df_pp = df_pp.merge(_pf_info, on="cnpj_norm", how="left")

        _data_rel = semana or datetime.now().strftime("%Y-W%V")
        _wb  = _opxl.Workbook()
        _ws  = _wb.active
        _ws.title = "Alertas de Preço"

        # ── Cabeçalho do relatório ──────────────────────────────────
        _titulo_fill = PatternFill("solid", fgColor="0D47A1")
        _titulo_font = Font(bold=True, color="FFFFFF", size=13)
        _ws.merge_cells("A1:H1")
        _ws["A1"] = f"Relatório de Alertas de Preço — {_data_rel}"
        _ws["A1"].fill = _titulo_fill
        _ws["A1"].font = _titulo_font
        _ws["A1"].alignment = Alignment(horizontal="center", vertical="center")
        _ws.row_dimensions[1].height = 26

        _ws.merge_cells("A2:H2")
        _ws["A2"] = f"Gerado em {datetime.now().strftime('%d/%m/%Y %H:%M')} · Gestão de Frotas"
        _ws["A2"].font = Font(italic=True, color="666666", size=10)
        _ws["A2"].alignment = Alignment(horizontal="center")

        _row = 4
        _alert_total = 0

        # ── Para cada combustível com limiar ────────────────────────
        for _comb_key, _lim in limiar.items():
            if _lim <= 0:
                continue

            # Detecta coluna de preço no df_pp
            _col_preco = None
            for _c in df_pp.columns:
                _cn = re.sub(r"[^a-z]", "", _c.lower())
                if _cn in _comb_key.lower().replace(" ", "") or \
                   _comb_key.lower().replace(" ", "") in _cn:
                    _col_preco = _c
                    break
            if _col_preco is None:
                # fallback: primeira coluna numérica
                for _c in df_pp.columns:
                    if pd.api.types.is_numeric_dtype(df_pp[_c]):
                        _col_preco = _c
                        break
            if _col_preco is None:
                continue

            _df_c = df_pp.copy()
            _df_c["_preco_num"] = pd.to_numeric(_df_c[_col_preco], errors="coerce")
            _df_alert = _df_c[
                _df_c["_preco_num"].notna() &
                (_df_c["_preco_num"] > _lim)
            ].sort_values("_preco_num", ascending=False)
            if _df_alert.empty:
                continue

            _alert_total += len(_df_alert)

            # Título do combustível
            _ws.merge_cells(f"A{_row}:H{_row}")
            _ws[f"A{_row}"] = f"⚠️ {_comb_key.title()} — Limiar: R$ {_lim:.3f}/L · {len(_df_alert)} postos em alerta"
            _ws[f"A{_row}"].fill = PatternFill("solid", fgColor="FFF9C4")
            _ws[f"A{_row}"].font = Font(bold=True, color="F57F17", size=11)
            _ws[f"A{_row}"].alignment = Alignment(horizontal="left", indent=1)
            _row += 1

            # Cabeçalho da tabela
            _hdrs = ["CNPJ","Razão Social","Município","UF",
                     f"Preço ({_comb_key.title()})","Desvio vs Limiar","% Acima","Bandeira"]
            _hdr_fill = PatternFill("solid", fgColor="E3F2FD")
            _hdr_font = Font(bold=True, color="1565C0", size=10)
            for _ci, _h in enumerate(_hdrs, 1):
                _cell = _ws.cell(row=_row, column=_ci, value=_h)
                _cell.fill = _hdr_fill
                _cell.font = _hdr_font
                _cell.alignment = Alignment(horizontal="center")
                _cell.border = Border(
                    bottom=Side(style="thin", color="90CAF9"),
                    top=Side(style="thin", color="90CAF9"),
                )
            _row += 1

            # Linhas de dados
            _alt_fill_r = PatternFill("solid", fgColor="FFEBEE")
            _alt_fill_w = PatternFill("solid", fgColor="FFFFFF")
            for _ri, (_, _ar) in enumerate(_df_alert.iterrows()):
                _preco_p  = _ar["_preco_num"]
                _desvio   = _preco_p - _lim
                _pct      = _desvio / _lim * 100 if _lim else 0
                _fill     = _alt_fill_r if _ri % 2 == 0 else _alt_fill_w

                _cnpj_raw = _ar.get("cnpj_norm", _ar.get("cnpj", _ar.get("_cnpj_norm", "")))
                # Formata CNPJ: 00.000.000/0000-00
                try:
                    _d = re.sub(r"\D", "", str(_cnpj_raw))
                    _cnpj_c = f"{_d[:2]}.{_d[2:5]}.{_d[5:8]}/{_d[8:12]}-{_d[12:14]}" if len(_d)==14 else _cnpj_raw
                except Exception:
                    _cnpj_c = _cnpj_raw
                _nome_c   = _ar.get("razaoSocial", _ar.get("nome", _ar.get("nomeFantasia", "")))
                _mun_c    = _ar.get("municipio", "")
                _uf_c     = _ar.get("uf", "")
                _band_c   = _ar.get("distribuidora", "")

                _vals = [
                    _cnpj_c, _nome_c, _mun_c, _uf_c,
                    _preco_p, _desvio, _pct / 100, _band_c,
                ]
                for _ci, _v in enumerate(_vals, 1):
                    _cell = _ws.cell(row=_row, column=_ci, value=_v)
                    _cell.fill = _fill
                    _cell.font = Font(size=9)
                    if _ci == 5:  # preço
                        _cell.number_format = 'R$ #,##0.000'
                        _cell.font = Font(size=9, bold=True,
                                          color=("C62828" if _preco_p > _lim * 1.1 else "E65100"))
                    elif _ci == 6:
                        _cell.number_format = 'R$ #,##0.000'
                    elif _ci == 7:
                        _cell.number_format = '0.0%'
                _row += 1
            _row += 2  # espaço entre combustíveis

        if _alert_total == 0:
            _ws[f"A{_row}"] = "✅ Nenhum posto acima do limiar configurado."
            _ws[f"A{_row}"].font = Font(color="2E7D32", italic=True, size=10)
            _row += 1

        # Resumo final
        _row += 1
        _ws.merge_cells(f"A{_row}:H{_row}")
        _ws[f"A{_row}"] = f"Total de postos em alerta: {_alert_total}"
        _ws[f"A{_row}"].font = Font(bold=True, size=11,
                                     color=("C62828" if _alert_total > 0 else "2E7D32"))

        # Ajusta largura das colunas
        _larguras = [18, 40, 22, 5, 12, 12, 8, 18]
        for _ci, _larg in enumerate(_larguras, 1):
            _ws.column_dimensions[get_column_letter(_ci)].width = _larg

        _buf = _io.BytesIO()
        _wb.save(_buf)
        _buf.seek(0)
        _fname = f"alertas_preco_{datetime.now().strftime('%Y%m%d_%H%M')}.xlsx"

        # Atualiza data do último relatório
        _intel = _intel_load()
        _intel["last_report"] = datetime.now().isoformat()
        _intel_save(_intel)

        return _buf.getvalue(), _fname, None

    except Exception as _ex:
        return None, None, str(_ex)


