@st.cache_data(show_spinner=False, ttl=3600)
def _github_baixar_bytes(nome_arquivo: str) -> "tuple[bytes | None, str]":
    """
    Baixa um arquivo da subpasta estudo-de-rede no GitHub.
    Cache servidor: 1 download por hora por arquivo.
    Retry 3x com timeout progressivo para arquivos grandes.
    Retorna (bytes, erro_str); bytes=None em caso de falha.
    """
    import urllib.parse as _uparse
    _url = f"{_REPO_BASE_URL}/{_uparse.quote(nome_arquivo)}"
    _timeouts = [30, 60, 120]  # timeout progressivo por tentativa
    _ultimo_erro = ""
    for _tentativa, _timeout in enumerate(_timeouts, 1):
        try:
            _resp = requests.get(
                _url,
                timeout=_timeout,
                stream=False,
                headers={"Accept": "application/octet-stream"}
            )
            if _resp.status_code == 200:
                return _resp.content, ""
            _ultimo_erro = f"HTTP {_resp.status_code}"
        except Exception as _e:
            _ultimo_erro = str(_e)
            if _tentativa < len(_timeouts):
                import time as _t; _t.sleep(2 * _tentativa)
    # Fallback: tenta arquivo local se download do GitHub falhou
    _local_path = os.path.join(_DIR, nome_arquivo)
    if os.path.exists(_local_path):
        try:
            with open(_local_path, "rb") as _f_local:
                return _f_local.read(), ""
        except Exception as _e_local:
            return None, f"Erro ao baixar {nome_arquivo}: {_ultimo_erro} | local: {_e_local}"
    return None, f"Erro ao baixar {nome_arquivo}: {_ultimo_erro}"


def _doc_pdf_hash() -> str:
    """Retorna hash MD5 do PDF de documentação (para invalidar cache quando o arquivo muda)."""
    import hashlib as _hl
    for _nome in _DOC_PDF_CANDIDATOS:
        _p = os.path.join(_DIR, _nome)
        if os.path.exists(_p):
            try:
                with open(_p, "rb") as _f:
                    return _hl.md5(_f.read()).hexdigest()
            except Exception:
                pass
    return "no_file"


@st.cache_data(show_spinner=False)   # cache invalidado pelo hash do arquivo
def _carregar_doc_pdf(_cache_key: str = ""):
    """
    Carrega o PDF de documentação do repositório.
    Tenta vários nomes possíveis para o arquivo.
    Retorna (bytes, nome_arquivo) ou (None, None) se não encontrado.
    O parâmetro _cache_key (hash MD5) garante que o cache é invalidado
    sempre que o arquivo PDF é substituído por uma versão nova.
    """
    for _nome in _DOC_PDF_CANDIDATOS:
        _caminho_doc = os.path.join(_DIR, _nome)
        if os.path.exists(_caminho_doc):
            try:
                with open(_caminho_doc, "rb") as _f:
                    return _f.read(), _nome
            except Exception:
                continue
    return None, None


def normalizar_cnpj(valor):
    if pd.isna(valor):
        return ""
    return "".join(c for c in str(valor) if c.isdigit())


def detectar_coluna_cnpj(df: pd.DataFrame):
    for col in df.columns:
        if "cnpj" in col.lower():
            return col
    for col in df.columns:
        amostra = df[col].dropna().astype(str).head(5)
        if amostra.apply(lambda x: len("".join(c for c in x if c.isdigit())) >= 14).any():
            return col
    return None


def _detectar_col(df: pd.DataFrame, termos: list) -> str | None:
    """Retorna o nome da coluna que melhor bate com os termos.

    Estratégia em 2 passos:
      1. Match EXATO por ordem de termos (prioridade): varre todos os termos em
         sequência e, para cada um, percorre as colunas buscando correspondência
         exata. Isso garante que, p.ex., 'BANDEIRA' seja encontrado antes que
         'REDE' (substring de 'CREDENCIADO') cause uma falsa detecção.
      2. Match SUBSTRING por ordem de colunas (fallback): mantém comportamento
         original para planilhas com nomes de coluna compostos.
    """
    # 1ª passagem — match exato, prioridade determinada pela ordem dos termos
    for _t in termos:
        for _c in df.columns:
            if _anp_norm(_c) == _t:
                return _c
    # 2ª passagem — substring como fallback
    for _c in df.columns:
        _cn = _anp_norm(_c)
        if any(t in _cn for t in termos):
            return _c
    return None


