# ═══════════════════════════════════════════════════════════════════
#  MANUTENÇÃO PREDITIVA — Persistência Supabase
# ═══════════════════════════════════════════════════════════════════

def _manut_salvar(cnpj_frota: str, placa: str, data: str,
                  hodometro: int | None, tecnico: str, oficina: str,
                  custo: float | None, itens: list[str],
                  obs: str, criado_por: str = "") -> tuple[bool, str]:
    """Salva um registro de manutenção no Supabase."""
    _db = _db_client()
    if not _db:
        return False, "Supabase não disponível."
    try:
        payload = {
            "cnpj_frota":       __import__("re").sub(r"\D","",str(cnpj_frota)).strip(),
            "placa":            placa.upper().strip(),
            "data_manutencao":  data,
            "hodometro":        hodometro,
            "tecnico":          tecnico.strip() or None,
            "oficina":          oficina.strip() or None,
            "custo_total":      custo,
            "itens_realizados": itens,
            "obs_gerais":       obs.strip() or None,
            "criado_por":       criado_por,
        }
        _db.table("manutencoes_realizadas").insert(payload).execute()
        return True, "Manutenção registrada com sucesso."
    except Exception as e:
        return False, str(e)


def _manut_listar(cnpj_frota: str | None = None,
                  placa: str | None = None,
                  limit: int = 500) -> list:
    """Carrega histórico de manutenções do Supabase."""
    _db = _db_client()
    if not _db:
        return []
    try:
        q = (_db.table("manutencoes_realizadas")
             .select("*")
             .order("data_manutencao", desc=True)
             .limit(limit))
        if cnpj_frota:
            import re as _re_ml
            _cnpj_ml = _re_ml.sub(r"\D", "", str(cnpj_frota))
            q = q.eq("cnpj_frota", _cnpj_ml)
        if placa:
            q = q.eq("placa", placa.upper().strip())
        r = q.execute()
        return r.data or []
    except Exception:
        return []


def _manut_ultima_por_tipo(placa: str, tipo: str,
                            historico: list) -> dict | None:
    """Retorna o registro mais recente de manutenção para placa+tipo."""
    matches = [
        r for r in historico
        if r.get("placa","").upper() == placa.upper()
        and tipo in (r.get("itens_realizados") or [])
        and r.get("hodometro")
    ]
    if not matches:
        return None
    return max(matches, key=lambda r: r.get("hodometro", 0))


def _manut_excluir(id_reg: int) -> tuple[bool, str]:
    """Remove um registro de manutenção."""
    _db = _db_client()
    if not _db:
        return False, "Supabase não disponível."
    try:
        _db.table("manutencoes_realizadas").delete().eq("id", id_reg).execute()
        return True, "Registro excluído."
    except Exception as e:
        return False, str(e)


def _precos_tooltip_html(cnpj_norm: str, uf: str, municipio: str = "") -> str:
    """Retorna bloco HTML com preços de combustíveis para o tooltip do mapa.

    Hierarquia ANP:
      1. Preços do estabelecimento (abastecimentos do cliente)
      2. Preços do município (ANP — aba MUNICIPIOS)
      3. Preços do estado (ANP — aba ESTADOS)
      4. Preços do Brasil (ANP — aba BRASIL)
    Retorna "" se não houver dados.
    """
    try:
        linhas = []
        fonte = ""
        _cache_att  = st.session_state.get("_precos_anp_cache", {})
        _sheets_att = _cache_att.get("sheets", {})
        _semana_att = _cache_att.get("semana", "")

        # ── Prioridade 1: abastecimentos do cliente para este posto ─────────
        _abast_df = st.session_state.get("_abastecimentos_cliente_df", None)
        if (_abast_df is not None and not _abast_df.empty
                and cnpj_norm and "cnpj_posto" in _abast_df.columns):
            _cnpj_limpo = str(cnpj_norm).replace(r"\D", "")
            _rows_abast = _abast_df[
                _abast_df["cnpj_posto"].astype(str).str.replace(r"\D","",regex=True) == _cnpj_limpo
            ]
            if not _rows_abast.empty and "preco_unitario" in _rows_abast.columns:
                # Último preço por combustível
                _ult = (_rows_abast.sort_values("data_abastecimento", ascending=False)
                        .groupby("combustivel")["preco_unitario"].first())
                for _comb, _preco in _ult.items():
                    try:
                        linhas.append(f"<b>{_comb}:</b> R$ {float(_preco):.3f}/L")
                    except Exception:
                        pass
                if linhas:
                    fonte = "Abastecimento do cliente"

        # ── Prioridade 2: ANP por município → estado → Brasil ───────────────
        if not linhas and _sheets_att:
            _rows_anp = _anp_extrair_precos(_sheets_att, uf=uf, municipio=municipio or None)
            if _rows_anp:
                _nivel = _rows_anp[0].get("_nivel", uf or "BR") if _rows_anp else ""
                _pks_label = {
                    "diesels10":         "Diesel S10",
                    "diesel":            "Diesel",
                    "gasolinaaditivada": "Gasolina Aditivada",
                    "gasolina":          "Gasolina",
                    "etanol":            "Etanol",
                    "gnv":               "GNV",
                    "glp":               "GLP",
                }
                _seen = set()
                for _r in _rows_anp:
                    _pk  = _r.get("_pk", "")
                    _lbl = _pks_label.get(_pk, str(_r.get("Produto", _pk)).strip())
                    _preco = _r.get("Preço Médio")
                    if _pk not in _seen and _preco is not None:
                        _seen.add(_pk)
                        try:
                            _v_float = float(_preco)
                            # Filtrar valores absurdos (GLP em kg != L, erro de dados)
                            if 0.5 < _v_float < 50.0:
                                linhas.append(f"<b>{_lbl}:</b> R$ {_v_float:.3f}/L")
                        except Exception:
                            pass
                if linhas:
                    _nivel_label = _rows_anp[0].get("_nivel", uf or "BR") if _rows_anp else (uf or "BR")
                    fonte = f"ANP {_nivel_label}{(' · ' + _semana_att) if _semana_att else ''} (preço médio)"

        if not linhas:
            return ""

        _items_html = "<br>".join(linhas)
        _fonte_html = (f"<span style='font-size:9px;color:#aaa'>Fonte: {fonte}</span>"
                       if fonte else "")
        return (
            f"<br><span style='font-size:10px;color:#b0b0b0'>──────────────</span>"
            f"<br><span style='font-size:10px;color:#ffd54f'><b>💰 Preços</b></span>"
            f"<br><span style='font-size:11px'>{_items_html}</span>"
            f"<br>{_fonte_html}"
        )
    except Exception:
        return ""


def _montar_html_precos(linhas: list, fonte: str) -> str:
    """Monta bloco HTML de preços para tooltip do mapa."""
    _items_html = "<br>".join(linhas)
    _fonte_html = (
        f"<span style='font-size:9px;color:#aaa'>Fonte: {fonte}</span>" if fonte else ""
    )
    return (
        f"<br><span style='font-size:10px;color:#b0b0b0'>──────────────</span>"
        f"<br><span style='font-size:10px;color:#ffd54f'><b>💰 Preços</b></span>"
        f"<br><span style='font-size:11px'>{_items_html}</span>"
        f"<br>{_fonte_html}"
    )


def _precos_tooltip_html_bulk(cnpjs: "pd.Series", ufs: "pd.Series", municipios: "pd.Series | None" = None) -> dict:
    """
    Pré-computa HTML de preços para todos os CNPJs de uma vez.
    Retorna dict {cnpj_norm: html_str}.

    Elimina a complexidade O(n²) de chamar _precos_tooltip_html() por linha.
    Versão 5.2 — chamada uma única vez antes do loop de traces em criar_mapa.
    """
    resultado: dict = {}
    _pp_df_tt = st.session_state.get("_pp_df")

    pp_index: dict = {}
    if (
        _pp_df_tt is not None
        and not _pp_df_tt.empty
        and "cnpj_norm" in _pp_df_tt.columns
    ):
        for cnpj_n, grupo in _pp_df_tt.groupby("cnpj_norm", sort=False):
            linhas = []
            _rows_sorted = sorted(
                grupo.iterrows(),
                key=lambda x: _comb_sort_key(
                    str(x[1].get("combustivel_label", "") or x[1].get("combustivel_pk", ""))
                ),
            )
            for _, _r in _rows_sorted:
                _lbl = str(_r.get("combustivel_label", "") or "").strip()
                try:
                    _preco = float(_r["preco"])
                except Exception:
                    _preco = None
                if _lbl and _preco is not None:
                    linhas.append(f"<b>{_lbl}:</b> R$ {_preco:.3f}/L")
            if linhas:
                _data_tt = str(grupo.iloc[0].get("data_atualizacao", "") or "").strip()
                _data_tt = _data_tt if _data_tt and _data_tt not in ("nan", "None") else ""
                fonte = f"PP{(' · ' + _data_tt) if _data_tt else ''}"
                pp_index[str(cnpj_n)] = _montar_html_precos(linhas, fonte)

    _cache_att  = st.session_state.get("_precos_anp_cache", {})
    _sheets_att = _cache_att.get("sheets", {})
    _semana_att = _cache_att.get("semana", "")
    # Cache ANP por UF usando hierarquia municipio -> estado -> Brasil
    anp_por_uf: dict = {}
    if _sheets_att:
        _pks_label = {
            "diesels10":              "Diesel S10",
            "diesel":                 "Diesel Comum",
            "gasolinaaditivada":      "Gasolina Aditivada",
            "gasolina":               "Gasolina Comum",
            "etanolhidratadocombusti":"Etanol Hidratado",
            "etanol":                 "Etanol",
            "gnv":                    "GNV",
            "glp":                    "GLP",
            "oleodiesel":             "Diesel Comum",
            "oleodiesels10":          "Diesel S10",
        }
        for uf_val in ufs.dropna().unique():
            uf_val = str(uf_val).strip().upper()
            if not uf_val:
                continue
            _rows_uf = _anp_extrair_precos(_sheets_att, uf=uf_val)
            if _rows_uf:
                linhas = []
                _seen = set()
                for _r in _rows_uf:
                    _pk   = _r.get("_pk", "")
                    _lbl  = _pks_label.get(_pk, str(_r.get("Produto", _pk)).strip())
                    _preco = _r.get("Preço Médio") or _r.get("Preco Medio")
                    if _pk not in _seen and _preco is not None:
                        _seen.add(_pk)
                        try:
                            _v_float = float(_preco)
                            # Filtrar valores absurdos (GLP em kg != L, erro de dados)
                            if 0.5 < _v_float < 50.0:
                                linhas.append(f"<b>{_lbl}:</b> R$ {_v_float:.3f}/L")
                        except Exception:
                            pass
                if linhas:
                    _nivel = _rows_uf[0].get("Nível", uf_val)
                    fonte  = f"ANP {_nivel}"
                    if _semana_att:
                        _sem_label = str(_semana_att)[-10:] if len(str(_semana_att)) > 10 else str(_semana_att)
                        fonte += f" · sem. {_sem_label} (media)"
                    anp_por_uf[uf_val] = _montar_html_precos(linhas, fonte)

    # Pre-computa cache por municipio+uf
    anp_por_mun: dict = {}
    if _sheets_att and municipios is not None:
        _pks_label2 = {
            "diesels10":              "Diesel S10",
            "diesel":                 "Diesel Comum",
            "gasolinaaditivada":      "Gasolina Aditivada",
            "gasolina":               "Gasolina Comum",
            "etanolhidratadocombusti":"Etanol Hidratado",
            "etanol":                 "Etanol",
            "gnv":                    "GNV",
        }
        _mun_uf_pares = set(
            zip(municipios.fillna("").astype(str).values,
                ufs.fillna("").astype(str).str.upper().values)
        )
        for _mun_v, _uf_v in _mun_uf_pares:
            if not _mun_v or not _uf_v:
                continue
            _key = f"{_mun_v}|{_uf_v}"
            if _key in anp_por_mun:
                continue
            _rows_mun = _anp_extrair_precos(_sheets_att, uf=_uf_v, municipio=_mun_v)
            if not _rows_mun:
                continue
            _nivel_mun = _rows_mun[0].get("Nível", _uf_v)
            # Apenas usar se nivel for Municipio ou Capital
            if _nivel_mun not in ("Município", "Capital"):
                continue
            linhas = []
            _seen = set()
            for _r in _rows_mun:
                _pk   = _r.get("_pk", "")
                _lbl  = _pks_label2.get(_pk, str(_r.get("Produto", _pk)).strip())
                _preco = _r.get("Preço Médio") or _r.get("Preco Medio")
                if _pk not in _seen and _preco is not None:
                    _seen.add(_pk)
                    try:
                        _v_f = float(_preco)
                        if 0.5 < _v_f < 50.0:
                            linhas.append(f"<b>{_lbl}:</b> R$ {_v_f:.3f}/L")
                    except Exception:
                        pass
            if linhas:
                _sem = f" · sem. {str(_semana_att)[-10:]}" if _semana_att else ""
                anp_por_mun[_key] = _montar_html_precos(
                    linhas, f"ANP {_nivel_mun}{_sem} (media)")

    cnpjs_arr = cnpjs.fillna("").astype(str).values
    ufs_arr   = ufs.fillna("").astype(str).str.strip().str.upper().values
    muns_arr  = municipios.fillna("").astype(str).values if municipios is not None else [""] * len(cnpjs_arr)

    # ── Prioridade 0: último preço real de abastecimento do cliente ──
    _abast_idx: dict = {}
    try:
        _abast_tt = _carregar_abastecimentos_unificados(dias=730)
        if not _abast_tt.empty and "cnpj_posto" in _abast_tt.columns:
            import re as _re_tt
            _preco_col_tt = next((c for c in ["preco_litro","preco_unitario","item_valor_unitario"]
                                  if c in _abast_tt.columns), None)
            _prod_col_tt  = next((c for c in ["produto","combustivel","item_nome"]
                                  if c in _abast_tt.columns), None)
            if _preco_col_tt and _prod_col_tt:
                _abast_tt["_cn_tt"] = _abast_tt["cnpj_posto"].astype(str).str.replace(r"\D","",regex=True)
                _abast_tt["_preco_tt"] = pd.to_numeric(_abast_tt[_preco_col_tt], errors="coerce")
                if "data_abastecimento" in _abast_tt.columns:
                    _abast_tt = _abast_tt.sort_values("data_abastecimento", ascending=False)
                for _cn_tt, _grp_tt in _abast_tt.groupby("_cn_tt"):
                    _ult_tt = _grp_tt.groupby(_prod_col_tt).first().reset_index()
                    _linhas_tt = []
                    for _, _r_tt in _ult_tt.iterrows():
                        _p_tt = _r_tt.get("_preco_tt")
                        _c_tt = str(_r_tt.get(_prod_col_tt, "")).strip()
                        if _c_tt and pd.notna(_p_tt) and 0.5 < float(_p_tt) < 50.0:
                            _linhas_tt.append(f"<b>{_c_tt}:</b> R$ {float(_p_tt):.3f}/L")
                    if _linhas_tt:
                        _dt_tt = ""
                        if "data_abastecimento" in _grp_tt.columns:
                            _dt_tt = str(_grp_tt.iloc[0]["data_abastecimento"])[:10]
                        _abast_idx[str(_cn_tt)] = _montar_html_precos(
                            _linhas_tt, f"Último abastecimento{( ' · ' + _dt_tt) if _dt_tt else ''}")
    except Exception:
        pass
    for cnpj_n, uf_val, mun_val in zip(cnpjs_arr, ufs_arr, muns_arr):
        _mun_key = f"{mun_val}|{uf_val}"
        if cnpj_n in _abast_idx:
            resultado[cnpj_n] = _abast_idx[cnpj_n]
        elif cnpj_n in pp_index:
            resultado[cnpj_n] = pp_index[cnpj_n]
        elif _mun_key in anp_por_mun:
            resultado[cnpj_n] = anp_por_mun[_mun_key]
        elif uf_val in anp_por_uf:
            resultado[cnpj_n] = anp_por_uf[uf_val]
        else:
            resultado[cnpj_n] = ""

    return resultado


def _hover_txt_vec(sub_df: pd.DataFrame, precos_bulk: dict) -> list:
    """
    Gera lista de textos de tooltip para todos os pontos de uma vez (vetorizado).
    Substitui: sub_df.apply(_hover_txt, axis=1).tolist()
    Versão 5.2.
    """
    nomes  = sub_df.get("razaoSocial",   pd.Series([""] * len(sub_df))).fillna("").astype(str).str[:40].values
    dists  = sub_df.get("distribuidora", pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    muns   = sub_df.get("municipio",     pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    ufs_   = sub_df.get("uf",            pd.Series([""] * len(sub_df))).fillna("").astype(str).str.strip().str.upper().values
    cnpjs  = sub_df.get("cnpj",          pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    if "_cnpj_norm" in sub_df.columns:
        cnpj_norms = sub_df["_cnpj_norm"].fillna("").astype(str).str.replace(" ", "", regex=False).values
    else:
        cnpj_norms = cnpjs
    pf_  = sub_df["_pro_frotas"].fillna(False).values if "_pro_frotas" in sub_df.columns else np.zeros(len(sub_df), dtype=bool)
    cer_ = sub_df["_cercado"   ].fillna(False).values if "_cercado"    in sub_df.columns else np.zeros(len(sub_df), dtype=bool)
    rr_  = sub_df["_rodo_rede" ].fillna(False).values if "_rodo_rede"  in sub_df.columns else np.zeros(len(sub_df), dtype=bool)
    textos = []
    for i in range(len(sub_df)):
        geo      = f"{muns[i]}/{ufs_[i]}" if muns[i] and ufs_[i] else muns[i] or ufs_[i]
        pf_tag   = " ⭐" if pf_[i]  else ""
        rr_tag   = " · Rodo Rede" if rr_[i] else ""
        cer_tag  = " ⚠️" if cer_[i] else ""
        cnpj_str = f"<br>📋 {cnpjs[i]}" if cnpjs[i] else ""
        precos   = precos_bulk.get(cnpj_norms[i], "")
        textos.append(
            f"<b>{nomes[i]}</b>{pf_tag}{rr_tag}{cer_tag}"
            f"<br>{dists[i]}<br>{geo}{cnpj_str}{precos}"
        )
    return textos


def _customdata_vec(sub_df: pd.DataFrame) -> list:
    """
    Gera customdata com to_numpy() — sem iterrows().
    Substitui: _customdata(sub_df)
    Versão 5.2.
    """
    muns  = sub_df.get("municipio",     pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    ufs_  = sub_df.get("uf",            pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    geos  = np.where(
        (muns != "") & (ufs_ != ""),
        np.char.add(np.char.add(muns, "/"), ufs_),
        np.where(muns != "", muns, ufs_),
    )
    cnpjs = sub_df.get("cnpj",          pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    nomes = sub_df.get("razaoSocial",   pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    dists = sub_df.get("distribuidora", pd.Series([""] * len(sub_df))).fillna("").astype(str).values
    lats  = sub_df["_lat"].astype(float).values
    lons  = sub_df["_lon"].astype(float).values
    pf_  = sub_df["_pro_frotas"].fillna(False).astype(bool).values if "_pro_frotas" in sub_df.columns else np.zeros(len(sub_df), dtype=bool)
    cer_ = sub_df["_cercado"   ].fillna(False).astype(bool).values if "_cercado"    in sub_df.columns else np.zeros(len(sub_df), dtype=bool)
    rr_  = sub_df["_rodo_rede" ].fillna(False).astype(bool).values if "_rodo_rede"  in sub_df.columns else np.zeros(len(sub_df), dtype=bool)
    pf_s  = np.where(pf_,  "1", "")
    cer_s = np.where(cer_, "1", "")
    rr_s  = np.where(rr_,  "1", "")
    arr = np.column_stack([cnpjs, nomes, dists, geos,
                           lats.astype(object), lons.astype(object),
                           pf_s, cer_s, rr_s])
    return arr.tolist()


def criar_mapa(df, coords_rota=None, lat_orig=None, lon_orig=None,
               lat_dest=None, lon_dest=None, label_orig="Origem", label_dest="Destino",
               waypoints=None):
    """Retorna go.Figure (Plotly Scattermapbox) — WebGL, suporta 10 000+ marcadores."""
    # ── Cap de marcadores — postos ANP por bandeira ──────────────────────────────
    n_total = len(df)
    foi_limitado = False
    if not df.empty and n_total > MAX_MAPA_POSTOS:
        foi_limitado = True
        # Priorizar postos transacionados pelo cliente
        _mask_trans = pd.Series(False, index=df.index)
        if "_transacionado" in df.columns:
            _mask_trans |= df["_transacionado"].fillna(False)
        df_trans = df[_mask_trans]
        df_reg   = df[~_mask_trans]
        n_reg_max = max(0, MAX_MAPA_POSTOS - len(df_trans))
        if len(df_reg) > n_reg_max:
            df_reg = df_reg.sample(n=n_reg_max, random_state=42)
        df = pd.concat([df_trans, df_reg], ignore_index=True)

    # ── Centro e zoom do mapa ──────────────────────────────────────────────────
    if not df.empty:
        clat = float(df["_lat"].mean())
        clon = float(df["_lon"].mean())
        zoom = 6
    elif coords_rota:
        lats = [c[0] for c in coords_rota]
        lons = [c[1] for c in coords_rota]
        clat = (min(lats) + max(lats)) / 2
        clon = (min(lons) + max(lons)) / 2
        zoom = 5
    else:
        clat, clon, zoom = -15.0, -47.0, 4

    traces = []

    # ── Linha da rota ──────────────────────────────────────────────────────────
    if coords_rota and len(coords_rota) >= 2:
        coords_poly = _downsample(coords_rota, 500)
        traces.append(go.Scattermapbox(
            lat=[c[0] for c in coords_poly],
            lon=[c[1] for c in coords_poly],
            mode="lines",
            line=dict(width=4, color="#1565C0"),
            hoverinfo="skip",
            name="Rota",
            showlegend=False,
        ))

    # ── Marcadores origem / paradas / destino ─────────────────────────────────
    if lat_orig is not None:
        traces.append(go.Scattermapbox(
            lat=[lat_orig], lon=[lon_orig],
            mode="markers",
            marker=dict(size=16, color="#2E7D32"),
            text=[f"🟢 Origem: {label_orig}"],
            hoverinfo="text",
            name="Origem",
            showlegend=False,
        ))
    # Paradas intermediárias — PIN laranja grande com número da parada
    if waypoints:
        for idx_wp, wp in enumerate(waypoints, start=1):
            traces.append(go.Scattermapbox(
                lat=[wp["lat"]], lon=[wp["lon"]],
                mode="markers+text",
                marker=dict(size=22, color="#FF8F00"),
                text=[str(idx_wp)],
                textfont=dict(size=12, color="#fff", family="Arial Black, sans-serif"),
                textposition="middle center",
                customdata=[[wp["label"], idx_wp]],
                hovertemplate=(
                    f"<b>📍 Parada {idx_wp}</b><br>"
                    f"{wp['label']}<extra></extra>"
                ),
                name=f"Parada {idx_wp}",
                showlegend=False,
            ))
    if lat_dest is not None:
        traces.append(go.Scattermapbox(
            lat=[lat_dest], lon=[lon_dest],
            mode="markers",
            marker=dict(size=16, color="#C62828"),
            text=[f"🔴 Destino: {label_dest}"],
            hoverinfo="text",
            name="Destino",
            showlegend=False,
        ))

    # ── Postos ─────────────────────────────────────────────────────────────────
    if not df.empty:
        distribuidoras = sorted(df["distribuidora"].dropna().unique())
        mapa_cores = {d.upper().strip(): _cor_marca(d) for d in distribuidoras}


        # Pre-computa lookup CNPJ->HTML de precos uma unica vez (evita O(n2))
        _precos_bulk = _precos_tooltip_html_bulk(
            df.get("_cnpj_norm", df.get("cnpj", pd.Series(dtype=str))),
            df.get("uf", pd.Series(dtype=str)),
            df.get("municipio", pd.Series(dtype=str)),
        )

        # ── Postos ANP por bandeira — legenda por marca ─────────────────────────────
        # Postos transacionados pelo cliente — destaque especial
        if "_transacionado" in df.columns and df["_transacionado"].fillna(False).any():
            df_trans_map = df[df["_transacionado"].fillna(False)]
            traces.append(go.Scattermapbox(
                lat=df_trans_map["_lat"].tolist(), lon=df_trans_map["_lon"].tolist(),
                mode="markers",
                marker=dict(size=14, color="#00b4d8", opacity=1.0,
                           symbol="circle"),
                text=_hover_txt_vec(df_trans_map, _precos_bulk),
                customdata=_customdata_vec(df_trans_map),
                hoverinfo="text",
                name="💳 Postos utilizados",
            ))

        # Bandeiras principais — cada uma com sua cor de identidade
        _bandeiras_legenda = [
            ("IPIRANGA",    "#FFB300", "🟡 Ipiranga"),
            ("ULTRAPAR",    "#FFB300", "🟡 Ipiranga"),
            ("VIBRA",       "#43A047", "🟢 Vibra/BR"),
            ("BR DISTRIB",  "#43A047", "🟢 Vibra/BR"),
            ("PETROBRAS D", "#43A047", "🟢 Vibra/BR"),
            ("RAIZEN",      "#E53935", "🔴 Shell/Raízen"),
            ("RAÍZEN",      "#E53935", "🔴 Shell/Raízen"),
            ("SHELL",       "#E53935", "🔴 Shell/Raízen"),
            ("ALESAT",      "#F57C00", "🟠 Ale"),
            ("ALE COMB",    "#F57C00", "🟠 Ale"),
        ]
        _bandeiras_vistas = set()
        for _substr, _cor_b, _nome_b in _bandeiras_legenda:
            if _nome_b in _bandeiras_vistas:
                continue
            if "distribuidora" not in df.columns:
                continue
            _mask_b = df["distribuidora"].fillna("").str.upper().str.contains(_substr)
            if "_transacionado" in df.columns:
                _mask_b = _mask_b & ~df["_transacionado"].fillna(False)
            if not _mask_b.any():
                continue
            _bandeiras_vistas.add(_nome_b)
            _df_b = df[_mask_b]
            traces.append(go.Scattermapbox(
                lat=_df_b["_lat"].tolist(), lon=_df_b["_lon"].tolist(),
                mode="markers",
                marker=dict(size=9, color=_cor_b, opacity=0.88),
                text=_hover_txt_vec(_df_b, _precos_bulk),
                customdata=_customdata_vec(_df_b),
                hoverinfo="text",
                name=_nome_b,
            ))

        # Demais bandeiras — cor determinística por nome
        _mask_demais = pd.Series(True, index=df.index)
        for _substr, _, _ in _bandeiras_legenda:
            _mask_demais &= ~df["distribuidora"].fillna("").str.upper().str.contains(_substr)
        if "_transacionado" in df.columns:
            _mask_demais &= ~df["_transacionado"].fillna(False)
        if _mask_demais.any():
            _df_demais = df[_mask_demais].copy()
            _df_demais["_cor_plot"] = _df_demais["distribuidora"].apply(
                lambda d: _cor(d, mapa_cores))
            traces.append(go.Scattermapbox(
                lat=_df_demais["_lat"].tolist(), lon=_df_demais["_lon"].tolist(),
                mode="markers",
                marker=dict(size=8, color=_df_demais["_cor_plot"].tolist(), opacity=0.82),
                text=_hover_txt_vec(_df_demais, _precos_bulk),
                customdata=_customdata_vec(_df_demais),
                hoverinfo="text",
                name="⚪ Outras bandeiras",
            ))

    # ── Trace Top 5 Mais Baratos — estrelas douradas sobrepostas ─────────────────
    if not df.empty and "_rank_barato" in df.columns:
        _df_top5 = df[df["_rank_barato"] > 0].sort_values("_rank_barato")
        if not _df_top5.empty:
            _top5_hover = []
            for _, _tr in _df_top5.iterrows():
                _rank_n  = int(_tr["_rank_barato"])
                _emoji_r = _RANK_EMOJI.get(_rank_n, str(_rank_n))
                _nome_r  = str(_tr.get("razaoSocial", "?"))[:35]
                _preco_r = _tr.get("_preco_barato")
                _comb_r  = str(_tr.get("_comb_barato", ""))
                _mun_r   = str(_tr.get("municipio", ""))
                _uf_r    = str(_tr.get("uf", ""))
                _geo_r   = f"{_mun_r}/{_uf_r}" if _mun_r and _uf_r else _mun_r or _uf_r
                _preco_str = f"R$ {_preco_r:.3f}/L" if _preco_r is not None else "—"
                _top5_hover.append(
                    f"<b>{_emoji_r} #{_rank_n} Mais Barato</b><br>"
                    f"{_nome_r}<br>"
                    f"💰 {_preco_str} — {_comb_r}<br>"
                    f"📍 {_geo_r}<extra></extra>"
                )
            traces.append(go.Scattermapbox(
                lat=_df_top5["_lat"].tolist(),
                lon=_df_top5["_lon"].tolist(),
                mode="markers+text",
                marker=dict(size=22, color="#FFD700", opacity=1.0),
                text=[_RANK_EMOJI.get(int(r), "★") for r in _df_top5["_rank_barato"]],
                textfont=dict(size=11, color="#7B3F00", family="Arial Black, sans-serif"),
                textposition="middle center",
                hovertemplate=_top5_hover,
                name="💰 Top 5 Mais Baratos",
                showlegend=True,
            ))

    # ── Garante ao menos 1 trace Scattermapbox para ativar tiles mesmo sem dados ──
    # Sem isso, Plotly cai no modo cartesiano quando traces=[] e exibe eixos vazios.
    if not traces:
        traces.append(go.Scattermapbox(
            lat=[], lon=[],
            mode="markers",
            marker=dict(size=1, opacity=0),
            hoverinfo="skip",
            showlegend=False,
        ))

    # ── Anotação de limitação ──────────────────────────────────────────────────
    layout_annotations = []
    if foi_limitado:
        layout_annotations.append(dict(
            text=(f"⚠️ Exibindo {_fmt_int(MAX_MAPA_POSTOS)} de {_fmt_int(n_total)} postos "
                  f"(Gestão de Frotas priorizados). Veja todos na aba Dados Tabulares."),
            x=0.5, y=0.02, xref="paper", yref="paper",
            showarrow=False, align="center",
            font=dict(size=11, color="#E65100"),
            bgcolor="rgba(255,243,224,0.92)",
            bordercolor="#FF9800", borderwidth=1,
        ))

    fig = go.Figure(
        data=traces,
        layout=go.Layout(
            mapbox=dict(
                style="carto-positron",
                center=dict(lat=clat, lon=clon),
                zoom=zoom,
            ),
            margin=dict(l=0, r=0, t=0, b=0),
            legend=dict(
                bgcolor="rgba(255,255,255,0.92)",
                bordercolor="#ccc",
                borderwidth=1,
                font=dict(size=11),
                x=0.01, y=0.99,
                xanchor="left", yanchor="top",
            ),
            annotations=layout_annotations,
            uirevision="mapa_estudo_rede",
        ),
    )
    return fig


@_fragment
def _renderizar_mapa(fig: go.Figure, height: int = 660, key: str = "mapa_plot") -> None:
    """
    Renderiza o mapa Plotly e exibe painel de detalhe ao clicar num posto.

    — Seleção ativa: banner amarelo acima do mapa + card destacado abaixo.
    — Botão "✕ Limpar seleção" força re-render limpo (sem seleção).
    — CNPJ + localização aparecem no tooltip (hover) nativo do Plotly.
    """
    # ── Chaves de sessão para esta instância do mapa ────────────────────────────
    _sel_key = f"_msel_{key}"   # armazena dados do posto selecionado
    _ver_key = f"_mver_{key}"   # versão para forçar re-render ao limpar

    _ver      = st.session_state.get(_ver_key, 0)
    _chart_key = f"{key}_v{_ver}"
    _sel       = st.session_state.get(_sel_key)  # dict com dados do posto ou None

    # ── Banner de seleção ativa (aparece ACIMA do mapa) ─────────────────────────
    if _sel:
        _ban_nome = _sel.get("nome", "Posto")
        _ban_geo  = _sel.get("geo", "")
        _ban_lat  = _sel.get("lat")
        _ban_lon  = _sel.get("lon")
        _ban_maps = (f"https://maps.google.com/?q={float(_ban_lat):.6f},{float(_ban_lon):.6f}"
                     if _ban_lat is not None and _ban_lon is not None else None)

        c_info, c_maps, c_limpar = st.columns([5, 1, 1])
        with c_info:
            st.markdown(
                f"<div style='"
                f"background:linear-gradient(90deg,#fff8e1,#fffde7);"
                f"border:1.5px solid #f9a825;"
                f"border-radius:8px;padding:8px 14px;"
                f"display:flex;align-items:center;gap:10px;"
                f"font-size:13px;color:#5f4307;line-height:1.4'>"
                f"<span style='font-size:18px'>📌</span>"
                f"<div><b>Posto selecionado</b><br>"
                f"<span style='color:#333'>{_ban_nome}"
                f"{'  ·  ' + _ban_geo if _ban_geo else ''}</span></div>"
                f"</div>",
                unsafe_allow_html=True,
            )
        with c_maps:
            if _ban_maps:
                st.link_button("📍 Maps", _ban_maps, use_container_width=True)
        with c_limpar:
            if st.button(
                "✕ Limpar",
                key=f"_desel_{key}",
                use_container_width=True,
                help="Remover seleção e voltar ao mapa limpo",
            ):
                st.session_state.pop(_sel_key, None)
                st.session_state[_ver_key] = _ver + 1  # troca a key → re-render sem seleção
                st.rerun()

    # ── Renderiza o gráfico ─────────────────────────────────────────────────────
    # Config mobile-friendly: botões da toolbar reduzidos, sem mode bar em telas pequenas
    _plotly_cfg = {
        "scrollZoom":          True,
        "displaylogo":         False,
        "responsive":          True,
        "modeBarButtonsToRemove": [
            "select2d", "lasso2d", "autoScale2d",
            "hoverClosestCartesian", "hoverCompareCartesian",
        ],
        "toImageButtonOptions": {"format": "png", "filename": "mapa_rede"},
    }
    try:
        evt = st.plotly_chart(
            fig,
            use_container_width=True,
            config=_plotly_cfg,
            height=height,
            on_select="rerun",
            key=_chart_key,
        )
    except TypeError:
        st.plotly_chart(fig, use_container_width=True,
                        config={"scrollZoom": True}, height=height)
        return

    # ── Captura seleção ─────────────────────────────────────────────────────────
    pts = (evt or {}).get("selection", {}).get("points", [])
    if not pts:
        return

    pt = pts[0]
    cd = pt.get("customdata") or []

    # customdata = [cnpj, nome, distribuidora, geo, lat, lon, pf, cercado, rr]
    _cnpj = cd[0] if len(cd) > 0 else ""
    _nome = cd[1] if len(cd) > 1 else pt.get("text", "Posto")
    _dist = cd[2] if len(cd) > 2 else ""
    _geo  = cd[3] if len(cd) > 3 else ""
    _lat  = cd[4] if len(cd) > 4 else pt.get("lat")
    _lon  = cd[5] if len(cd) > 5 else pt.get("lon")
    _pf   = bool(cd[6]) if len(cd) > 6 else False
    _cer  = bool(cd[7]) if len(cd) > 7 else False
    _rr   = bool(cd[8]) if len(cd) > 8 else False

    if _lat is None or _lon is None:
        return

    # Persiste no session_state (mantém painel visível em reruns futuros)
    _existing_cnpj = (st.session_state.get(_sel_key) or {}).get("cnpj", "")
    st.session_state[_sel_key] = dict(
        nome=_nome, cnpj=_cnpj, dist=_dist, geo=_geo,
        lat=_lat, lon=_lon, pf=_pf, cer=_cer, rr=_rr,
    )

    # ── Força re-render imediato para o banner aparecer na 1ª seleção ──
    # Sem este rerun o banner só apareceria no 2º clique, porque o
    # st.plotly_chart() (que produz os dados) vem depois do bloco "if _sel:"
    if _cnpj != _existing_cnpj:
        st.rerun()

    _maps_url = f"https://maps.google.com/?q={_lat:.6f},{_lon:.6f}"

    # ── Badges de categoria ─────────────────────────────────────────────────────
    _badges_html = ""
    if _pf:
        _badges_html += (
            "<span style='background:#1565c0;color:#fff;border-radius:4px;"
            "padding:2px 8px;font-size:11px;margin-right:5px'>⭐ Gestão de Frotas</span>"
        )
    if _rr:
        _rr_img = _img_rodo_rede_b64()
        if _rr_img:
            _badges_html += (
                f"<span style='display:inline-flex;align-items:center;gap:4px;"
                f"background:#fff3e0;border:1px solid {COR_RR_FILL};"
                f"border-radius:4px;padding:2px 7px;font-size:11px;margin-right:5px'>"
                f"<img src='{_rr_img}' style='height:14px;width:auto;object-fit:contain;"
                f"vertical-align:middle;border-radius:2px'> ⭐ Ipiranga RodoRede</span>"
            )
        else:
            _badges_html += (
                f"<span style='background:{COR_RR_FILL};color:#fff;border-radius:4px;"
                f"padding:2px 8px;font-size:11px;margin-right:5px'>⭐ Ipiranga RodoRede</span>"
            )
    if _cer:
        _badges_html += (
            "<span style='background:#FF8F00;color:#fff;border-radius:4px;"
            "padding:2px 8px;font-size:11px;margin-right:5px'>⚠️ Cercado</span>"
        )

    _cnpj_html = f"<span style='color:#666;font-size:12px'>📋 {_cnpj}</span>&nbsp;&nbsp;" if _cnpj else ""
    _geo_html  = f"<span style='color:#666;font-size:12px'>📍 {_geo}</span>" if _geo else ""
    _dist_html = f"&nbsp;·&nbsp;<span style='color:#888'>{_dist}</span>" if _dist else ""

    # ── Preços do posto (busca no _pp_df pelo CNPJ) ─────────────────────────────
    _precos_html = ""
    try:
        _pp_df_card = st.session_state.get("_pp_df")
        _cnpj_norm  = re.sub(r"\D", "", str(_cnpj))
        if _pp_df_card is not None and _cnpj_norm and "cnpj_norm" in _pp_df_card.columns:
            _pp_posto = _pp_df_card[_pp_df_card["cnpj_norm"] == _cnpj_norm]
            if not _pp_posto.empty:
                _linhas_preco = []
                for _, _pr in _pp_posto.iterrows():
                    _lbl = str(_pr.get("combustivel_label") or _pr.get("combustivel_pk", ""))
                    _prc = _pr.get("preco")
                    if _lbl and _prc is not None:
                        _linhas_preco.append(
                            f"<span style='display:inline-block;margin-right:14px;"
                            f"font-size:11.5px'>"
                            f"<b>{_lbl}:</b> R$ {float(_prc):.3f}/L</span>"
                        )
                if _linhas_preco:
                    _precos_html = (
                        "<div style='margin-top:8px;padding-top:6px;"
                        "border-top:1px solid rgba(21,101,192,0.2)'>"
                        "<span style='font-size:11px;font-weight:700;color:#1565c0'>"
                        "⛽ Preços</span><br>"
                        + "".join(_linhas_preco)
                        + "</div>"
                    )
    except Exception:
        pass

    # ── Card de detalhe destacado (abaixo do mapa) ──────────────────────────────
    col_info, col_maps, col_limpar = st.columns([5, 1, 1])
    with col_info:
        st.markdown(
            f"<div style='"
            f"background:linear-gradient(135deg,#fff8e1 0%,#fffde7 100%);"
            f"border-left:5px solid #f9a825;"
            f"border-radius:0 10px 10px 0;"
            f"padding:12px 16px;"
            f"box-shadow:0 3px 12px rgba(249,168,37,0.18);"
            f"margin-top:4px'>"
            f"<div style='font-size:15px;font-weight:700;color:#5f4307'>"
            f"🏪 {_nome}{_dist_html}</div>"
            f"<div style='margin:6px 0 4px'>{_badges_html}</div>"
            f"<div style='margin-top:4px'>{_cnpj_html}{_geo_html}</div>"
            f"{_precos_html}"
            f"</div>",
            unsafe_allow_html=True,
        )
    with col_maps:
        st.link_button("📍 Maps", _maps_url, use_container_width=True)
    with col_limpar:
        if st.button(
            "✕ Limpar",
            key=f"_desel_card_{key}",
            use_container_width=True,
            help="Remover seleção",
        ):
            st.session_state.pop(_sel_key, None)
            st.session_state[_ver_key] = _ver + 1
            st.rerun()


# ═══════════════════════════════════════════════════════════════════
#  PREÇOS ANP — Levantamento Semanal de Preços de Combustíveis
#
#  Estrutura real do arquivo (resumo_semanal_lpc_*.xlsx):
#    Aba CAPITAIS  — colunas: DATA INICIAL, DATA FINAL, ESTADO, MUNICÍPIO, PRODUTO, Nº POSTOS, UNIDADE, PREÇO MÉDIO
#    Aba MUNICIPIOS— mesmas colunas de CAPITAIS
#    Aba ESTADOS   — colunas: DATA INICIAL, DATA FINAL, REGIAO, ESTADOS, PRODUTO, Nº POSTOS, UNIDADE, PREÇO MÉDIO
#    Aba REGIOES   — colunas: DATA INICIAL, DATA FINAL, REGIAO, PRODUTO, Nº POSTOS, UNIDADE, PREÇO MÉDIO, DESVIO
#    Aba BRASIL    — colunas: DATA INICIAL, DATA FINAL, BRASIL, PRODUTO, Nº POSTOS, UNIDADE, PREÇO MÉDIO, DESVIO
#  Cabeçalho sempre na linha 9 (0-indexed); linhas 0-7 são título/obs.
# ═══════════════════════════════════════════════════════════════════

def _anp_norm(s):
    """Remove acentos, uppercase, strip — para comparações robustas."""
    return unicodedata.normalize("NFD", str(s)).encode("ascii", "ignore").decode("ascii").upper().strip()


# Mapeamento reverso: nome normalizado → código UF (construído uma única vez)
_NOME_PARA_UF: dict = {
    _anp_norm(nome): codigo for codigo, nome in UF_NOME.items()
}


def _normalizar_uf(valor: str) -> str:
    """Converte 'Ceará', 'CEARÁ', 'ceara', 'CE', 'ce', etc. para o código de 2 letras.
    Retorna o valor original em maiúscula se não conseguir identificar.
    """
    v = str(valor).strip().upper()
    if v in UFS:                          # já é código válido
        return v
    return _NOME_PARA_UF.get(_anp_norm(v), v)


def _brl(v, d=2):
    """Formata número no padrão monetário brasileiro: ponto para milhar, vírgula para decimal.
    Exemplo: _brl(1234.5) → '1.234,50'  |  _brl(1.329, 3) → '1,329'
    """
    s = f"{v:,.{d}f}"          # '1,234.50' (padrão US)
    return s.replace(",", "X").replace(".", ",").replace("X", ".")


def _fmt_int(v) -> str:
    """Formata inteiro com ponto como separador de milhar (padrão BR).
    Exemplo: _fmt_int(14045) → '14.045'  |  _fmt_int(2962) → '2.962'
    """
    try:
        return f"{int(round(v)):,}".replace(",", ".")
    except (TypeError, ValueError):
        return str(v)


def _gerar_pdf_conversa(historico: list, empresa_nome: str = "", logo_b64: str = "") -> bytes:
    """Gera PDF formatado da conversa com o Assistente IA."""
    import io as _io_pdf
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors as _rlc
    from reportlab.lib.units import cm
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_LEFT, TA_CENTER, TA_RIGHT
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, HRFlowable
    from reportlab.lib.colors import HexColor
    from datetime import datetime

    _buf = _io_pdf.BytesIO()
    _doc = SimpleDocTemplate(
        _buf, pagesize=A4,
        leftMargin=2*cm, rightMargin=2*cm,
        topMargin=2*cm, bottomMargin=2*cm,
    )

    _styles = getSampleStyleSheet()
    _cor_primaria  = HexColor("#26215C")
    _cor_secundaria= HexColor("#534AB7")
    _cor_user_bg   = HexColor("#EEEDFE")
    _cor_bot_bg    = HexColor("#F8F7FF")
    _cor_borda     = HexColor("#AFA9EC")
    _cor_texto     = HexColor("#2C2C2A")
    _cor_cinza     = HexColor("#888780")

    _st_titulo = ParagraphStyle("titulo", parent=_styles["Normal"],
        fontSize=18, fontName="Helvetica-Bold", textColor=_cor_primaria,
        spaceAfter=4, alignment=TA_CENTER)
    _st_subtitulo = ParagraphStyle("subtitulo", parent=_styles["Normal"],
        fontSize=10, fontName="Helvetica", textColor=_cor_cinza,
        spaceAfter=2, alignment=TA_CENTER)
    _st_data = ParagraphStyle("data", parent=_styles["Normal"],
        fontSize=9, fontName="Helvetica", textColor=_cor_cinza,
        spaceAfter=16, alignment=TA_CENTER)
    _st_label_user = ParagraphStyle("label_user", parent=_styles["Normal"],
        fontSize=8, fontName="Helvetica-Bold", textColor=_cor_secundaria,
        spaceBefore=10, spaceAfter=3)
    _st_label_bot = ParagraphStyle("label_bot", parent=_styles["Normal"],
        fontSize=8, fontName="Helvetica-Bold", textColor=_cor_primaria,
        spaceBefore=10, spaceAfter=3)
    _st_msg = ParagraphStyle("msg", parent=_styles["Normal"],
        fontSize=10, fontName="Helvetica", textColor=_cor_texto,
        leading=15, spaceAfter=6)
    _st_rodape = ParagraphStyle("rodape", parent=_styles["Normal"],
        fontSize=8, fontName="Helvetica", textColor=_cor_cinza,
        alignment=TA_CENTER)

    _elementos = []

    # ── Cabeçalho com logo ────────────────────────────────────────
    if logo_b64:
        try:
            from reportlab.platypus import Image as _RLImg
            _logo_io = _io_pdf.BytesIO(base64.b64decode(logo_b64))
            _logo_img = _RLImg(_logo_io, width=4*cm, height=2*cm)
            _logo_img.hAlign = "CENTER"
            _elementos.append(_logo_img)
            _elementos.append(Spacer(1, 0.3*cm))
        except Exception:
            pass

    _elementos.append(Paragraph("Assistente IA — FNI Insights", _st_titulo))
    _elementos.append(Paragraph("Relatório de Conversa", _st_subtitulo))
    if empresa_nome:
        _elementos.append(Paragraph(f"Empresa: {empresa_nome}", _st_subtitulo))
    _elementos.append(Paragraph(
        f"Gerado em {datetime.now().strftime('%d/%m/%Y às %H:%M')}", _st_data))
    _elementos.append(HRFlowable(width="100%", thickness=1,
        color=_cor_borda, spaceAfter=12))

    # ── Mensagens ─────────────────────────────────────────────────
    for _msg in historico:
        _role = _msg.get("role", "")
        _text = _msg.get("content", "")

        if _role == "user":
            _elementos.append(Paragraph("👤 Você perguntou:", _st_label_user))
            _tbl = Table(
                [[Paragraph(_text.replace(chr(10), "<br/>"), _st_msg)]],
                colWidths=[16.5*cm]
            )
            _tbl.setStyle(TableStyle([
                ("BACKGROUND", (0,0), (-1,-1), _cor_user_bg),
                ("ROUNDEDCORNERS", [8]),
                ("BOX", (0,0), (-1,-1), 0.5, _cor_borda),
                ("LEFTPADDING", (0,0), (-1,-1), 10),
                ("RIGHTPADDING", (0,0), (-1,-1), 10),
                ("TOPPADDING", (0,0), (-1,-1), 8),
                ("BOTTOMPADDING", (0,0), (-1,-1), 8),
            ]))
            _elementos.append(_tbl)

        elif _role == "assistant":
            _elementos.append(Paragraph("🤖 Assistente FNI respondeu:", _st_label_bot))
            # Limpa markdown básico para PDF
            _clean = _text.replace("**", "").replace("*", "").replace("###", "").replace("##", "").replace("#", "")
            _tbl = Table(
                [[Paragraph(_clean.replace(chr(10), "<br/>"), _st_msg)]],
                colWidths=[16.5*cm]
            )
            _tbl.setStyle(TableStyle([
                ("BACKGROUND", (0,0), (-1,-1), _cor_bot_bg),
                ("ROUNDEDCORNERS", [8]),
                ("BOX", (0,0), (-1,-1), 0.5, HexColor("#D3D1C7")),
                ("LEFTPADDING", (0,0), (-1,-1), 10),
                ("RIGHTPADDING", (0,0), (-1,-1), 10),
                ("TOPPADDING", (0,0), (-1,-1), 8),
                ("BOTTOMPADDING", (0,0), (-1,-1), 8),
            ]))
            _elementos.append(_tbl)

    # ── Rodapé ────────────────────────────────────────────────────
    _elementos.append(Spacer(1, 0.5*cm))
    _elementos.append(HRFlowable(width="100%", thickness=0.5, color=_cor_borda))
    _elementos.append(Spacer(1, 0.2*cm))
    _n_msgs = len([m for m in historico if m.get("role") == "user"])
    _elementos.append(Paragraph(
        f"FNI Gestão de Frotas · fxgestaodefrotasonline.com · "
        f"{_n_msgs} pergunta(s) nesta conversa",
        _st_rodape))

    _doc.build(_elementos)
    return _buf.getvalue()





def _layout_br(fig, **kwargs):
    """Aplica padrão BR (separador milhar=. decimal=,) a figuras Plotly + kwargs extras."""
    fig.update_layout(
        separators=",.",          # BR: vírgula decimal, ponto milhar
        font=dict(family="Arial, sans-serif"),
        **kwargs
    )
    return fig


