                _c_h2.metric("📊 Observações totais", _fmt_int(_n_obs))
                _datas_all = [e["data"] for v in _hist_all.values() for e in v]
                _dt_min = min(_datas_all) if _datas_all else "—"
                _dt_max = max(_datas_all) if _datas_all else "—"
