def _cc_listar(cnpj_frota: str | None = None, empresa_id: str | None = None) -> list:
    """Lista centros de custo ativos."""
    try:
        _db = _db_client()
        _cnpj_cc = cnpj_frota or _cnpj_usuario_atual()
        q = _db.table("centros_custo").select("*").eq("ativo", True).order("nome")
        if _cnpj_cc:
            q = q.eq("cnpj_frota", _cnpj_cc)
        elif empresa_id:
            q = q.eq("empresa_id", empresa_id)
        return q.execute().data or []
    except Exception:
        return []


def _cc_salvar(nome: str, codigo: str, descricao: str, responsavel: str,
               cnpj_frota: str, empresa_id: str, criado_por: str,
               cc_id: str | None = None) -> tuple[bool, str]:
    """Cria ou atualiza um centro de custo."""
    try:
        _db = _db_client()
        payload = {
            "nome": nome.strip(),
            "codigo": codigo.strip() if codigo else None,
            "descricao": descricao.strip() if descricao else None,
            "responsavel": responsavel.strip() if responsavel else None,
            "cnpj_frota": cnpj_frota or None,
            "empresa_id": empresa_id or None,
            "criado_por": criado_por,
            "ativo": True,
        }
        if cc_id:
            _db.table("centros_custo").update(payload).eq("id", cc_id).execute()
            return True, f"Centro '{nome}' atualizado com sucesso."
        else:
            _db.table("centros_custo").insert(payload).execute()
            return True, f"Centro '{nome}' criado com sucesso."
    except Exception as e:
        return False, f"Erro: {e}"


def _cc_desativar(cc_id: str) -> tuple[bool, str]:
    """Desativa (soft delete) um centro de custo."""
    try:
        _db_client().table("centros_custo").update({"ativo": False}).eq("id", cc_id).execute()
        return True, "Centro de custo desativado."
    except Exception as e:
        return False, f"Erro: {e}"


def _cc_veiculos_listar(cc_id: str) -> list:
    """Lista veículos alocados em um centro de custo."""
    try:
        return (_db_client().table("centros_custo_veiculos")
                .select("*").eq("centro_custo_id", cc_id)
                .eq("ativo", True).order("placa").execute().data or [])
    except Exception:
        return []


def _cc_veiculo_alocar(cc_id: str, placa: str, cnpj_frota: str,
                        empresa_id: str, criado_por: str) -> tuple[bool, str]:
    """Aloca um veículo a um centro de custo."""
    try:
        _db = _db_client()
        # Desativa alocação anterior da mesma placa
        (_db.table("centros_custo_veiculos")
            .update({"ativo": False})
            .eq("placa", placa.upper().strip())
            .eq("ativo", True)
            .execute())
        # Cria nova alocação
        _db.table("centros_custo_veiculos").insert({
            "centro_custo_id": cc_id,
            "placa": placa.upper().strip(),
            "cnpj_frota": cnpj_frota or None,
            "empresa_id": empresa_id or None,
            "criado_por": criado_por,
            "ativo": True,
        }).execute()
        return True, f"Veículo {placa.upper()} alocado com sucesso."
    except Exception as e:
        return False, f"Erro: {e}"


def _cc_veiculo_remover(alocacao_id: str) -> tuple[bool, str]:
    """Remove alocação de veículo."""
    try:
        _db_client().table("centros_custo_veiculos").update({"ativo": False}).eq("id", alocacao_id).execute()
        return True, "Veículo removido do centro de custo."
    except Exception as e:
        return False, f"Erro: {e}"


def _cc_mapa_placa() -> dict:
    """Retorna dicionário {placa: nome_centro_custo} para uso nos relatórios."""
    try:
        _rows = (_db_client().table("centros_custo_veiculos")
                 .select("placa,centro_custo_id,centros_custo(nome,codigo)")
                 .eq("ativo", True).execute().data or [])
        return {r["placa"]: (r.get("centros_custo") or {}).get("nome","Sem centro")
                for r in _rows if r.get("placa")}
    except Exception:
        return {}


def _cc_enriquecer_df(df: "pd.DataFrame", col_placa: str = "veiculo_placa") -> "pd.DataFrame":
    """
    Adiciona coluna '_centro_custo_real' ao DataFrame baseado na placa.
    Usa a tabela centros_custo_veiculos como fonte autoritativa.
    """
    if df.empty or col_placa not in df.columns:
        return df
    try:
        _mapa = _cc_mapa_placa()
        if _mapa:
            df["_centro_custo_real"] = df[col_placa].map(_mapa).fillna("Sem centro alocado")
        else:
            df["_centro_custo_real"] = "Sem centro alocado"
    except Exception:
        df["_centro_custo_real"] = "Sem centro alocado"
    return df


def _cc_resumo_financeiro(cnpj_frota: str, dt_ini: str, dt_fim: str) -> dict:
    """
    Consolida custos de abastecimento + manutenção por centro de custo.
    Retorna dict {nome_cc: {comb, manut, litros, n_abast, n_manut, veiculos}}
    """
    import math as _mf
    _mapa = _cc_mapa_placa()
    resultado = {}

    # Abastecimentos
    try:
        _db = _db_client()
        q = (_db.table("profrotas_abastecimentos")
             .select("veiculo_placa,item_quantidade,item_valor_total,item_valor_unitario,item_tipo")
             .eq("item_tipo", 1)
             .gte("data_abastecimento", dt_ini)
             .lte("data_abastecimento", dt_fim + "T23:59:59")
             .limit(20000))
        if cnpj_frota:
            q = q.eq("cnpj_frota", cnpj_frota)
        _rows = q.execute().data or []
        for _r in _rows:
            _placa = str(_r.get("veiculo_placa","") or "").strip()
            _cc    = _mapa.get(_placa, "Sem centro alocado")
            _qtd   = float(_r.get("item_quantidade") or 0)
            _vtot  = _r.get("item_valor_total")
            _vun   = _r.get("item_valor_unitario")
            _valor = float(_vtot) if _vtot else (float(_vun or 0) * _qtd)
            if _math_isnan(_valor): _valor = 0
            if _cc not in resultado:
                resultado[_cc] = {"comb":0,"manut":0,"litros":0,"n_abast":0,"n_manut":0,"veiculos":set()}
            resultado[_cc]["comb"]    += _valor
            resultado[_cc]["litros"]  += _qtd
            resultado[_cc]["n_abast"] += 1
            resultado[_cc]["veiculos"].add(_placa)
    except Exception:
        pass

    # Manutenções
    try:
        _man_rows = _manut_listar(cnpj_frota=cnpj_frota, limit=2000)
        for _mr in _man_rows:
            _dt_mr = str(_mr.get("data_manutencao",""))[:10]
            if not (dt_ini <= _dt_mr <= dt_fim): continue
            _placa_mr = str(_mr.get("placa","") or "").strip()
            _cc_mr    = _mapa.get(_placa_mr, "Sem centro alocado")
            _custo_mr = float(_mr.get("custo_total") or 0)
            if _cc_mr not in resultado:
                resultado[_cc_mr] = {"comb":0,"manut":0,"litros":0,"n_abast":0,"n_manut":0,"veiculos":set()}
            resultado[_cc_mr]["manut"]    += _custo_mr
            resultado[_cc_mr]["n_manut"]  += 1
            resultado[_cc_mr]["veiculos"].add(_placa_mr)
    except Exception:
        pass

    # Converte sets para contagem
    for _cc in resultado:
        resultado[_cc]["veiculos"] = len(resultado[_cc]["veiculos"])
    return resultado


def _math_isnan(v):
    try:
        import math; return math.isnan(v)
    except Exception: return False
# ── Função central de indicadores de manutenção ─────────────────────────────
@st.cache_data(show_spinner=False, ttl=60)
def _mf_indicadores(cnpj_frota: str, km_por_placa: dict) -> dict:
    """
    Calcula indicadores de manutenção unificados.
    Retorna dict com n_total, n_critico, n_alerta, n_ok, score_medio, custo_est.
    Usa registro real do banco para calcular fase desde última manutenção.
    """
    import math as _mf_math
    _PRED_CFG_IND = {
        "oleo":         {"leve":10000,"pesado":15000,"custo":450},
        "pneus":        {"leve":40000,"pesado":60000,"custo":3200},
        "freios":       {"leve":40000,"pesado":60000,"custo":1800},
        "filtros":      {"leve":15000,"pesado":20000,"custo":380},
        "arrefecimento":{"leve":40000,"pesado":60000,"custo":800},
        "suspensao":    {"leve":50000,"pesado":80000,"custo":2500},
        "eletrico":     {"leve":30000,"pesado":50000,"custo":600},
        "revisao":      {"leve":20000,"pesado":30000,"custo":1200},
    }
    _KWS_IND = {
        "oleo":        ["óleo","oleo","oil","lubrif","troca de óleo","troca de oleo"],
        "pneus":       ["pneu","rodíz","rodiz","tire"],
        "freios":      ["freio","pastilha","disco","brake"],
        "filtros":     ["filtro","filter"],
        "arrefecimento":["arrefec","radiador","cooling"],
        "suspensao":   ["suspensão","suspensao","amortec","mola"],
        "eletrico":    ["elétric","eletric","electric","bateria"],
        "revisao":     ["revisão geral","revisao geral","revisão","revisao","overhaul"],
    }
    # Revisão Geral reseta todos os componentes
    _REVISAO_GERAL_KWS = ["revisão geral","revisao geral","revisão completa","revisao completa"]
    # Carrega histórico sem cache
    _hist = _manut_listar(cnpj_frota=cnpj_frota if cnpj_frota else None, limit=2000)
    # Monta mapa placa → {comp: hod_ult}
    _hod_ult_map = {}
    for _hr in _hist:
        _pl = str(_hr.get("placa","")).upper().strip()
        _hod = _hr.get("hodometro")
        if not _hod: continue
        try: _hod = float(_hod)
        except: continue
        if _mf_math.isnan(_hod) or _hod <= 0: continue
        _itens_str = " ".join(str(it) for it in (_hr.get("itens_realizados") or [])).lower()
        # Revisão Geral reseta TODOS os componentes
        _is_revisao_geral = any(kw in _itens_str for kw in _REVISAO_GERAL_KWS)
        if _is_revisao_geral:
            if _pl not in _hod_ult_map: _hod_ult_map[_pl] = {}
            for _comp_rg in _PRED_CFG_IND.keys():
                if _hod > _hod_ult_map[_pl].get(_comp_rg, 0):
                    _hod_ult_map[_pl][_comp_rg] = _hod
        for _comp, _kws in _KWS_IND.items():
            if any(kw in _itens_str for kw in _kws):
                if _hod > _hod_ult_map.get(_pl, {}).get(_comp, 0):
                    if _pl not in _hod_ult_map: _hod_ult_map[_pl] = {}
                    _hod_ult_map[_pl][_comp] = _hod

    n_crit = n_alert = n_ok = 0
    score_sum = 0
    custo_est = 0
    n_total = len(km_por_placa)

    for _plc, _km in km_por_placa.items():
        try:
            _km = float(_km)
            if _mf_math.isnan(_km) or _km <= 0: continue
        except: continue
        _plc_up = str(_plc).upper().strip()
        _scores = []
        _vencidos = []
        for _comp, _cfg in _PRED_CFG_IND.items():
            intv = _cfg["leve"]
            _hod_ult = (_hod_ult_map.get(_plc_up) or {}).get(_comp, 0)
            fase = (_km - _hod_ult) if _hod_ult > 0 and _km >= _hod_ult else (_km % intv)
            try:
                pct = min(fase / intv, 1.5)
            except: pct = 0
            sc = max(0, min(100, round(100 - pct * 110)))
            _scores.append(sc)
            if pct >= 0.85: _vencidos.append(_comp)
        sg = round(sum(_scores) / len(_scores)) if _scores else 0
        score_sum += sg
        if sg < 40:
            n_crit += 1
            custo_est += sum(_PRED_CFG_IND[c]["custo"] for c in _vencidos)
        elif sg < 70: n_alert += 1
        else: n_ok += 1

    return {
        "n_total":    n_total,
        "n_critico":  n_crit,
        "n_alerta":   n_alert,
        "n_ok":       n_ok,
        "score_medio":round(score_sum / n_total) if n_total else 0,
        "custo_est":  custo_est,
    }


if modo == "📍 Por UF/Município":
    _doc_tela("📍 Por UF/Município")
