                            orientation="h",
                            marker_color=_rt_dev["cor_dev"].tolist(),
                            text=_rt_dev["desvio_pct"].apply(lambda v: f"+{v:.0f}%" if v >= 0 else f"{v:.0f}%"),
                            textposition="outside",
