                    _ts_df["mes_nome"]   = _ts_df["data"].dt.strftime("%b/%y")
                    _ts_df["mes_period"] = _ts_df["data"].dt.to_period("M").apply(lambda p: p.start_time)
                    _ts_df["ano"]        = _ts_df["data"].dt.year

                    _ts_f1, _ts_f2, _ts_f3 = st.columns([2,2,2])
