                {"name": "cnpj",      "type": "string", "required": False, "desc": "CNPJ do posto (14 dígitos)", "example": "12345678000190"},
                {"name": "limit",     "type": "integer","required": False, "desc": "Máx. registros (1–500)", "example": "100"},
