                {"name": "combustivel", "type": "string",  "required": False, "desc": "Tipo de combustível", "example": "OLEO DIESEL S10"},
                {"name": "cnpj",        "type": "string",  "required": False, "desc": "CNPJ específico", "example": "12345678000190"},
